import React, { useState } from 'react';
import { CardData, Suit, Rank } from '../types';
import Card from '../components/Card';
import TutorialSensei, { TUTORIAL_STEPS } from '../components/TutorialSensei';
import { calculateHandValue } from '../services/gameLogic';
import { ArrowRight, RefreshCw, Hand, AlertCircle } from 'lucide-react';

// Hardcoded tutorial IDs for stability
const KING_ID = 'tut-king';
const SEVEN_A_ID = 'tut-seven-a';
const SEVEN_B_ID = 'tut-seven-b';
const FIVE_ID = 'tut-five';
const ACE_ID = 'tut-ace-joker';

const INITIAL_HAND: CardData[] = [
  { id: KING_ID, suit: Suit.Hearts, rank: Rank.King, value: 10 },
  { id: SEVEN_A_ID, suit: Suit.Clubs, rank: Rank.Seven, value: 7 },
  { id: FIVE_ID, suit: Suit.Diamonds, rank: Rank.Five, value: 5 }
];

const MOCK_DECK: CardData[] = [
  { id: SEVEN_B_ID, suit: Suit.Spades, rank: Rank.Seven, value: 7 },
  { id: ACE_ID, suit: Suit.Hearts, rank: Rank.Ace, value: 1 },
];

interface TutorialEngineProps {
  onExit: () => void;
}

const TutorialEngine: React.FC<TutorialEngineProps> = ({ onExit }) => {
  const [step, setStep] = useState(0);
  const [hand, setHand] = useState<CardData[]>(INITIAL_HAND);
  const [deck, setDeck] = useState<CardData[]>(MOCK_DECK);
  const [openPile, setOpenPile] = useState<CardData[]>([]);
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [pendingDiscard, setPendingDiscard] = useState<CardData | null>(null);
  const [pendingToss, setPendingToss] = useState<CardData[]>([]);

  // Scripted Joker: For tutorial, Aces are always Jokers
  const roundJoker = { rank: Rank.Ace } as any;

  const handleCardClick = (card: CardData) => {
    // Only allow selecting the King in step 1
    if (step === 1 && card.id === KING_ID) {
      setSelectedIds(prev => {
        const isSelected = prev.includes(card.id);
        const nextIds = isSelected ? [] : [card.id];
        // Auto-advance to Discard step if selected
        if (!isSelected) setStep(2);
        return nextIds;
      });
    }
    // Only allow selecting Sevens in step 4
    if (step === 4 && (card.id === SEVEN_A_ID || card.id === SEVEN_B_ID)) {
      setSelectedIds(prev => {
        const isSelected = prev.includes(card.id);
        const nextIds = isSelected ? prev.filter(id => id !== card.id) : [...prev, card.id];
        // Auto-advance to Toss step if both are selected
        if (nextIds.length === 2) setStep(5);
        return nextIds;
      });
    }
  };

  const nextStep = () => {
    if (step < TUTORIAL_STEPS.length - 1) {
      setStep(s => s + 1);
    }
  };

  const handleDiscardAction = () => {
    // Check if step 2 OR if King is selected at step 1
    if ((step === 2 || step === 1) && selectedIds.includes(KING_ID)) {
      const king = hand.find(c => c.id === KING_ID)!;
      setHand(prev => prev.filter(c => c.id !== KING_ID));
      setPendingDiscard(king);
      setSelectedIds([]);
      setStep(3); // Move to draw step
    }
  };

  const handleDrawAction = () => {
    if ((step === 3 || step === 6) && deck.length > 0) {
      const drawn = deck[0];
      setDeck(prev => prev.slice(1));

      const newHand = [...hand, drawn];

      // Cleanup pending piles
      if (pendingDiscard) setOpenPile(prev => [...prev, pendingDiscard]);
      if (pendingToss.length) setOpenPile(prev => [...prev, ...pendingToss]);

      setHand(newHand);
      setPendingDiscard(null);
      setPendingToss([]);

      if (step === 3) setStep(4); // Move to Toss Intro
      if (step === 6) setStep(7); // Move to Ace/Joker Intro
    }
  };

  const handleTossAction = () => {
    if ((step === 5 || step === 4) && selectedIds.length === 2) {
      const tossed = hand.filter(c => selectedIds.includes(c.id));
      setHand(prev => prev.filter(c => !selectedIds.includes(c.id)));
      setPendingToss(tossed);
      setSelectedIds([]);
      setStep(6); // Move to Draw for Toss
    }
  };

  const handleShowAction = () => {
    if (step === 8) {
      setStep(9); // Victory step
    }
  };

  return (
    <div className="h-[100dvh] flex flex-col bg-[#1a2e1a] relative overflow-hidden">
      <TutorialSensei stepIndex={step} onNext={nextStep} onExit={onExit} />

      {/* Header (Simplified) */}
      <div className="h-16 bg-[#0f1f0f] flex items-center justify-between px-4 shadow-lg z-20 shrink-0">
        <h1 className="font-serif font-bold text-xl text-yellow-500">ACADEMY</h1>
        <div className="flex items-center gap-2">
           <span className="text-xs uppercase tracking-widest text-purple-400 font-bold">Joker: Aces</span>
           <div className="flex bg-white text-black px-2 py-1 rounded border-2 border-purple-500 items-center gap-1">
             <span className="font-bold">A</span>
           </div>
        </div>
      </div>

      <div className="flex-1 flex flex-col justify-between p-4 max-w-7xl mx-auto w-full">
        {/* Opponents (Bots are grayscale in tutorial) */}
        <div className="flex justify-center gap-8 mb-2 opacity-30 grayscale pointer-events-none">
           {[1, 2, 3].map(i => (
             <div key={i} className="flex flex-col items-center p-2">
                <div className="w-10 h-10 bg-slate-700 rounded-full border-2 border-slate-500" />
                <span className="text-[10px] mt-1 text-white">Bot {i}</span>
             </div>
           ))}
        </div>

        {/* Table Area */}
        <div className="flex-1 flex items-center justify-center gap-6 md:gap-16 relative">
          <div className="flex flex-col items-center gap-2">
             <Card 
               disabled={step !== 3 && step !== 6} 
               onClick={handleDrawAction}
               className={(step === 3 || step === 6) ? 'ring-4 ring-yellow-400 animate-pulse' : ''} 
             />
             <span className="text-xs uppercase tracking-wider font-bold text-slate-400">Deck ({deck.length})</span>
          </div>

          <div className="flex gap-4 items-center">
            <div className="flex flex-col items-center gap-2">
               {openPile.length > 0 ? (
                 <Card card={openPile[openPile.length-1]} disabled={true} />
               ) : (
                 <div className="w-20 h-28 md:w-24 md:h-36 border-2 border-dashed border-white/10 rounded-xl" />
               )}
               <span className="text-xs uppercase tracking-wider font-bold text-slate-400">Open Pile</span>
            </div>

            {pendingDiscard && (
              <div className="flex flex-col items-center gap-2 animate-in slide-in-from-left-4 fade-in">
                <Card card={pendingDiscard} disabled={true} className="opacity-70" />
                <span className="text-[10px] text-yellow-400 font-bold uppercase">Discarding</span>
              </div>
            )}

            {pendingToss.length > 0 && (
              <div className="flex flex-col items-center gap-2 animate-in slide-in-from-left-4 fade-in">
                <div className="flex -space-x-8">
                   {pendingToss.map(c => <Card key={c.id} card={c} disabled={true} className="opacity-70" />)}
                </div>
                <span className="text-[10px] text-blue-400 font-bold uppercase">Tossing</span>
              </div>
            )}
          </div>
        </div>

        {/* Player Controls & Hand */}
        <div className="flex flex-col items-center gap-6 pb-8">
           <div className={`flex items-center gap-2 bg-black/40 backdrop-blur-md p-2 rounded-full border border-white/10 shadow-xl ${(step < 2 || step === 3 || step === 4 || step === 6 || step === 7 || step > 8) ? 'opacity-0 scale-90' : 'opacity-100 scale-100'} transition-all duration-300 pointer-events-auto`}>
              {(step === 2 || (step === 1 && selectedIds.includes(KING_ID))) && (
                <button 
                  onClick={handleDiscardAction}
                  className="bg-green-600 hover:bg-green-500 text-white px-6 py-2 rounded-full font-bold flex items-center gap-2 ring-4 ring-yellow-400 animate-bounce"
                >
                  <Hand size={18} /> DISCARD KING
                </button>
              )}
              {(step === 5 || (step === 4 && selectedIds.length === 2)) && (
                <button 
                  onClick={handleTossAction}
                  disabled={selectedIds.length !== 2}
                  className={`px-6 py-2 rounded-full font-bold flex items-center gap-2 transition-all ${selectedIds.length === 2 ? 'bg-blue-600 text-white ring-4 ring-yellow-400 animate-bounce' : 'bg-slate-700 text-slate-500'}`}
                >
                  <RefreshCw size={18} /> TOSS SEVENS
                </button>
              )}
              {step === 8 && (
                <button 
                  onClick={handleShowAction}
                  className="bg-red-600 text-white px-8 py-2 rounded-full font-bold flex items-center gap-2 ring-4 ring-yellow-400 animate-bounce"
                >
                  <AlertCircle size={18} /> CALL SHOW
                </button>
              )}
           </div>

           {/* Visual prompt for Drawing */}
           {(step === 3 || step === 6) && (
              <div className="bg-yellow-500/20 text-yellow-500 px-4 py-2 rounded-full text-sm font-bold animate-pulse flex items-center gap-2 border border-yellow-500/30">
                 <ArrowRight size={18} className="-rotate-90" /> Draw from the deck to finish turn
              </div>
           )}

           <div className="flex items-end justify-center -space-x-6 h-[160px]">
              {hand.map((card) => {
                const isSelected = selectedIds.includes(card.id);
                const isTarget = (step === 1 && card.id === KING_ID) || 
                               (step === 4 && (card.id === SEVEN_A_ID || card.id === SEVEN_B_ID));

                return (
                  <Card 
                    key={card.id} 
                    card={card} 
                    isJoker={card.rank === Rank.Ace}
                    selected={isSelected}
                    onClick={() => handleCardClick(card)}
                    className={`transition-all ${isTarget && !isSelected ? 'ring-4 ring-yellow-400 scale-105 z-10' : ''}`}
                  />
                );
              })}
           </div>

           <div className="text-xs text-gray-400">
             Your Tutorial Hand • Energy: <span className="text-white font-bold text-lg">{calculateHandValue(hand, roundJoker)}</span>
           </div>
        </div>
      </div>
    </div>
  );
};

export default TutorialEngine;

import React, { useState } from 'react';
import { CardData, Suit, Rank, GamePhase } from '../types';
import Card from '../components/Card';
import TutorialSensei, { TUTORIAL_STEPS } from '../components/TutorialSensei';
