  const [pendingDiscard, setPendingDiscard] = useState<CardData | null>(null);
  const [pendingToss, setPendingToss] = useState<CardData[]>([]);

  const roundJoker = { rank: Rank.Ace } as any;

  const handleCardClick = (card: CardData) => {
    if (step === 1 && card.id === KING_ID) {
      setSelectedIds(prev => {
        const isSelected = prev.includes(card.id);
        if (!isSelected) setStep(2);
        return isSelected ? [] : [card.id];
      });
    }
    if (step === 4 && (card.id === SEVEN_A_ID || card.id === SEVEN_B_ID)) {
      setSelectedIds(prev => {
        const isSelected = prev.includes(card.id);
        const nextIds = isSelected ? prev.filter(id => id !== card.id) : [...prev, card.id];
        if (nextIds.length === 2) setStep(5);
        return nextIds;
      });
