import { CardData, Suit, Rank } from '../types';
import Card from '../components/Card';
import TutorialSensei, { TUTORIAL_STEPS } from '../components/TutorialSensei';
import { calculateHandValue } from '../services/gameLogic';
import { ArrowRight, RefreshCw, Hand, AlertCircle, LogOut, Bot, GraduationCap, Trophy, ChevronRight } from 'lucide-react';

// Hardcoded tutorial IDs for stability
const KING_ID = 'tut-king';
const SEVEN_A_ID = 'tut-seven-a';
const SEVEN_B_ID = 'tut-seven-b';
const FIVE_ID = 'tut-five';
const ACE_ID = 'tut-ace-joker';

const INITIAL_HAND: CardData[] = [
  { id: KING_ID, suit: Suit.Hearts, rank: Rank.King, value: 10 },
  { id: SEVEN_A_ID, suit: Suit.Clubs, rank: Rank.Seven, value: 7 },
  { id: FIVE_ID, suit: Suit.Diamonds, rank: Rank.Five, value: 5 }
];

const MOCK_DECK: CardData[] = [
  { id: SEVEN_B_ID, suit: Suit.Spades, rank: Rank.Seven, value: 7 },
  { id: ACE_ID, suit: Suit.Hearts, rank: Rank.Ace, value: 1 },
];

interface TutorialEngineProps {
  onExit: () => void;
}

const TutorialEngine: React.FC<TutorialEngineProps> = ({ onExit }) => {
  const [step, setStep] = useState(0);
  const [hand, setHand] = useState<CardData[]>(INITIAL_HAND);
  const [deck, setDeck] = useState<CardData[]>(MOCK_DECK);
  const [openPile, setOpenPile] = useState<CardData[]>([]);
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [pendingDiscard, setPendingDiscard] = useState<CardData | null>(null);
  const [pendingToss, setPendingToss] = useState<CardData[]>([]);

  const roundJoker = { rank: Rank.Ace } as any;

  const handleCardClick = (card: CardData) => {
    if (step === 1 && card.id === KING_ID) {
      setSelectedIds(prev => {
        const isSelected = prev.includes(card.id);
        if (!isSelected) setStep(2);
        return isSelected ? [] : [card.id];
      });
    }
    if (step === 4 && (card.id === SEVEN_A_ID || card.id === SEVEN_B_ID)) {
      setSelectedIds(prev => {
        const isSelected = prev.includes(card.id);
        const nextIds = isSelected ? prev.filter(id => id !== card.id) : [...prev, card.id];
        if (nextIds.length === 2) setStep(5);
        return nextIds;
      });
    }
  };

  const nextStep = () => {
    if (step < TUTORIAL_STEPS.length - 1) setStep(s => s + 1);
  };

  const handleDiscardAction = () => {
    if ((step === 2 || step === 1) && selectedIds.includes(KING_ID)) {
      const king = hand.find(c => c.id === KING_ID)!;
      setHand(prev => prev.filter(c => c.id !== KING_ID));
      setPendingDiscard(king);
      setSelectedIds([]);
      setStep(3);
    }
  };

  const handleDrawAction = (source: 'DECK' | 'OPEN') => {
    // Only allow drawing from deck in tutorial
    if (source === 'OPEN') return;

    if ((step === 3 || step === 6) && deck.length > 0) {
      const drawn = deck[0];
      setDeck(prev => prev.slice(1));
      const newHand = [...hand, drawn];
      if (pendingDiscard) setOpenPile(prev => [...prev, pendingDiscard]);
      if (pendingToss.length) setOpenPile(prev => [...prev, ...pendingToss]);
      setHand(newHand);
      setPendingDiscard(null);
      setPendingToss([]);
      if (step === 3) setStep(4);
      if (step === 6) setStep(7);
    }
  };

  const handleTossAction = () => {
    if ((step === 5 || step === 4) && selectedIds.length === 2) {
      const tossed = hand.filter(c => selectedIds.includes(c.id));
      setHand(prev => prev.filter(c => !selectedIds.includes(c.id)));
      setPendingToss(tossed);
      setSelectedIds([]);
      setStep(6);
    }
  };

  const handleShowAction = () => {
    if (step === 8) setStep(9);
  };

  return (
    <div className="h-[100dvh] flex flex-col overflow-hidden bg-[#1a2e1a] relative">
      {/* Sensei Box: Hide at the very end to show final victory screen clearly */}
      {step < 9 && <TutorialSensei stepIndex={step} onNext={nextStep} onExit={onExit} />}

      {/* Top Bar: Exactly like App.tsx */}
      <div className="h-16 bg-[#0f1f0f] flex items-center justify-between px-4 shadow-lg z-20 shrink-0">
        <div className="flex items-center gap-4">
          <button onClick={onExit} className="text-red-400 hover:text-red-300 transition-colors bg-white/5 p-2 rounded-lg">
             <LogOut size={20} />
          </button>

          <h1 className="font-serif font-bold text-xl text-yellow-500 hidden md:block">ACADEMY</h1>
          <div className="bg-slate-800 px-3 py-1 rounded-lg text-xs md:text-sm flex items-center gap-2 border border-yellow-500/20">
             <GraduationCap size={14} className="text-yellow-500" />
             <span className="font-bold text-white uppercase tracking-tight">Tutorial 1/1</span>
          </div>
        </div>

        <div className="flex items-center gap-2">
           <span className="text-xs uppercase tracking-widest text-purple-400 font-bold hidden sm:inline">All Aces are Jokers</span>
           <span className="text-xs uppercase tracking-widest text-purple-400 font-bold sm:hidden">Joker: A</span>
           <div className="flex bg-white text-black px-2 py-1 rounded border-2 border-purple-500 items-center gap-1">
             <span className="font-bold">A</span>
           </div>
        </div>

        <div className="flex items-center gap-4">
           <div className="flex items-center gap-2">
             <div className="w-3 h-3 rounded-full bg-green-500 animate-pulse" />
             <span className="text-sm font-bold truncate text-white uppercase tracking-tight">YOU (Master)</span>
           </div>
        </div>
      </div>

      {/* Game Area */}
      <div className="flex-1 relative flex flex-col justify-between p-2 md:p-4 max-w-7xl mx-auto w-full overflow-hidden">

        {/* Opponents (Disabled for Tutorial) */}
        <div className="flex justify-center flex-wrap gap-2 md:gap-8 mb-2 opacity-30 grayscale pointer-events-none">
           {[1, 2, 3].map(id => (
             <div key={id} className="flex flex-col items-center p-2 rounded-lg bg-black/20">
                <div className="relative">
                   <div className="w-10 h-10 md:w-12 md:h-12 bg-slate-700 rounded-full flex items-center justify-center border-2 border-slate-500">
                     <Bot size={20} className="text-slate-300" />
                   </div>
                   <div className="absolute -bottom-1 -right-1 w-5 h-5 bg-blue-900 rounded-full flex items-center justify-center text-[10px] font-bold border border-white">3</div>
                </div>
                <span className="text-xs font-bold mt-1 text-white">Bot {id}</span>
                <span className="text-[10px] text-yellow-400">0 pts</span>
                <div className="flex -space-x-4 mt-2">
                   {[1, 2, 3].map(i => <Card key={i} small className="scale-75" />)}
                </div>
             </div>
           ))}
        </div>

        {/* Table Area */}
        <div className="flex-1 flex items-center justify-center gap-4 md:gap-16 my-2 relative">
            <div className="flex flex-col items-center gap-2">
               <Card 
                 disabled={step !== 3 && step !== 6} 
                 onClick={() => handleDrawAction('DECK')}
                 className={(step === 3 || step === 6) ? 'ring-4 ring-yellow-400 animate-pulse scale-110 z-10' : ''} 
               />
               <span className="text-xs uppercase tracking-wider font-bold text-slate-400">Deck ({deck.length})</span>
            </div>

            <div className="flex gap-4 items-center">
              <div className="flex flex-col items-center gap-2 relative">
                 {openPile.length > 0 ? (
                   <Card 
                     card={openPile[openPile.length - 1]}
                     isJoker={openPile[openPile.length - 1].rank === Rank.Ace}
                     disabled={true}
                   />
                 ) : (
                   <div className="w-20 h-28 md:w-24 md:h-36 border-2 border-dashed border-white/10 rounded-xl flex items-center justify-center">
                     <span className="text-white/20 text-xs">Empty</span>
                   </div>
                 )}
                 <span className="text-xs uppercase tracking-wider font-bold text-slate-400">Open Pile</span>
              </div>

              {pendingDiscard && (
                <div className="flex flex-col items-center gap-2 relative animate-in slide-in-from-left-4 fade-in">
                  <div className="relative">
                    <Card card={pendingDiscard} disabled={true} className="opacity-70 ring-2 ring-yellow-500/50" />
                    <div className="absolute inset-0 flex items-center justify-center"><ArrowRight className="text-white drop-shadow-lg" size={32} /></div>
                  </div>
                  <span className="text-xs uppercase tracking-wider font-bold text-yellow-400 animate-pulse">Discarding...</span>
                </div>
              )}

              {pendingToss.length > 0 && (
                 <div className="flex flex-col items-center gap-1 relative animate-in slide-in-from-left-4 fade-in">
                    <div className="relative flex -space-x-8">
                       {pendingToss.map(c => <Card key={c.id} card={c} disabled={true} className="opacity-70 ring-2 ring-blue-500/50" />)}
                       <div className="absolute inset-0 flex items-center justify-center pointer-events-none"><RefreshCw className="text-white drop-shadow-lg animate-spin" size={32} /></div>
                    </div>
                    <span className="text-xs uppercase tracking-wider font-bold text-blue-400 animate-pulse">Tossing...</span>
                 </div>
              )}
            </div>

            {/* Victory Overlay: Match exactly like App.tsx */}
            {step === 9 && (
               <div className="absolute inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm">
                 <div className="bg-slate-900/95 p-6 rounded-2xl shadow-2xl border border-yellow-500/30 backdrop-blur-sm max-w-sm w-full text-center m-4 animate-in fade-in zoom-in">
                    <h2 className="text-2xl font-serif font-bold text-white mb-1">Match Complete</h2>
                    <p className="text-gray-400 mb-6 text-xs uppercase tracking-widest">Final Tutorial Standings</p>

                    <div className="space-y-3 mb-8 text-left">
                       {/* You Row */}
                       <div className="flex justify-between items-center p-3 rounded-lg border bg-yellow-500/10 border-yellow-500/50">
                          <span className="flex items-center gap-2 text-yellow-400 font-bold">
                             <Trophy size={14} className="text-yellow-500" /> YOU (Master)
                          </span>
                          <div className="flex items-center gap-3">
                             <div className="flex flex-col items-end">
                                <span className="text-[10px] uppercase text-gray-500 font-bold">Hand</span>
                                <span className="text-sm font-bold text-gray-400">5</span>
                             </div>
                             <div className="w-px h-8 bg-white/10"></div>
                             <div className="flex flex-col items-end">
                                <span className="text-[10px] uppercase text-gray-500 font-bold">Total</span>
                                <span className="text-lg font-bold text-yellow-400">0</span>
                             </div>
                          </div>
                       </div>

                       {/* Bot Rows */}
                       {[1, 2, 3].map(i => (
                         <div key={i} className="flex justify-between items-center p-3 rounded-lg border bg-slate-800 border-white/5 opacity-50">
                            <span className="text-gray-300">Bot {i}</span>
                            <div className="flex items-center gap-3">
                               <div className="flex flex-col items-end">
                                  <span className="text-[10px] uppercase text-gray-500 font-bold">Total</span>
                                  <span className="text-lg font-bold text-red-400">25</span>
                               </div>
                            </div>
                         </div>
                       ))}
                    </div>

                    <button 
                      onClick={onExit} 
                      className="w-full bg-yellow-500 hover:bg-yellow-400 text-black font-bold py-4 rounded-xl flex items-center justify-center gap-2 transition-transform hover:scale-[1.02] active:scale-95 shadow-lg shadow-yellow-900/20"
                    >
                       Enter The Arena <ChevronRight size={18} />
                    </button>

                    <div className="mt-4 text-[10px] text-gray-500 uppercase tracking-widest">
                       Protocol 100% Complete • Academy Dismissed
                    </div>
                 </div>
               </div>
            )}
        </div>

        {/* Player Controls & Hand: Sync with App.tsx styling */}
        <div className="flex flex-col items-center gap-4 pb-8 shrink-0">

           <div className={`flex items-center gap-2 bg-black/40 backdrop-blur-md p-2 rounded-full border border-white/10 shadow-xl transition-all z-10 scale-90 md:scale-100 ${(step < 2 || step === 3 || step === 4 || step === 6 || step === 7 || step > 8) ? 'opacity-0 scale-95 pointer-events-none' : 'opacity-100 scale-100'}`}>
              {(step === 2 || (step === 1 && selectedIds.includes(KING_ID))) && (
                <button onClick={handleDiscardAction} className="bg-green-600 hover:bg-green-500 text-white px-6 py-2 rounded-full font-bold flex items-center gap-2 text-xs md:text-sm shadow-lg shadow-green-900/50 ring-4 ring-yellow-400 animate-bounce">
                  <Hand size={18} /> DISCARD (1)
                </button>
              )}
              {(step === 5 || (step === 4 && selectedIds.length === 2)) && (
                <button onClick={handleTossAction} className="bg-blue-600 hover:bg-blue-500 text-white px-6 py-2 rounded-full font-bold flex items-center gap-2 text-xs md:text-sm shadow-lg shadow-blue-900/50 ring-4 ring-yellow-400 animate-bounce">
                  <RefreshCw size={18} /> TOSS (2)
                </button>
              )}
              {step === 8 && (
                <button onClick={handleShowAction} className="bg-red-600 hover:bg-red-500 text-white px-8 py-2 rounded-full font-bold flex items-center gap-2 text-xs md:text-sm shadow-lg shadow-red-900/50 ring-4 ring-yellow-400 animate-bounce">
                  <AlertCircle size={18} /> CALL SHOW
                </button>
              )}
           </div>

           {/* Draw Prompt Pill */}
           {(step === 3 || step === 6) && (
              <div className="bg-yellow-500/20 text-yellow-500 px-4 py-2 rounded-full text-xs font-bold animate-pulse flex items-center gap-2 border border-yellow-500/30">
                 <ArrowRight size={14} className="-rotate-90" /> DRAW FROM DECK TO FINISH TURN
              </div>
           )}

           <div className="flex items-end justify-center -space-x-4 md:-space-x-6 h-[140px] md:h-[160px]">
              {hand.map((card) => {
                const isSelected = selectedIds.includes(card.id);
                const isTarget = (step === 1 && card.id === KING_ID) || 
                               (step === 4 && (card.id === SEVEN_A_ID || card.id === SEVEN_B_ID));

                return (
                  <Card 
                    key={card.id} 
                    card={card} 
                    isJoker={card.rank === Rank.Ace}
                    selected={isSelected}
                    onClick={() => handleCardClick(card)}
                    className={`transition-all origin-bottom ${isTarget && !isSelected ? 'ring-4 ring-yellow-400 scale-105 z-10' : ''}`}
                  />
                );
              })}
           </div>

           <div className="text-xs text-gray-400 mt-2">
             <span className="text-green-400 font-bold uppercase tracking-widest">YOU (Master)</span> • Energy: <span className="text-white font-bold text-lg">{calculateHandValue(hand, roundJoker)}</span>
           </div>
        </div>
      </div>
    </div>
  );
};

export default TutorialEngine;

import React from 'react';
import { GraduationCap, Play, LogOut, ChevronRight } from 'lucide-react';

export interface TutorialStep {
  text: string;
  highlight: string;
  isNarrative?: boolean; // If true, shows a "Next" button to manually advance
}

export const TUTORIAL_STEPS: TutorialStep[] = [
  { text: "Welcome to Tri-Stack Academy! I'm your Sensei. The goal is to finish the round with the lowest 'Energy' possible to win. Let's look at your hand.", highlight: "hand", isNarrative: true },
  { text: "You have a King (10 energy), a 7, and a 5. Total Energy is 22. That's way too high! Tap that King to select it.", highlight: "king" },
  { text: "Now hit DISCARD. We need to replace that heavy King with something lighter.", highlight: "discard" },
  { text: "Great. Now draw a card from the deck. Maybe we'll find a low number or a Joker.", highlight: "deck" },
  { text: "Look! You drew another 7. When you have a pair of the same rank, you can do a TWIN TOSS. Select both 7s.", highlight: "sevens" },
  { text: "Hit TOSS! This dumps two cards at once. It's the fastest way to drop your Energy.", highlight: "toss" },
  { text: "Now draw 1 card back from the deck to finish the Toss.", highlight: "deck" },
  { text: "You drew an ACE! This round, all Aces are JOKERS. They have 0 Energy! Your total is now [Ace(0) + 5] = 5.", highlight: "joker", isNarrative: true },
  { text: "In v3, once your energy is 5 or less, you can call SHOW. Hit the red button to call for a showdown!", highlight: "show" },
  { text: "You won! Since you had the lowest energy, you score 0. Bots take their hand values as penalties. First to 100 total points is out!", highlight: "end", isNarrative: true }
];

interface TutorialSenseiProps {
  stepIndex: number;
  onNext: () => void;
  onExit: () => void;
}

const TutorialSensei: React.FC<TutorialSenseiProps> = ({ stepIndex, onNext, onExit }) => {
  const currentStep = TUTORIAL_STEPS[stepIndex];
  if (!currentStep) return null;

  const isLastStep = stepIndex === TUTORIAL_STEPS.length - 1;

  return (
    <div className="absolute top-20 left-1/2 -translate-x-1/2 z-[80] w-[95%] max-w-md pointer-events-none">
      <div className="bg-slate-900 border-2 border-yellow-500 p-5 rounded-3xl shadow-[0_0_30px_rgba(234,179,8,0.3)] animate-in slide-in-from-top-4 pointer-events-auto">
        <div className="flex items-start gap-4">
          <div className="relative shrink-0">
            <div className="bg-yellow-500 p-2.5 rounded-2xl text-black shadow-lg">
              <GraduationCap size={28} />
            </div>
            <div className="absolute -bottom-1 -right-1 w-4 h-4 bg-green-500 rounded-full border-2 border-slate-900 animate-pulse" />
          </div>

          <div className="flex-1">
            <h4 className="text-yellow-500 text-[10px] font-bold uppercase tracking-[0.2em] mb-1 opacity-70">Academy Protocol</h4>
            <p className="text-white font-medium text-sm leading-relaxed mb-4">
              {currentStep.text}
            </p>

            <div className="flex items-center gap-3">
              {currentStep.isNarrative && !isLastStep && (
                <button 
                  onClick={onNext}
                  className="bg-yellow-500 hover:bg-yellow-400 text-black px-5 py-2 rounded-xl text-xs font-bold uppercase tracking-widest flex items-center gap-2 transition-all active:scale-95"
                >
                  <Play size={14} fill="currentColor" /> Next Protocol
                </button>
              )}

              {isLastStep ? (
                <div className="text-green-400 text-xs font-bold flex items-center gap-2">
                   <ChevronRight size={14} /> Tap the card below to finish showdown...
                </div>
              ) : (
                <button 
                  onClick={onExit}
                  className="text-gray-500 text-[10px] font-bold uppercase hover:text-red-400 transition-colors ml-auto flex items-center gap-1"
                >
                  Abort <LogOut size={10} />
                </button>
              )}
            </div>
          </div>
        </div>

        {/* Progress Bar */}
        <div className="absolute -bottom-1 left-6 right-6 h-1 bg-slate-800 rounded-full overflow-hidden">
          <div 
            className="h-full bg-yellow-500 transition-all duration-500" 
            style={{ width: `${((stepIndex + 1) / TUTORIAL_STEPS.length) * 100}%` }}
          />
        </div>
      </div>
    </div>
  );
};

export default TutorialSensei;

import React, { useState, useEffect } from 'react';
import { CardData, Suit, Rank } from '../types';
import Card from '../components/Card';
import TutorialSensei, { TUTORIAL_STEPS } from '../components/TutorialSensei';
import { calculateHandValue } from '../services/gameLogic';
import { ArrowRight, RefreshCw, Hand, AlertCircle, LogOut, Bot, GraduationCap, Trophy, ChevronRight, MousePointer2 } from 'lucide-react';

// Hardcoded tutorial IDs
const KING_ID = 'tut-king';
const SEVEN_A_ID = 'tut-seven-a';
const SEVEN_B_ID = 'tut-seven-b';
const FIVE_ID = 'tut-five';
const ACE_ID = 'tut-ace-joker';

const INITIAL_HAND: CardData[] = [
  { id: KING_ID, suit: Suit.Hearts, rank: Rank.King, value: 10 },
  { id: SEVEN_A_ID, suit: Suit.Clubs, rank: Rank.Seven, value: 7 },
  { id: FIVE_ID, suit: Suit.Diamonds, rank: Rank.Five, value: 5 }
];

const MOCK_DECK: CardData[] = [
  { id: SEVEN_B_ID, suit: Suit.Spades, rank: Rank.Seven, value: 7 },
  { id: ACE_ID, suit: Suit.Hearts, rank: Rank.Ace, value: 1 },
];

interface TutorialEngineProps {
  onExit: () => void;
}

const TutorialEngine: React.FC<TutorialEngineProps> = ({ onExit }) => {
  const [step, setStep] = useState(0);
  const [hand, setHand] = useState<CardData[]>(INITIAL_HAND);
  const [deck, setDeck] = useState<CardData[]>(MOCK_DECK);
  const [openPile, setOpenPile] = useState<CardData[]>([]);
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [pendingDiscard, setPendingDiscard] = useState<CardData | null>(null);
  const [pendingToss, setPendingToss] = useState<CardData[]>([]);

  const roundJoker = { rank: Rank.Ace } as any;

  // Auto-advance narrative steps if they have specific triggers
  const handleCardClick = (card: CardData) => {
    if (step === 1 && card.id === KING_ID) {
      setSelectedIds([card.id]);
      setStep(2);
    } else if (step === 4 && (card.id === SEVEN_A_ID || card.id === SEVEN_B_ID)) {
      setSelectedIds(prev => {
        const next = prev.includes(card.id) ? prev.filter(id => id !== card.id) : [...prev, card.id];
        if (next.length === 2) setStep(5);
        return next;
      });
    }
  };

  const handleDiscardAction = () => {
    if (step === 2 && selectedIds.includes(KING_ID)) {
      const king = hand.find(c => c.id === KING_ID)!;
      setHand(prev => prev.filter(c => c.id !== KING_ID));
      setPendingDiscard(king);
      setSelectedIds([]);
      setStep(3);
    }
  };

  const handleDrawAction = () => {
    if ((step === 3 || step === 6) && deck.length > 0) {
      const drawn = deck[0];
      setDeck(prev => prev.slice(1));
      const newHand = [...hand, drawn];
      if (pendingDiscard) setOpenPile(prev => [...prev, pendingDiscard]);
      if (pendingToss.length) setOpenPile(prev => [...prev, ...pendingToss]);
      setHand(newHand);
      setPendingDiscard(null);
      setPendingToss([]);
      setStep(step + 1);
    }
  };

  const handleTossAction = () => {
    if (step === 5 && selectedIds.length === 2) {
      const tossed = hand.filter(c => selectedIds.includes(c.id));
      setHand(prev => prev.filter(c => !selectedIds.includes(c.id)));
      setPendingToss(tossed);
      setSelectedIds([]);
      setStep(6);
    }
  };

  const handleShowAction = () => {
    if (step === 8) setStep(9);
  };

  // Helper to determine spotlight area
  const getSpotlightClass = () => {
    if (step === 0 || step === 1) return 'spotlight-hand';
    if (step === 2) return 'spotlight-controls';
    if (step === 3 || step === 6) return 'spotlight-table';
    if (step === 4) return 'spotlight-hand';
    if (step === 5) return 'spotlight-controls';
    if (step === 8) return 'spotlight-controls';
    return '';
  };

  return (
    <div className="h-[100dvh] flex flex-col overflow-hidden bg-[#1a2e1a] relative">
      {/* Dynamic Background Spotlight */}
      {step < 9 && (
        <div className={`fixed inset-0 bg-black/60 transition-opacity duration-500 z-[60] pointer-events-none ${getSpotlightClass() ? 'opacity-100' : 'opacity-0'}`} />
      )}

      {step < 9 && (
        <TutorialSensei stepIndex={step} onNext={() => setStep(s => s + 1)} onExit={onExit} />
      )}

      {/* Header (Always Visible) */}
      <div className="h-16 bg-[#0f1f0f] flex items-center justify-between px-4 shadow-lg z-[70] shrink-0">
        <div className="flex items-center gap-4">
          <button onClick={onExit} className="text-red-400 hover:text-red-300 transition-colors bg-white/5 p-2 rounded-lg">
             <LogOut size={20} />
          </button>
          <h1 className="font-serif font-bold text-xl text-yellow-500 hidden md:block tracking-tighter">ACADEMY</h1>
          <div className="bg-slate-800 px-3 py-1 rounded-lg text-xs md:text-sm flex items-center gap-2 border border-yellow-500/20">
             <GraduationCap size={14} className="text-yellow-500" />
             <span className="font-bold text-white uppercase tracking-tight">Lesson 1/1</span>
          </div>
        </div>

        <div className="flex items-center gap-2">
           <span className="text-xs uppercase tracking-widest text-purple-400 font-bold hidden sm:inline">Joker Status: ACTIVE</span>
           <div className="flex bg-white text-black px-2 py-1 rounded border-2 border-purple-500 items-center gap-1 shadow-[0_0_15px_rgba(168,85,247,0.4)]">
             <span className="font-bold">A</span>
           </div>
        </div>

        <div className="flex items-center gap-4">
           <div className="flex items-center gap-2">
             <div className="w-3 h-3 rounded-full bg-green-500 animate-pulse" />
             <span className="text-sm font-bold truncate text-white uppercase tracking-tight">Human Apprentice</span>
           </div>
        </div>
      </div>

      {/* Table Area */}
      <div className="flex-1 relative flex flex-col justify-between p-2 md:p-4 max-w-7xl mx-auto w-full overflow-hidden">

        {/* Opponents (Dimmed) */}
        <div className="flex justify-center flex-wrap gap-2 md:gap-8 mb-2 opacity-20 grayscale pointer-events-none">
           {[1, 2, 3].map(id => (
             <div key={id} className="flex flex-col items-center p-2 rounded-lg bg-black/20">
                <div className="w-10 h-10 md:w-12 md:h-12 bg-slate-700 rounded-full flex items-center justify-center border-2 border-slate-500">
                  <Bot size={20} className="text-slate-300" />
                </div>
                <span className="text-xs font-bold mt-1 text-white">Bot {id}</span>
                <div className="flex -space-x-4 mt-2">
                   {[1, 2, 3].map(i => <Card key={i} small className="scale-75" />)}
                </div>
             </div>
           ))}
        </div>

        {/* Action Table */}
        <div className={`flex-1 flex items-center justify-center gap-4 md:gap-16 my-2 relative transition-all duration-500 ${(step === 3 || step === 6) ? 'z-[70]' : 'z-10'}`}>
            <div className="flex flex-col items-center gap-2 relative">
               <Card 
                 disabled={step !== 3 && step !== 6} 
                 onClick={handleDrawAction}
                 className={(step === 3 || step === 6) ? 'ring-4 ring-yellow-400 scale-110 shadow-[0_0_30px_rgba(234,179,8,0.5)] z-20' : ''} 
               />
               {(step === 3 || step === 6) && (
                 <div className="absolute -top-12 animate-bounce text-yellow-500 flex flex-col items-center">
                    <span className="text-[10px] font-bold bg-yellow-500 text-black px-2 py-0.5 rounded-full mb-1">DRAW HERE</span>
                    <ChevronRight size={24} className="rotate-90" />
                 </div>
               )}
               <span className="text-xs uppercase tracking-wider font-bold text-slate-400">Deck ({deck.length})</span>
            </div>

            <div className="flex gap-4 items-center">
              <div className="flex flex-col items-center gap-2 relative">
                 {openPile.length > 0 ? (
                   <Card card={openPile[openPile.length - 1]} isJoker={openPile[openPile.length - 1].rank === Rank.Ace} disabled={true} />
                 ) : (
                   <div className="w-20 h-28 md:w-24 md:h-36 border-2 border-dashed border-white/10 rounded-xl flex items-center justify-center">
                     <span className="text-white/20 text-xs uppercase tracking-widest font-bold">Pile</span>
                   </div>
                 )}
                 <span className="text-xs uppercase tracking-wider font-bold text-slate-400">Open Pile</span>
