                    <button 
                      onClick={onExit} 
                      className="w-full bg-yellow-500 hover:bg-yellow-400 text-black font-black py-5 rounded-2xl flex items-center justify-center gap-3 transition-transform hover:scale-[1.02] active:scale-95 shadow-[0_10px_30px_rgba(234,179,8,0.3)]"
                    >
                       ENTER THE ARENA <ChevronRight size={24} />
                    </button>
                 </div>
               </div>
            )}
        </div>

        {/* Player Controls */}
        <div className="flex flex-col items-center gap-4 pb-8 shrink-0 relative">

           <div className={`flex items-center gap-2 bg-black/60 backdrop-blur-xl p-2 rounded-full border border-white/10 shadow-2xl transition-all scale-100 ${(step === 2 || step === 5 || step === 8) ? 'z-[70] opacity-100 translate-y-0' : 'z-0 opacity-0 translate-y-4 pointer-events-none'}`}>
              {step === 2 && (
                <button onClick={handleDiscardAction} className="bg-green-600 hover:bg-green-500 text-white px-8 py-3 rounded-full font-black flex items-center gap-2 text-sm shadow-[0_0_20px_rgba(22,163,74,0.4)] animate-bounce ring-4 ring-yellow-400">
                  <Hand size={20} /> DISCARD (1)
                </button>
              )}
              {step === 5 && (
                <button onClick={handleTossAction} className="bg-blue-600 hover:bg-blue-500 text-white px-8 py-3 rounded-full font-black flex items-center gap-2 text-sm shadow-[0_0_20px_rgba(37,99,235,0.4)] animate-bounce ring-4 ring-yellow-400">
                  <RefreshCw size={20} /> TOSS (2)
                </button>
              )}
              {step === 8 && (
                <button onClick={handleShowAction} className="bg-red-600 hover:bg-red-500 text-white px-10 py-3 rounded-full font-black flex items-center gap-2 text-sm shadow-[0_0_20px_rgba(220,38,38,0.4)] animate-bounce ring-4 ring-yellow-400">
                  <AlertCircle size={20} /> CALL SHOW
                </button>
              )}
           </div>

           <div className={`flex items-end justify-center -space-x-4 md:-space-x-6 h-[140px] md:h-[160px] transition-all duration-500 ${(step === 1 || step === 4 || step === 7) ? 'z-[70]' : 'z-10'}`}>
              {hand.map((card) => {
                const isSelected = selectedIds.includes(card.id);
                const isTarget = (step === 1 && card.id === KING_ID) || 
                               (step === 4 && (card.id === SEVEN_A_ID || card.id === SEVEN_B_ID));

                return (
                  <div key={card.id} className="relative transition-all">
                    <Card 
                      card={card} 
                      isJoker={card.rank === Rank.Ace}
                      selected={isSelected}
                      onClick={() => handleCardClick(card)}
                      className={`transition-all origin-bottom ${isTarget && !isSelected ? 'ring-4 ring-yellow-400 scale-110 shadow-[0_0_20px_rgba(234,179,8,0.5)]' : ''}`}
                    />
                    {isTarget && !isSelected && (
                       <div className="absolute -top-10 left-1/2 -translate-x-1/2 animate-bounce z-30">
                          <MousePointer2 className="text-yellow-400 fill-yellow-400 drop-shadow-md" size={32} />
                       </div>
                    )}
                  </div>
                );
              })}
           </div>

           <div className="text-xs text-gray-400 mt-2 flex flex-col items-center gap-1">
             <div className="flex items-center gap-2">
               <span className="text-green-500 font-black uppercase tracking-widest">Apprentice</span>
               <span className="w-1 h-1 bg-gray-600 rounded-full" />
               <span className="text-gray-300 font-bold">Energy Target: 5 or Less</span>
             </div>
             <div className="text-white font-black text-2xl flex items-baseline gap-2">
                <span className="text-[10px] text-gray-500 font-bold uppercase tracking-tighter">Current:</span>
                {calculateHandValue(hand, roundJoker)}
                {step === 7 && <span className="text-purple-400 text-xs animate-pulse ml-2 tracking-widest">(JOKER DETECTED)</span>}
             </div>
           </div>
        </div>
      </div>

      <style>{`
        .spotlight-hand {
          clip-path: polygon(0% 0%, 100% 0%, 100% 100%, 0% 100%, 0% 70%, 10% 70%, 10% 95%, 90% 95%, 90% 70%, 0% 70%);
        }
        .spotlight-controls {
          clip-path: polygon(0% 0%, 100% 0%, 100% 100%, 0% 100%, 0% 65%, 25% 65%, 25% 75%, 75% 75%, 75% 65%, 0% 65%);
        }
        .spotlight-table {
          clip-path: polygon(0% 0%, 100% 0%, 100% 100%, 0% 100%, 0% 30%, 15% 30%, 15% 60%, 85% 60%, 85% 30%, 0% 30%);
        }
        @keyframes scale-in-center {
          0% { transform: scale(0); opacity: 0; }
          100% { transform: scale(1); opacity: 1; }
        }
        .scale-in-center { animation: scale-in-center 0.5s cubic-bezier(0.250, 0.460, 0.450, 0.940) both; }
      `}</style>
    </div>
  );
};

export default TutorialEngine;

import React from 'react';
import { GraduationCap, Play, LogOut, ChevronRight, Sparkles } from 'lucide-react';

export interface TutorialStep {
  text: string;
  highlight: string;
  isNarrative?: boolean;
}

export const TUTORIAL_STEPS: TutorialStep[] = [
  { text: "Welcome to Tri-Stack Academy. The mission is simple: Minimize your 'Hand Energy'. If you end with the lowest score at the table, you dominate. Let's inspect your current loadout.", highlight: "hand", isNarrative: true },
  { text: "This King is heavy. It's weighing you down with 10 Energy points. Tap the King to prepare a discard maneuver.", highlight: "king" },
  { text: "Optimal. Now execute a DISCARD. We need to cycle your hand until you find low-value cards or Jokers.", highlight: "discard" },
  { text: "Tactical replenishment required. Draw a card from the Deck to finish your turn cycle.", highlight: "deck" },
  { text: "Visual Match Confirmed. You now have a pair of Sevens. In v3, pairs are powerful. Select both Sevens to initialize a Twin Toss.", highlight: "sevens" },
  { text: "Execute the TOSS. This dumps two cards simultaneously, permanently reducing your hand size for the round. Efficiency is key.", highlight: "toss" },
  { text: "Complete the maneuver. Draw one card back from the deck to stabilize your hand.", highlight: "deck" },
  { text: "Alert: You drew an ACE. In this protocol, all Aces are JOKERS. Their energy value is ZERO. Your hand total has dropped to 5.", highlight: "joker", isNarrative: true },
  { text: "Condition Green. Your energy is 5 or less. You are eligible to call a SHOW. Hit the red button to initiate the final showdown.", highlight: "show" },
  { text: "Calculation complete. You had the lowest energy, resulting in a 0-point round. The bots take penalties. First to 100 total points is eliminated.", highlight: "end", isNarrative: true }
];

interface TutorialSenseiProps {
  stepIndex: number;
  onNext: () => void;
  onExit: () => void;
}

const TutorialSensei: React.FC<TutorialSenseiProps> = ({ stepIndex, onNext, onExit }) => {
  const currentStep = TUTORIAL_STEPS[stepIndex];
  if (!currentStep) return null;

  const isLastStep = stepIndex === TUTORIAL_STEPS.length - 1;

  return (
    <div className="absolute top-20 left-1/2 -translate-x-1/2 z-[80] w-[95%] max-w-lg pointer-events-none">
      <div className="bg-slate-900/40 backdrop-blur-md border border-yellow-500/50 p-6 rounded-[2rem] shadow-[0_20px_50px_rgba(0,0,0,0.5)] animate-in slide-in-from-top-4 pointer-events-auto">
        <div className="flex items-start gap-5">
          <div className="relative shrink-0 mt-1">
            <div className="bg-yellow-500 p-3 rounded-2xl text-black shadow-[0_0_20px_rgba(234,179,8,0.4)]">
              <GraduationCap size={32} />
            </div>
            <div className="absolute -bottom-1 -right-1 w-5 h-5 bg-green-500 rounded-full border-4 border-slate-900 animate-pulse" />
          </div>

          <div className="flex-1">
            <div className="flex items-center gap-2 mb-2">
              <Sparkles size={12} className="text-yellow-500" />
              <h4 className="text-yellow-500 text-[10px] font-black uppercase tracking-[0.3em] opacity-80">Academy Instructor</h4>
            </div>

            <p className="text-white font-semibold text-base leading-relaxed mb-6">
              {currentStep.text}
            </p>

            <div className="flex items-center justify-between">
              {currentStep.isNarrative && !isLastStep ? (
                <button 
                  onClick={onNext}
                  className="bg-yellow-500 hover:bg-yellow-400 text-black px-6 py-2.5 rounded-xl text-xs font-black uppercase tracking-widest flex items-center gap-2 transition-all active:scale-95 shadow-lg shadow-yellow-900/20"
                >
                  <Play size={14} fill="currentColor" /> Proceed
                </button>
              ) : (
                <div className="text-[10px] text-gray-400 uppercase tracking-widest font-bold flex items-center gap-2">
                   <ChevronRight size={12} className="text-yellow-500 animate-ping" /> Waiting for Action...
                </div>
              )}

              {!isLastStep && (
                <button 
                  onClick={onExit}
                  className="text-gray-500 text-[10px] font-bold uppercase hover:text-red-400 transition-colors flex items-center gap-1 group"
                >
                  Terminate <LogOut size={10} className="group-hover:translate-x-1 transition-transform" />
                </button>
              )}
            </div>
          </div>
        </div>

        {/* Step Counter Overlay */}
        <div className="absolute -top-3 -right-3 bg-slate-800 text-yellow-500 border border-yellow-500/30 w-8 h-8 rounded-full flex items-center justify-center text-[10px] font-black shadow-xl">
           {stepIndex + 1}
        </div>

        {/* Dynamic Progress Line */}
        <div className="absolute -bottom-0 left-10 right-10 h-0.5 bg-slate-800 rounded-full overflow-hidden">
          <div 
            className="h-full bg-gradient-to-r from-yellow-600 to-yellow-400 transition-all duration-700 ease-out" 
            style={{ width: `${((stepIndex + 1) / TUTORIAL_STEPS.length) * 100}%` }}
          />
        </div>
      </div>
    </div>
  );
};

export default TutorialSensei;

import React, { useState, useEffect } from 'react';
import { CardData, Suit, Rank } from '../types';
import Card from '../components/Card';
import TutorialSensei, { TUTORIAL_STEPS } from '../components/TutorialSensei';
import { calculateHandValue } from '../services/gameLogic';
// Added Sparkles to the imported icons from lucide-react
import { ArrowRight, RefreshCw, Hand, AlertCircle, LogOut, Bot, GraduationCap, Trophy, ChevronRight, MousePointer2, Sparkles } from 'lucide-react';

// Hardcoded tutorial IDs
const KING_ID = 'tut-king';
const SEVEN_A_ID = 'tut-seven-a';
const SEVEN_B_ID = 'tut-seven-b';
const FIVE_ID = 'tut-five';
const ACE_ID = 'tut-ace-joker';

const INITIAL_HAND: CardData[] = [
  { id: KING_ID, suit: Suit.Hearts, rank: Rank.King, value: 10 },
  { id: SEVEN_A_ID, suit: Suit.Clubs, rank: Rank.Seven, value: 7 },
  { id: FIVE_ID, suit: Suit.Diamonds, rank: Rank.Five, value: 5 }
];

const MOCK_DECK: CardData[] = [
  { id: SEVEN_B_ID, suit: Suit.Spades, rank: Rank.Seven, value: 7 },
  { id: ACE_ID, suit: Suit.Hearts, rank: Rank.Ace, value: 1 },
];

interface TutorialEngineProps {
  onExit: () => void;
}

const TutorialEngine: React.FC<TutorialEngineProps> = ({ onExit }) => {
  const [step, setStep] = useState(0);
  const [hand, setHand] = useState<CardData[]>(INITIAL_HAND);
  const [deck, setDeck] = useState<CardData[]>(MOCK_DECK);
  const [openPile, setOpenPile] = useState<CardData[]>([]);
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [pendingDiscard, setPendingDiscard] = useState<CardData | null>(null);
  const [pendingToss, setPendingToss] = useState<CardData[]>([]);

  const roundJoker = { rank: Rank.Ace } as any;

  // Auto-advance narrative steps if they have specific triggers
  const handleCardClick = (card: CardData) => {
    if (step === 1 && card.id === KING_ID) {
      setSelectedIds([card.id]);
      setStep(2);
    } else if (step === 4 && (card.id === SEVEN_A_ID || card.id === SEVEN_B_ID)) {
      setSelectedIds(prev => {
        const next = prev.includes(card.id) ? prev.filter(id => id !== card.id) : [...prev, card.id];
        if (next.length === 2) setStep(5);
        return next;
      });
    }
  };

  const handleDiscardAction = () => {
    if (step === 2 && selectedIds.includes(KING_ID)) {
      const king = hand.find(c => c.id === KING_ID)!;
      setHand(prev => prev.filter(c => c.id !== KING_ID));
      setPendingDiscard(king);
      setSelectedIds([]);
      setStep(3);
    }
  };

  const handleDrawAction = () => {
    if ((step === 3 || step === 6) && deck.length > 0) {
      const drawn = deck[0];
      setDeck(prev => prev.slice(1));
      const newHand = [...hand, drawn];
      if (pendingDiscard) setOpenPile(prev => [...prev, pendingDiscard]);
      if (pendingToss.length) setOpenPile(prev => [...prev, ...pendingToss]);
      setHand(newHand);
      setPendingDiscard(null);
      setPendingToss([]);
      setStep(step + 1);
    }
  };

  const handleTossAction = () => {
    if (step === 5 && selectedIds.length === 2) {
      const tossed = hand.filter(c => selectedIds.includes(c.id));
      setHand(prev => prev.filter(c => !selectedIds.includes(c.id)));
      setPendingToss(tossed);
      setSelectedIds([]);
      setStep(6);
    }
  };

  const handleShowAction = () => {
    if (step === 8) setStep(9);
  };

  // Helper to determine spotlight area
  const getSpotlightClass = () => {
    if (step === 0 || step === 1) return 'spotlight-hand';
    if (step === 2) return 'spotlight-controls';
    if (step === 3 || step === 6) return 'spotlight-table';
    if (step === 4) return 'spotlight-hand';
    if (step === 5) return 'spotlight-controls';
    if (step === 8) return 'spotlight-controls';
    return '';
  };

  return (
    <div className="h-[100dvh] flex flex-col overflow-hidden bg-[#1a2e1a] relative">
      {/* Dynamic Background Spotlight */}
      {step < 9 && (
        <div className={`fixed inset-0 bg-black/60 transition-opacity duration-500 z-[60] pointer-events-none ${getSpotlightClass() ? 'opacity-100' : 'opacity-0'}`} />
      )}

      {step < 9 && (
        <TutorialSensei stepIndex={step} onNext={() => setStep(s => s + 1)} onExit={onExit} />
      )}

      {/* Header (Always Visible) */}
      <div className="h-16 bg-[#0f1f0f] flex items-center justify-between px-4 shadow-lg z-[70] shrink-0">
        <div className="flex items-center gap-4">
          <button onClick={onExit} className="text-red-400 hover:text-red-300 transition-colors bg-white/5 p-2 rounded-lg">
             <LogOut size={20} />
          </button>
          <h1 className="font-serif font-bold text-xl text-yellow-500 hidden md:block tracking-tighter">ACADEMY</h1>
          <div className="bg-slate-800 px-3 py-1 rounded-lg text-xs md:text-sm flex items-center gap-2 border border-yellow-500/20">
             <GraduationCap size={14} className="text-yellow-500" />
             <span className="font-bold text-white uppercase tracking-tight">Lesson 1/1</span>
          </div>
        </div>

        <div className="flex items-center gap-2">
           <span className="text-xs uppercase tracking-widest text-purple-400 font-bold hidden sm:inline">Joker Status: ACTIVE</span>
           <div className="flex bg-white text-black px-2 py-1 rounded border-2 border-purple-500 items-center gap-1 shadow-[0_0_15px_rgba(168,85,247,0.4)]">
             <span className="font-bold">A</span>
           </div>
        </div>

        <div className="flex items-center gap-4">
           <div className="flex items-center gap-2">
             <div className="w-3 h-3 rounded-full bg-green-500 animate-pulse" />
             <span className="text-sm font-bold truncate text-white uppercase tracking-tight">Human Apprentice</span>
           </div>
        </div>
      </div>

      {/* Table Area */}
      <div className="flex-1 relative flex flex-col justify-between p-2 md:p-4 max-w-7xl mx-auto w-full overflow-hidden">

        {/* Opponents (Dimmed) */}
        <div className="flex justify-center flex-wrap gap-2 md:gap-8 mb-2 opacity-20 grayscale pointer-events-none">
           {[1, 2, 3].map(id => (
             <div key={id} className="flex flex-col items-center p-2 rounded-lg bg-black/20">
                <div className="w-10 h-10 md:w-12 md:h-12 bg-slate-700 rounded-full flex items-center justify-center border-2 border-slate-500">
                  <Bot size={20} className="text-slate-300" />
                </div>
                <span className="text-xs font-bold mt-1 text-white">Bot {id}</span>
                <div className="flex -space-x-4 mt-2">
                   {[1, 2, 3].map(i => <Card key={i} small className="scale-75" />)}
                </div>
             </div>
           ))}
        </div>

        {/* Action Table */}
        <div className={`flex-1 flex items-center justify-center gap-4 md:gap-16 my-2 relative transition-all duration-500 ${(step === 3 || step === 6) ? 'z-[70]' : 'z-10'}`}>
            <div className="flex flex-col items-center gap-2 relative">
               <Card 
                 disabled={step !== 3 && step !== 6} 
                 onClick={handleDrawAction}
                 className={(step === 3 || step === 6) ? 'ring-4 ring-yellow-400 scale-110 shadow-[0_0_30px_rgba(234,179,8,0.5)] z-20' : ''} 
               />
               {(step === 3 || step === 6) && (
                 <div className="absolute -top-12 animate-bounce text-yellow-500 flex flex-col items-center">
                    <span className="text-[10px] font-bold bg-yellow-500 text-black px-2 py-0.5 rounded-full mb-1">DRAW HERE</span>
                    <ChevronRight size={24} className="rotate-90" />
                 </div>
               )}
               <span className="text-xs uppercase tracking-wider font-bold text-slate-400">Deck ({deck.length})</span>
            </div>

            <div className="flex gap-4 items-center">
              <div className="flex flex-col items-center gap-2 relative">
                 {openPile.length > 0 ? (
                   <Card card={openPile[openPile.length - 1]} isJoker={openPile[openPile.length - 1].rank === Rank.Ace} disabled={true} />
                 ) : (
                   <div className="w-20 h-28 md:w-24 md:h-36 border-2 border-dashed border-white/10 rounded-xl flex items-center justify-center">
                     <span className="text-white/20 text-xs uppercase tracking-widest font-bold">Pile</span>
                   </div>
                 )}
                 <span className="text-xs uppercase tracking-wider font-bold text-slate-400">Open Pile</span>
              </div>

              {pendingDiscard && (
                <div className="flex flex-col items-center gap-2 relative animate-in slide-in-from-left-4 fade-in">
                  <div className="relative">
                    <Card card={pendingDiscard} disabled={true} className="opacity-70 ring-2 ring-yellow-500/50" />
                    <div className="absolute inset-0 flex items-center justify-center pointer-events-none"><ArrowRight className="text-white drop-shadow-lg" size={32} /></div>
                  </div>
                  <span className="text-xs uppercase tracking-wider font-bold text-yellow-400">Discarding...</span>
                </div>
              )}

              {pendingToss.length > 0 && (
                 <div className="flex flex-col items-center gap-1 relative animate-in slide-in-from-left-4 fade-in">
                    <div className="relative flex -space-x-8">
                       {pendingToss.map(c => <Card key={c.id} card={c} disabled={true} className="opacity-70 ring-2 ring-blue-500/50" />)}
                       <div className="absolute inset-0 flex items-center justify-center pointer-events-none"><RefreshCw className="text-white drop-shadow-lg animate-spin" size={32} /></div>
                    </div>
                    <span className="text-xs uppercase tracking-wider font-bold text-blue-400">Tossing...</span>
                 </div>
              )}
            </div>

            {/* Final Match Complete UI - Same as App.tsx */}
            {step === 9 && (
               <div className="absolute inset-0 z-[100] flex items-center justify-center bg-black/80 backdrop-blur-md animate-in fade-in duration-700">
                 <div className="bg-slate-900 border border-yellow-500/30 p-8 rounded-[2.5rem] shadow-2xl max-w-md w-full text-center m-4 scale-in-center">
                    <div className="w-20 h-20 bg-yellow-500/20 rounded-full flex items-center justify-center mx-auto mb-6 border border-yellow-500/50">
                       <Trophy className="text-yellow-500" size={40} />
                    </div>
                    <h2 className="text-3xl font-serif font-bold text-white mb-2">Victory Secured</h2>
                    <p className="text-gray-400 mb-8 text-xs uppercase tracking-[0.3em] font-bold">Hand Energy: 5 • Rank: Master</p>

                    <div className="space-y-3 mb-10 text-left">
                       <div className="flex justify-between items-center p-4 rounded-2xl border bg-yellow-500/10 border-yellow-500/50">
                          <span className="text-yellow-400 font-bold flex items-center gap-2"><Sparkles size={16}/> YOU</span>
                          <span className="text-xl font-bold text-yellow-400">0 Total</span>
                       </div>
                       {[1, 2, 3].map(i => (
                         <div key={i} className="flex justify-between items-center p-4 rounded-2xl border bg-slate-800/50 border-white/5 opacity-50">
                            <span className="text-gray-400">Bot #{i}</span>
                            <span className="text-lg font-bold text-red-400/80">+25</span>
                         </div>
                       ))}
                    </div>

                    <button 
                      onClick={onExit} 
                      className="w-full bg-yellow-500 hover:bg-yellow-400 text-black font-black py-5 rounded-2xl flex items-center justify-center gap-3 transition-transform hover:scale-[1.02] active:scale-95 shadow-[0_10px_30px_rgba(234,179,8,0.3)]"
                    >
                       ENTER THE ARENA <ChevronRight size={24} />
                    </button>
                 </div>
               </div>
            )}
        </div>

        {/* Player Controls */}
        <div className="flex flex-col items-center gap-4 pb-8 shrink-0 relative">

           <div className={`flex items-center gap-2 bg-black/60 backdrop-blur-xl p-2 rounded-full border border-white/10 shadow-2xl transition-all scale-100 ${(step === 2 || step === 5 || step === 8) ? 'z-[70] opacity-100 translate-y-0' : 'z-0 opacity-0 translate-y-4 pointer-events-none'}`}>
              {step === 2 && (
                <button onClick={handleDiscardAction} className="bg-green-600 hover:bg-green-500 text-white px-8 py-3 rounded-full font-black flex items-center gap-2 text-sm shadow-[0_0_20px_rgba(22,163,74,0.4)] animate-bounce ring-4 ring-yellow-400">
                  <Hand size={20} /> DISCARD (1)
                </button>
              )}
              {step === 5 && (
                <button onClick={handleTossAction} className="bg-blue-600 hover:bg-blue-500 text-white px-8 py-3 rounded-full font-black flex items-center gap-2 text-sm shadow-[0_0_20px_rgba(37,99,235,0.4)] animate-bounce ring-4 ring-yellow-400">
                  <RefreshCw size={20} /> TOSS (2)
                </button>
              )}
              {step === 8 && (
                <button onClick={handleShowAction} className="bg-red-600 hover:bg-red-500 text-white px-10 py-3 rounded-full font-black flex items-center gap-2 text-sm shadow-[0_0_20px_rgba(220,38,38,0.4)] animate-bounce ring-4 ring-yellow-400">
                  <AlertCircle size={20} /> CALL SHOW
                </button>
              )}
           </div>

           <div className={`flex items-end justify-center -space-x-4 md:-space-x-6 h-[140px] md:h-[160px] transition-all duration-500 ${(step === 1 || step === 4 || step === 7) ? 'z-[70]' : 'z-10'}`}>
              {hand.map((card) => {
                const isSelected = selectedIds.includes(card.id);
                const isTarget = (step === 1 && card.id === KING_ID) || 
                               (step === 4 && (card.id === SEVEN_A_ID || card.id === SEVEN_B_ID));

                return (
                  <div key={card.id} className="relative transition-all">
                    <Card 
                      card={card} 
                      isJoker={card.rank === Rank.Ace}
                      selected={isSelected}
                      onClick={() => handleCardClick(card)}
                      className={`transition-all origin-bottom ${isTarget && !isSelected ? 'ring-4 ring-yellow-400 scale-110 shadow-[0_0_20px_rgba(234,179,8,0.5)]' : ''}`}
                    />
                    {isTarget && !isSelected && (
                       <div className="absolute -top-10 left-1/2 -translate-x-1/2 animate-bounce z-30">
                          <MousePointer2 className="text-yellow-400 fill-yellow-400 drop-shadow-md" size={32} />
                       </div>
                    )}
                  </div>
                );
              })}
           </div>

           <div className="text-xs text-gray-400 mt-2 flex flex-col items-center gap-1">
             <div className="flex items-center gap-2">
               <span className="text-green-500 font-black uppercase tracking-widest">Apprentice</span>
               <span className="w-1 h-1 bg-gray-600 rounded-full" />
               <span className="text-gray-300 font-bold">Energy Target: 5 or Less</span>
             </div>
             <div className="text-white font-black text-2xl flex items-baseline gap-2">
                <span className="text-[10px] text-gray-500 font-bold uppercase tracking-tighter">Current:</span>
                {calculateHandValue(hand, roundJoker)}
                {step === 7 && <span className="text-purple-400 text-xs animate-pulse ml-2 tracking-widest">(JOKER DETECTED)</span>}
             </div>
           </div>
        </div>
      </div>

      <style>{`
        .spotlight-hand {
          clip-path: polygon(0% 0%, 100% 0%, 100% 100%, 0% 100%, 0% 70%, 10% 70%, 10% 95%, 90% 95%, 90% 70%, 0% 70%);
        }
        .spotlight-controls {
          clip-path: polygon(0% 0%, 100% 0%, 100% 100%, 0% 100%, 0% 65%, 25% 65%, 25% 75%, 75% 75%, 75% 65%, 0% 65%);
        }
        .spotlight-table {
          clip-path: polygon(0% 0%, 100% 0%, 100% 100%, 0% 100%, 0% 30%, 15% 30%, 15% 60%, 85% 60%, 85% 30%, 0% 30%);
        }
        @keyframes scale-in-center {
          0% { transform: scale(0); opacity: 0; }
          100% { transform: scale(1); opacity: 1; }
        }
        .scale-in-center { animation: scale-in-center 0.5s cubic-bezier(0.250, 0.460, 0.450, 0.940) both; }
      `}</style>
    </div>
  );
};

