import React, { useState, useEffect } from 'react';
import { CardData, Suit, Rank } from '../types';
import Card from '../components/Card';
import TutorialSensei, { TUTORIAL_STEPS } from '../components/TutorialSensei';
import { calculateHandValue } from '../services/gameLogic';
import { ArrowRight, RefreshCw, Hand, AlertCircle, LogOut, Bot, GraduationCap, Trophy, ChevronRight, MousePointer2, Sparkles } from 'lucide-react';

// Hardcoded tutorial IDs
const KING_ID = 'tut-king';
const SEVEN_A_ID = 'tut-seven-a';
const SEVEN_B_ID = 'tut-seven-b';
const FIVE_ID = 'tut-five';
const ACE_ID = 'tut-ace-joker';

const INITIAL_HAND: CardData[] = [
  { id: KING_ID, suit: Suit.Hearts, rank: Rank.King, value: 10 },
  { id: SEVEN_A_ID, suit: Suit.Clubs, rank: Rank.Seven, value: 7 },
  { id: FIVE_ID, suit: Suit.Diamonds, rank: Rank.Five, value: 5 }
];

const MOCK_DECK: CardData[] = [
  { id: SEVEN_B_ID, suit: Suit.Spades, rank: Rank.Seven, value: 7 },
  { id: ACE_ID, suit: Suit.Hearts, rank: Rank.Ace, value: 1 },
];

interface TutorialEngineProps {
  onExit: () => void;
}

const TutorialEngine: React.FC<TutorialEngineProps> = ({ onExit }) => {
  const [step, setStep] = useState(0);
  const [hand, setHand] = useState<CardData[]>(INITIAL_HAND);
  const [deck, setDeck] = useState<CardData[]>(MOCK_DECK);
  const [openPile, setOpenPile] = useState<CardData[]>([]);
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [pendingDiscard, setPendingDiscard] = useState<CardData | null>(null);
  const [pendingToss, setPendingToss] = useState<CardData[]>([]);

  const roundJoker = { rank: Rank.Ace } as any;

  const handleCardClick = (card: CardData) => {
    if (step === 1 && card.id === KING_ID) {
      setSelectedIds([card.id]);
      setStep(2);
    } else if (step === 4 && (card.id === SEVEN_A_ID || card.id === SEVEN_B_ID)) {
      setSelectedIds(prev => {
        const next = prev.includes(card.id) ? prev.filter(id => id !== card.id) : [...prev, card.id];
        if (next.length === 2) setStep(5);
        return next;
      });
    }
  };

  const handleDiscardAction = () => {
    if (step === 2 && selectedIds.includes(KING_ID)) {
      const king = hand.find(c => c.id === KING_ID)!;
      setHand(prev => prev.filter(c => c.id !== KING_ID));
      setPendingDiscard(king);
      setSelectedIds([]);
      setStep(3);
    }
  };

  const handleDrawAction = () => {
    if ((step === 3 || step === 6) && deck.length > 0) {
      const drawn = deck[0];
      setDeck(prev => prev.slice(1));
      const newHand = [...hand, drawn];
      if (pendingDiscard) setOpenPile(prev => [...prev, pendingDiscard]);
      if (pendingToss.length) setOpenPile(prev => [...prev, ...pendingToss]);
      setHand(newHand);
      setPendingDiscard(null);
      setPendingToss([]);
      setStep(step + 1);
    }
  };

  const handleTossAction = () => {
    if (step === 5 && selectedIds.length === 2) {
      const tossed = hand.filter(c => selectedIds.includes(c.id));
      setHand(prev => prev.filter(c => !selectedIds.includes(c.id)));
      setPendingToss(tossed);
      setSelectedIds([]);
      setStep(6);
    }
  };

  const handleShowAction = () => {
    if (step === 8) setStep(9);
  };

  const getSpotlightClass = () => {
    if (step === 0 || step === 1 || step === 4 || step === 7) return 'spotlight-hand';
    if (step === 2 || step === 5 || step === 8) return 'spotlight-controls';
    if (step === 3 || step === 6) return 'spotlight-table';
    return '';
  };

  return (
    <div className="h-[100dvh] flex flex-col overflow-hidden bg-[#121c12] relative">
      {/* Dynamic Background Spotlight Overlay */}
      {step < 9 && (
        <div className={`fixed inset-0 bg-black/70 transition-all duration-700 z-[60] pointer-events-none backdrop-blur-[2px] ${getSpotlightClass()}`} />
      )}

      {step < 9 && (
        <TutorialSensei stepIndex={step} onNext={() => setStep(s => s + 1)} onExit={onExit} />
      )}

      {/* Persistent Header */}
      <div className="h-14 md:h-16 bg-[#0a120a] flex items-center justify-between px-4 shadow-2xl z-[80] shrink-0 border-b border-white/5">
        <div className="flex items-center gap-3 md:gap-4">
          <button onClick={onExit} className="text-red-400 hover:text-red-300 transition-colors bg-white/5 p-2 rounded-lg">
             <LogOut size={18} />
          </button>
          <div className="bg-yellow-500/10 px-3 py-1 rounded-full text-[10px] md:text-xs flex items-center gap-2 border border-yellow-500/30">
             <GraduationCap size={14} className="text-yellow-500" />
             <span className="font-bold text-yellow-500 uppercase tracking-widest">Protocol {step + 1}/10</span>
          </div>
        </div>

        <div className="flex items-center gap-2">
           <div className="flex bg-white text-black px-2 py-1 rounded-md border-2 border-purple-500 items-center gap-1 shadow-[0_0_15px_rgba(168,85,247,0.4)] scale-90 md:scale-100">
             <span className="font-bold text-xs">JOKER: A</span>
           </div>
        </div>

        <div className="flex items-center gap-4">
           <div className="flex items-center gap-2">
             <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse" />
             <span className="text-[10px] md:text-xs font-black text-white uppercase tracking-tighter">Human Apprentice</span>
           </div>
        </div>
      </div>

      {/* Main Arena */}
      <div className="flex-1 relative flex flex-col justify-between p-2 md:p-6 max-w-7xl mx-auto w-full overflow-hidden">

        {/* Opponents Area (Dimmed during tutorial) */}
        <div className="flex justify-center flex-wrap gap-2 md:gap-8 mb-2 opacity-10 grayscale pointer-events-none">
           {[1, 2, 3].map(id => (
             <div key={id} className="flex flex-col items-center p-2 rounded-lg bg-black/40 border border-white/5 scale-75 md:scale-100">
                <div className="w-10 h-10 bg-slate-800 rounded-full flex items-center justify-center border border-slate-700">
                  <Bot size={18} className="text-slate-500" />
                </div>
                <div className="flex -space-x-4 mt-2">
                   {[1, 2, 3].map(i => <Card key={i} small className="scale-75" />)}
                </div>
             </div>
           ))}
        </div>

        {/* Tactical Table Area */}
        <div className={`flex-1 flex items-center justify-center gap-6 md:gap-20 my-2 relative transition-all duration-500 ${(step === 3 || step === 6) ? 'z-[70]' : 'z-10'}`}>
            <div className="flex flex-col items-center gap-2 relative">
               <Card 
                 disabled={step !== 3 && step !== 6} 
                 onClick={handleDrawAction}
                 className={(step === 3 || step === 6) ? 'ring-4 ring-yellow-400 scale-110 shadow-[0_0_40px_rgba(234,179,8,0.6)] z-20 transition-transform' : ''} 
               />
               {(step === 3 || step === 6) && (
                 <div className="absolute -top-14 animate-bounce text-yellow-500 flex flex-col items-center z-30">
                    <span className="text-[9px] font-black bg-yellow-500 text-black px-3 py-1 rounded-full mb-1 shadow-xl">DRAW CARGO</span>
                    <ChevronRight size={20} className="rotate-90" />
                 </div>
               )}
               <span className="text-[10px] uppercase tracking-[0.2em] font-bold text-slate-500">Stockpile</span>
            </div>

            <div className="flex gap-4 items-center">
              <div className="flex flex-col items-center gap-2 relative">
                 {openPile.length > 0 ? (
                   <Card card={openPile[openPile.length - 1]} isJoker={openPile[openPile.length - 1].rank === Rank.Ace} disabled={true} />
                 ) : (
                   <div className="w-20 h-28 md:w-24 md:h-36 border-2 border-dashed border-white/5 rounded-2xl flex items-center justify-center">
                     <span className="text-white/10 text-[10px] uppercase tracking-widest font-black">Refuse</span>
                   </div>
                 )}
                 <span className="text-[10px] uppercase tracking-[0.2em] font-bold text-slate-500">Open Pile</span>
              </div>

              {pendingDiscard && (
                <div className="flex flex-col items-center gap-2 relative animate-in slide-in-from-left-4 fade-in">
                  <div className="relative">
                    <Card card={pendingDiscard} disabled={true} className="opacity-70 ring-2 ring-yellow-500/50" />
                    <div className="absolute inset-0 flex items-center justify-center pointer-events-none"><ArrowRight className="text-white drop-shadow-xl" size={40} /></div>
                  </div>
                  <span className="text-[10px] uppercase tracking-widest font-bold text-yellow-500">Discarding</span>
                </div>
              )}

              {pendingToss.length > 0 && (
                 <div className="flex flex-col items-center gap-1 relative animate-in slide-in-from-left-4 fade-in">
                    <div className="relative flex -space-x-8">
                       {pendingToss.map(c => <Card key={c.id} card={c} disabled={true} className="opacity-70 ring-2 ring-blue-500/50" />)}
                       <div className="absolute inset-0 flex items-center justify-center pointer-events-none"><RefreshCw className="text-white drop-shadow-xl animate-spin" size={40} /></div>
                    </div>
                    <span className="text-[10px] uppercase tracking-widest font-bold text-blue-500">Twin Toss</span>
                 </div>
              )}
            </div>

            {/* Success Overlay */}
            {step === 9 && (
               <div className="absolute inset-0 z-[100] flex items-center justify-center bg-black/90 backdrop-blur-xl animate-in fade-in duration-1000">
                 <div className="bg-slate-900 border border-yellow-500/30 p-10 rounded-[3rem] shadow-2xl max-w-sm w-full text-center m-4 scale-in-center">
                    <div className="w-24 h-24 bg-yellow-500 rounded-[2rem] flex items-center justify-center mx-auto mb-8 rotate-12 shadow-[0_0_50px_rgba(234,179,8,0.4)]">
                       <Trophy className="text-black" size={48} />
                    </div>
                    <h2 className="text-4xl font-serif font-black text-white mb-2">Protocol Clear</h2>
                    <p className="text-gray-500 mb-10 text-[10px] uppercase tracking-[0.4em] font-black">Hand Energy: 5 • Academy Certified</p>

                    <button 
                      onClick={onExit} 
                      className="w-full bg-yellow-500 hover:bg-yellow-400 text-black font-black py-5 rounded-2xl flex items-center justify-center gap-3 transition-transform hover:scale-[1.05] active:scale-95 shadow-[0_20px_40px_rgba(234,179,8,0.3)]"
                    >
                       ENTER THE ARENA <ChevronRight size={24} />
                    </button>
                 </div>
               </div>
            )}
        </div>

        {/* Controls and Player Hand */}
        <div className="flex flex-col items-center gap-4 pb-12 md:pb-16 shrink-0 relative">

           <div className={`flex items-center gap-2 bg-black/80 backdrop-blur-2xl p-2 rounded-[2rem] border border-white/10 shadow-[0_30px_60px_rgba(0,0,0,0.5)] transition-all transform ${(step === 2 || step === 5 || step === 8) ? 'z-[70] opacity-100 translate-y-0 scale-100' : 'z-0 opacity-0 translate-y-10 scale-90 pointer-events-none'}`}>
              {step === 2 && (
                <button onClick={handleDiscardAction} className="bg-green-600 hover:bg-green-500 text-white px-10 py-4 rounded-2xl font-black flex items-center gap-3 text-sm shadow-[0_15px_30px_rgba(22,163,74,0.3)] animate-bounce ring-4 ring-yellow-400">
                  <Hand size={20} /> EXECUTE DISCARD
                </button>
              )}
              {step === 5 && (
                <button onClick={handleTossAction} className="bg-blue-600 hover:bg-blue-500 text-white px-10 py-4 rounded-2xl font-black flex items-center gap-3 text-sm shadow-[0_15px_30px_rgba(37,99,235,0.3)] animate-bounce ring-4 ring-yellow-400">
                  <RefreshCw size={20} /> EXECUTE TWIN TOSS
                </button>
              )}
              {step === 8 && (
                <button onClick={handleShowAction} className="bg-red-600 hover:bg-red-500 text-white px-12 py-4 rounded-2xl font-black flex items-center gap-3 text-sm shadow-[0_15px_30px_rgba(220,38,38,0.3)] animate-bounce ring-4 ring-yellow-400">
                  <AlertCircle size={20} /> CALL SHOWDOWN
                </button>
              )}
           </div>

           <div className={`flex items-end justify-center -space-x-6 md:-space-x-8 h-[140px] md:h-[180px] transition-all duration-700 ${(step === 1 || step === 4 || step === 7) ? 'z-[70] scale-105' : 'z-10 scale-100'}`}>
              {hand.map((card) => {
                const isSelected = selectedIds.includes(card.id);
                const isTarget = (step === 1 && card.id === KING_ID) || 
                               (step === 4 && (card.id === SEVEN_A_ID || card.id === SEVEN_B_ID));

                return (
                  <div key={card.id} className="relative transition-all duration-300">
                    <Card 
                      card={card} 
                      isJoker={card.rank === Rank.Ace}
                      selected={isSelected}
                      onClick={() => handleCardClick(card)}
                      className={`transition-all origin-bottom ${isTarget && !isSelected ? 'ring-4 ring-yellow-400 scale-110 shadow-[0_0_30px_rgba(234,179,8,0.7)] z-30' : ''}`}
                    />
                    {isTarget && !isSelected && (
                       <div className="absolute -top-12 left-1/2 -translate-x-1/2 animate-bounce z-[80]">
                          <div className="bg-yellow-500 p-2 rounded-full shadow-2xl">
                             <MousePointer2 className="text-black" size={24} />
                          </div>
                       </div>
                    )}
                  </div>
                );
              })}
           </div>

           <div className="text-xs text-gray-500 mt-4 flex flex-col items-center gap-2">
             <div className="flex items-center gap-3 bg-black/20 px-4 py-1.5 rounded-full border border-white/5">
               <span className="text-green-500 font-black uppercase tracking-[0.2em] text-[10px]">Apprentice Unit</span>
               <div className="w-1 h-1 bg-gray-700 rounded-full" />
               <span className="text-gray-400 font-bold text-[10px]">Showdown Limit: 5</span>
             </div>
             <div className="text-white font-black text-3xl flex items-baseline gap-2 tabular-nums">
                <span className="text-[10px] text-gray-600 font-black uppercase tracking-widest">Hand Energy:</span>
                {calculateHandValue(hand, roundJoker)}
             </div>
           </div>
        </div>
      </div>

      <style>{`
        .spotlight-hand {
          clip-path: polygon(0% 0%, 100% 0%, 100% 100%, 0% 100%, 0% 60%, 5% 60%, 5% 95%, 95% 95%, 95% 60%, 0% 60%);
        }
        .spotlight-controls {
          clip-path: polygon(0% 0%, 100% 0%, 100% 100%, 0% 100%, 0% 55%, 20% 55%, 20% 75%, 80% 75%, 80% 55%, 0% 55%);
        }
        .spotlight-table {
          clip-path: polygon(0% 0%, 100% 0%, 100% 100%, 0% 100%, 0% 25%, 10% 25%, 10% 65%, 90% 65%, 90% 25%, 0% 25%);
        }
        @keyframes scale-in-center {
          0% { transform: scale(0); opacity: 0; }
          100% { transform: scale(1); opacity: 1; }
        }
        .scale-in-center { animation: scale-in-center 0.6s cubic-bezier(0.175, 0.885, 0.32, 1.275) both; }
      `}</style>
    </div>
  );
};

export default TutorialEngine;

import React from 'react';
import { GraduationCap, Play, LogOut, ChevronRight, Sparkles } from 'lucide-react';

export interface TutorialStep {
  text: string;
  highlight: string;
  isNarrative?: boolean;
}

export const TUTORIAL_STEPS: TutorialStep[] = [
  { text: "Welcome, Cadet. Tri-Stack Protocol is in effect. Your mission: Reach 5 Hand Energy or less and initiate a Showdown with the lowest score at the table.", highlight: "hand", isNarrative: true },
  { text: "This King is a liability. 10 Energy points is critical mass. Tap the card to select it for disposal.", highlight: "king" },
  { text: "Excellent. Now execute DISCARD. We must purge high-value cards to stabilize your energy levels.", highlight: "discard" },
  { text: "Cycle replenishment required. Draw from the Stockpile to conclude the turn maneuver.", highlight: "deck" },
  { text: "Twin Match confirmed. A pair of Sevens has been detected. In Tri-Stack v3, pairs allow a Twin Toss. Select both cards.", highlight: "sevens" },
  { text: "Initialize TOSS. This maneuver permanently reduces hand size, accelerating your descent to zero energy. Efficiency is vital.", highlight: "toss" },
  { text: "Stabilize hand. Draw one final card to refill your loadout.", highlight: "deck" },
  { text: "Protocol Alert: You've secured an ACE. This round, Aces are JOKERS. Energy value: ZERO. Your total is now 5.", highlight: "joker", isNarrative: true },
  { text: "Condition Green. Your energy is within the Showdown Limit. Initiate SHOW now to catch opponents off-guard.", highlight: "show" },
  { text: "Simulation Successful. You secured the lowest score. The Bots take the penalties. First to 100 points is eliminated. Academy dismissed.", highlight: "end", isNarrative: true }
];

interface TutorialSenseiProps {
  stepIndex: number;
  onNext: () => void;
  onExit: () => void;
}

const TutorialSensei: React.FC<TutorialSenseiProps> = ({ stepIndex, onNext, onExit }) => {
  const currentStep = TUTORIAL_STEPS[stepIndex];
  if (!currentStep) return null;

  const isLastStep = stepIndex === TUTORIAL_STEPS.length - 1;

  // Use more compact positioning that stays out of the way
  return (
    <div className="absolute top-[4.5rem] md:top-[5.5rem] left-1/2 -translate-x-1/2 z-[90] w-[92%] max-w-lg pointer-events-none">
      <div className="bg-slate-900/60 backdrop-blur-2xl border border-yellow-500/40 p-5 rounded-[2rem] shadow-[0_30px_100px_rgba(0,0,0,0.8)] animate-in slide-in-from-top-4 pointer-events-auto overflow-hidden">
        {/* Step Indicator Dot */}
        <div className="absolute top-4 right-6 flex gap-1">
          {Array.from({ length: TUTORIAL_STEPS.length }).map((_, i) => (
            <div key={i} className={`w-1 h-1 rounded-full transition-all duration-300 ${i === stepIndex ? 'bg-yellow-500 w-3' : 'bg-white/10'}`} />
          ))}
        </div>

        <div className="flex items-start gap-4">
          <div className="relative shrink-0 mt-0.5">
            <div className="bg-yellow-500 p-2.5 rounded-[1.25rem] text-black shadow-lg shadow-yellow-500/20">
              <GraduationCap size={24} />
            </div>
            <div className="absolute -bottom-1 -right-1 w-4 h-4 bg-green-500 rounded-full border-[3px] border-slate-900 animate-pulse" />
          </div>

          <div className="flex-1">
            <div className="flex items-center gap-1.5 mb-1 opacity-70">
              <Sparkles size={10} className="text-yellow-500" />
              <h4 className="text-yellow-500 text-[9px] font-black uppercase tracking-[0.25em]">Tactical Instructor</h4>
            </div>

            <p className="text-white font-bold text-sm leading-tight mb-4 pr-4">
              {currentStep.text}
            </p>

            <div className="flex items-center justify-between">
              {currentStep.isNarrative && !isLastStep ? (
                <button 
                  onClick={onNext}
                  className="bg-yellow-500 hover:bg-yellow-400 text-black px-5 py-2 rounded-xl text-[10px] font-black uppercase tracking-widest flex items-center gap-2 transition-all active:scale-95 shadow-lg shadow-yellow-900/20"
                >
                  <Play size={12} fill="currentColor" /> Proceed
                </button>
              ) : (
                <div className="text-[9px] text-gray-500 uppercase tracking-widest font-black flex items-center gap-2">
                   <div className="w-1 h-1 bg-yellow-500 rounded-full animate-ping" /> Instruction Pending...
                </div>
              )}

              {!isLastStep && (
                <button 
                  onClick={onExit}
                  className="text-gray-500 text-[9px] font-black uppercase hover:text-red-400 transition-colors flex items-center gap-1.5 group"
                >
                  Terminate <LogOut size={12} className="group-hover:translate-x-1 transition-transform" />
                </button>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default TutorialSensei;

import React, { useState, useEffect } from 'react';
import { CardData, Suit, Rank } from '../types';
import Card from '../components/Card';
import TutorialSensei, { TUTORIAL_STEPS } from '../components/TutorialSensei';
import { calculateHandValue } from '../services/gameLogic';
import { ArrowRight, RefreshCw, Hand, AlertCircle, LogOut, Bot, GraduationCap, Trophy, ChevronRight, MousePointer2, Sparkles } from 'lucide-react';

// Hardcoded tutorial IDs
const KING_ID = 'tut-king';
const SEVEN_A_ID = 'tut-seven-a';
const SEVEN_B_ID = 'tut-seven-b';
const FIVE_ID = 'tut-five';
const ACE_ID = 'tut-ace-joker';

const INITIAL_HAND: CardData[] = [
  { id: KING_ID, suit: Suit.Hearts, rank: Rank.King, value: 10 },
  { id: SEVEN_A_ID, suit: Suit.Clubs, rank: Rank.Seven, value: 7 },
  { id: FIVE_ID, suit: Suit.Diamonds, rank: Rank.Five, value: 5 }
];

const MOCK_DECK: CardData[] = [
  { id: SEVEN_B_ID, suit: Suit.Spades, rank: Rank.Seven, value: 7 },
  { id: ACE_ID, suit: Suit.Hearts, rank: Rank.Ace, value: 1 },
];

interface TutorialEngineProps {
  onExit: () => void;
}

const TutorialEngine: React.FC<TutorialEngineProps> = ({ onExit }) => {
  const [step, setStep] = useState(0);
  const [hand, setHand] = useState<CardData[]>(INITIAL_HAND);
  const [deck, setDeck] = useState<CardData[]>(MOCK_DECK);
  const [openPile, setOpenPile] = useState<CardData[]>([]);
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [pendingDiscard, setPendingDiscard] = useState<CardData | null>(null);
  const [pendingToss, setPendingToss] = useState<CardData[]>([]);

  const roundJoker = { rank: Rank.Ace } as any;

  const handleCardClick = (card: CardData) => {
    if (step === 1 && card.id === KING_ID) {
      setSelectedIds([card.id]);
      setStep(2);
    } else if (step === 4 && (card.id === SEVEN_A_ID || card.id === SEVEN_B_ID)) {
      setSelectedIds(prev => {
        const next = prev.includes(card.id) ? prev.filter(id => id !== card.id) : [...prev, card.id];
        if (next.length === 2) setStep(5);
        return next;
      });
    }
  };

  const handleDiscardAction = () => {
    if (step === 2 && selectedIds.includes(KING_ID)) {
      const king = hand.find(c => c.id === KING_ID)!;
      setHand(prev => prev.filter(c => c.id !== KING_ID));
      setPendingDiscard(king);
      setSelectedIds([]);
      setStep(3);
    }
  };

  const handleDrawAction = () => {
    if ((step === 3 || step === 6) && deck.length > 0) {
      const drawn = deck[0];
      setDeck(prev => prev.slice(1));
      const newHand = [...hand, drawn];
      if (pendingDiscard) setOpenPile(prev => [...prev, pendingDiscard]);
      if (pendingToss.length) setOpenPile(prev => [...prev, ...pendingToss]);
      setHand(newHand);
      setPendingDiscard(null);
      setPendingToss([]);
      setStep(step + 1);
    }
  };

  const handleTossAction = () => {
    if (step === 5 && selectedIds.length === 2) {
      const tossed = hand.filter(c => selectedIds.includes(c.id));
      setHand(prev => prev.filter(c => !selectedIds.includes(c.id)));
      setPendingToss(tossed);
      setSelectedIds([]);
      setStep(6);
    }
  };

  const handleShowAction = () => {
    if (step === 8) setStep(9);
  };

  const getSpotlightClass = () => {
    if (step === 0 || step === 1 || step === 4 || step === 7) return 'spotlight-hand';
    if (step === 2 || step === 5 || step === 8) return 'spotlight-controls';
    if (step === 3 || step === 6) return 'spotlight-table';
    return '';
  };

  return (
    <div className="h-[100dvh] flex flex-col overflow-hidden bg-[#121c12] relative">
      {/* Dynamic Background Spotlight Overlay */}
      {step < 9 && (
        <div className={`fixed inset-0 bg-black/70 transition-all duration-700 z-[60] pointer-events-none backdrop-blur-[2px] ${getSpotlightClass()}`} />
      )}

      {step < 9 && (
        <TutorialSensei stepIndex={step} onNext={() => setStep(s => s + 1)} onExit={onExit} />
      )}

      {/* Persistent Header */}
      <div className="h-14 md:h-16 bg-[#0a120a] flex items-center justify-between px-4 shadow-2xl z-[80] shrink-0 border-b border-white/5">
        <div className="flex items-center gap-3 md:gap-4">
          <button onClick={onExit} className="text-red-400 hover:text-red-300 transition-colors bg-white/5 p-2 rounded-lg">
             <LogOut size={18} />
          </button>
          <div className="bg-yellow-500/10 px-3 py-1 rounded-full text-[10px] md:text-xs flex items-center gap-2 border border-yellow-500/30">
             <GraduationCap size={14} className="text-yellow-500" />
             <span className="font-bold text-yellow-500 uppercase tracking-widest">Protocol {step + 1}/10</span>
          </div>
        </div>

        <div className="flex items-center gap-2">
           <div className="flex bg-white text-black px-2 py-1 rounded-md border-2 border-purple-500 items-center gap-1 shadow-[0_0_15px_rgba(168,85,247,0.4)] scale-90 md:scale-100">
             <span className="font-bold text-xs">JOKER: A</span>
           </div>
        </div>

        <div className="flex items-center gap-4">
           <div className="flex items-center gap-2">
             <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse" />
             <span className="text-[10px] md:text-xs font-black text-white uppercase tracking-tighter">Human Apprentice</span>
           </div>
        </div>
      </div>

      {/* Main Arena */}
      <div className="flex-1 relative flex flex-col justify-between p-2 md:p-6 max-w-7xl mx-auto w-full overflow-hidden">

        {/* Opponents Area (Dimmed during tutorial) */}
        <div className="flex justify-center flex-wrap gap-2 md:gap-8 mb-2 opacity-10 grayscale pointer-events-none">
           {[1, 2, 3].map(id => (
             <div key={id} className="flex flex-col items-center p-2 rounded-lg bg-black/40 border border-white/5 scale-75 md:scale-100">
                <div className="w-10 h-10 bg-slate-800 rounded-full flex items-center justify-center border border-slate-700">
                  <Bot size={18} className="text-slate-500" />
                </div>
                <div className="flex -space-x-4 mt-2">
                   {[1, 2, 3].map(i => <Card key={i} small className="scale-75" />)}
                </div>
             </div>
           ))}
        </div>

        {/* Tactical Table Area */}
        <div className={`flex-1 flex items-center justify-center gap-6 md:gap-20 my-2 relative transition-all duration-500 ${(step === 3 || step === 6) ? 'z-[70]' : 'z-10'}`}>
            <div className="flex flex-col items-center gap-2 relative">
               <Card 
                 disabled={step !== 3 && step !== 6} 
                 onClick={handleDrawAction}
                 className={(step === 3 || step === 6) ? 'ring-4 ring-yellow-400 scale-110 shadow-[0_0_40px_rgba(234,179,8,0.6)] z-20 transition-transform' : ''} 
               />
               {(step === 3 || step === 6) && (
                 <div className="absolute -top-14 animate-bounce text-yellow-500 flex flex-col items-center z-30">
                    <span className="text-[9px] font-black bg-yellow-500 text-black px-3 py-1 rounded-full mb-1 shadow-xl">DRAW CARGO</span>
                    <ChevronRight size={20} className="rotate-90" />
                 </div>
               )}
               <span className="text-[10px] uppercase tracking-[0.2em] font-bold text-slate-500">Stockpile</span>
            </div>

            <div className="flex gap-4 items-center">
              <div className="flex flex-col items-center gap-2 relative">
                 {openPile.length > 0 ? (
                   <Card card={openPile[openPile.length - 1]} isJoker={openPile[openPile.length - 1].rank === Rank.Ace} disabled={true} />
                 ) : (
                   <div className="w-20 h-28 md:w-24 md:h-36 border-2 border-dashed border-white/5 rounded-2xl flex items-center justify-center">
                     <span className="text-white/10 text-[10px] uppercase tracking-widest font-black">Refuse</span>
                   </div>
                 )}
                 <span className="text-[10px] uppercase tracking-[0.2em] font-bold text-slate-500">Open Pile</span>
              </div>

              {pendingDiscard && (
                <div className="flex flex-col items-center gap-2 relative animate-in slide-in-from-left-4 fade-in">
                  <div className="relative">
                    <Card card={pendingDiscard} disabled={true} className="opacity-70 ring-2 ring-yellow-500/50" />
                    <div className="absolute inset-0 flex items-center justify-center pointer-events-none"><ArrowRight className="text-white drop-shadow-xl" size={40} /></div>
                  </div>
                  <span className="text-[10px] uppercase tracking-widest font-bold text-yellow-500">Discarding</span>
                </div>
              )}

              {pendingToss.length > 0 && (
                 <div className="flex flex-col items-center gap-1 relative animate-in slide-in-from-left-4 fade-in">
                    <div className="relative flex -space-x-8">
                       {pendingToss.map(c => <Card key={c.id} card={c} disabled={true} className="opacity-70 ring-2 ring-blue-500/50" />)}
                       <div className="absolute inset-0 flex items-center justify-center pointer-events-none"><RefreshCw className="text-white drop-shadow-xl animate-spin" size={40} /></div>
                    </div>
                    <span className="text-[10px] uppercase tracking-widest font-bold text-blue-500">Twin Toss</span>
                 </div>
              )}
            </div>

            {/* Success Overlay */}
            {step === 9 && (
               <div className="absolute inset-0 z-[100] flex items-center justify-center bg-black/90 backdrop-blur-xl animate-in fade-in duration-1000">
                 <div className="bg-slate-900 border border-yellow-500/30 p-10 rounded-[3rem] shadow-2xl max-w-sm w-full text-center m-4 scale-in-center">
                    <div className="w-24 h-24 bg-yellow-500 rounded-[2rem] flex items-center justify-center mx-auto mb-8 rotate-12 shadow-[0_0_50px_rgba(234,179,8,0.4)]">
                       <Trophy className="text-black" size={48} />
                    </div>
                    <h2 className="text-4xl font-serif font-black text-white mb-2">Protocol Clear</h2>
                    <p className="text-gray-500 mb-10 text-[10px] uppercase tracking-[0.4em] font-black">Hand Energy: 5 • Academy Certified</p>

                    <button 
                      onClick={onExit} 
                      className="w-full bg-yellow-500 hover:bg-yellow-400 text-black font-black py-5 rounded-2xl flex items-center justify-center gap-3 transition-transform hover:scale-[1.05] active:scale-95 shadow-[0_20px_40px_rgba(234,179,8,0.3)]"
                    >
                       ENTER THE ARENA <ChevronRight size={24} />
                    </button>
                 </div>
               </div>
            )}
        </div>

        {/* Action Controls & Player Hand */}
        <div className="flex flex-col items-center gap-4 pb-12 md:pb-16 shrink-0 relative">

           {/* UI PARITY ACTION BAR: Exact same styling as App.tsx */}
           <div className={`flex items-center gap-2 bg-black/40 backdrop-blur-md p-2 rounded-full border border-white/10 shadow-xl transition-all z-[70] scale-90 md:scale-100 ${step === 2 || step === 5 || step === 8 ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-4 pointer-events-none'}`}>
              <button 
                onClick={handleShowAction} 
                disabled={step !== 8}
                className={`px-4 py-2 rounded-full font-bold flex items-center gap-2 text-xs md:text-sm transition-all ${step === 8 ? 'bg-red-600 hover:bg-red-500 text-white shadow-lg shadow-red-900/50 ring-4 ring-yellow-400 animate-pulse' : 'bg-slate-700 text-slate-500 cursor-not-allowed opacity-40'}`}
              >
                <AlertCircle size={16} /> SHOW
              </button>

              <div className="w-px h-6 bg-white/20 mx-1"></div>

              <button 
                onClick={handleTossAction} 
                disabled={step !== 5}
                className={`px-4 py-2 rounded-full font-bold flex items-center gap-2 text-xs md:text-sm transition-all ${step === 5 ? 'bg-blue-600 hover:bg-blue-500 text-white shadow-lg shadow-blue-900/50 ring-4 ring-yellow-400 animate-pulse' : 'bg-slate-700 text-slate-500 cursor-not-allowed opacity-40'}`}
              >
                <RefreshCw size={16} /> TOSS (2)
              </button>

              <button 
                onClick={handleDiscardAction} 
                disabled={step !== 2}
                className={`px-4 py-2 rounded-full font-bold flex items-center gap-2 text-xs md:text-sm transition-all ${step === 2 ? 'bg-green-600 hover:bg-green-500 text-white shadow-lg shadow-green-900/50 ring-4 ring-yellow-400 animate-pulse' : 'bg-slate-700 text-slate-500 cursor-not-allowed opacity-40'}`}
              >
                <Hand size={16} /> DISCARD (1)
              </button>
           </div>

           {/* Player Hand */}
           <div className={`flex items-end justify-center -space-x-6 md:-space-x-8 h-[140px] md:h-[180px] transition-all duration-700 ${(step === 1 || step === 4 || step === 7) ? 'z-[70] scale-105' : 'z-10 scale-100'}`}>
              {hand.map((card) => {
                const isSelected = selectedIds.includes(card.id);
                const isTarget = (step === 1 && card.id === KING_ID) || 
                               (step === 4 && (card.id === SEVEN_A_ID || card.id === SEVEN_B_ID));

                return (
                  <div key={card.id} className="relative transition-all duration-300">
                    <Card 
                      card={card} 
                      isJoker={card.rank === Rank.Ace}
                      selected={isSelected}
                      onClick={() => handleCardClick(card)}
                      className={`transition-all origin-bottom ${isTarget && !isSelected ? 'ring-4 ring-yellow-400 scale-110 shadow-[0_0_30px_rgba(234,179,8,0.7)] z-30' : ''}`}
                    />
                    {isTarget && !isSelected && (
                       <div className="absolute -top-12 left-1/2 -translate-x-1/2 animate-bounce z-[80]">
                          <div className="bg-yellow-500 p-2 rounded-full shadow-2xl">
                             <MousePointer2 className="text-black" size={24} />
                          </div>
                       </div>
                    )}
                  </div>
                );
              })}
           </div>

           <div className="text-xs text-gray-500 mt-4 flex flex-col items-center gap-2">
             <div className="flex items-center gap-3 bg-black/20 px-4 py-1.5 rounded-full border border-white/5">
               <span className="text-green-500 font-black uppercase tracking-[0.2em] text-[10px]">Apprentice Unit</span>
               <div className="w-1 h-1 bg-gray-700 rounded-full" />
               <span className="text-gray-400 font-bold text-[10px]">Showdown Limit: 5</span>
             </div>
             <div className="text-white font-black text-3xl flex items-baseline gap-2 tabular-nums">
                <span className="text-[10px] text-gray-600 font-black uppercase tracking-widest">Hand Energy:</span>
                {calculateHandValue(hand, roundJoker)}
             </div>
           </div>
        </div>
      </div>

      <style>{`
        .spotlight-hand {
          clip-path: polygon(0% 0%, 100% 0%, 100% 100%, 0% 100%, 0% 60%, 5% 60%, 5% 95%, 95% 95%, 95% 60%, 0% 60%);
        }
        .spotlight-controls {
          clip-path: polygon(0% 0%, 100% 0%, 100% 100%, 0% 100%, 0% 55%, 20% 55%, 20% 75%, 80% 75%, 80% 55%, 0% 55%);
        }
        .spotlight-table {
          clip-path: polygon(0% 0%, 100% 0%, 100% 100%, 0% 100%, 0% 25%, 10% 25%, 10% 65%, 90% 65%, 90% 25%, 0% 25%);
        }
        @keyframes scale-in-center {
          0% { transform: scale(0); opacity: 0; }
          100% { transform: scale(1); opacity: 1; }
        }
        .scale-in-center { animation: scale-in-center 0.6s cubic-bezier(0.175, 0.885, 0.32, 1.275) both; }
      `}</style>
    </div>
  );
};

export default TutorialEngine;

import React from 'react';
import { GraduationCap, Play, LogOut, Sparkles, ChevronRight } from 'lucide-react';

export interface TutorialStep {
  text: string;
  target: 'hand' | 'deck' | 'pile' | 'toss' | 'discard' | 'show' | 'none';
  isNarrative?: boolean;
}

export const TUTORIAL_STEPS: TutorialStep[] = [
  { text: "INITIATING SIMULATION: Minimize Hand Energy. Aces are JOKERS (0 pts). Targets: 5 Energy or less.", target: 'none', isNarrative: true },
  { text: "THREAT DETECTED: That King is 10 Energy. High weight. Select it for disposal.", target: 'hand' },
  { text: "PROTOCOL: DISCARD selected card to purge high energy from your system.", target: 'discard' },
  { text: "REPLENISHMENT: Draw a new unit from the Stockpile to stabilize your hand.", target: 'deck' },
  { text: "V3 TACTIC: A pair of Sevens found. Select BOTH to prepare a TWIN TOSS.", target: 'hand' },
  { text: "TWIN TOSS: Execute now. This dumps two cards and reduces total hand size.", target: 'toss' },
  { text: "FINAL DRAW: Recover one unit from the Stockpile to reach operational capacity.", target: 'deck' },
  { text: "ENERGY STABILIZED: You hold a Joker. Current Energy is 5. Showdown enabled.", target: 'none', isNarrative: true },
  { text: "EXECUTION: Call SHOW to catch opponents in high-energy states.", target: 'show' },
