  if (!currentStep) return null;

  return (
    <div className="fixed top-0 left-0 right-0 z-[100] px-4 pt- safe-top">
      <div className="max-w-xl mx-auto mt-4 bg-black/60 backdrop-blur-xl border border-yellow-500/20 rounded-2xl shadow-2xl overflow-hidden animate-in slide-in-from-top-4 duration-500">
        <div className="flex items-center gap-4 p-3 md:p-4">
          <div className="relative shrink-0">
            <div className="bg-yellow-500/10 p-2 rounded-xl border border-yellow-500/40 text-yellow-500">
              <GraduationCap size={20} />
            </div>
            <div className="absolute -bottom-1 -right-1 w-3 h-3 bg-green-500 rounded-full border-2 border-black animate-pulse" />
