import React, { useState } from 'react';
import { CardData, Suit, Rank } from '../types';
import Card from '../components/Card';
import TutorialSensei, { TUTORIAL_STEPS } from '../components/TutorialSensei';
import { calculateHandValue } from '../services/gameLogic';
import { ArrowRight, RefreshCw, Hand, AlertCircle, Bot, GraduationCap, Trophy, ChevronRight, MousePointer2, Sparkles } from 'lucide-react';

const KING_ID = 'tut-king';
const SEVEN_A_ID = 'tut-seven-a';
const SEVEN_B_ID = 'tut-seven-b';
const FIVE_ID = 'tut-five';
const ACE_ID = 'tut-ace-joker';

const INITIAL_HAND: CardData[] = [
  { id: KING_ID, suit: Suit.Hearts, rank: Rank.King, value: 10 },
  { id: SEVEN_A_ID, suit: Suit.Clubs, rank: Rank.Seven, value: 7 },
  { id: FIVE_ID, suit: Suit.Diamonds, rank: Rank.Five, value: 5 }
];

const MOCK_DECK: CardData[] = [
  { id: SEVEN_B_ID, suit: Suit.Spades, rank: Rank.Seven, value: 7 },
  { id: ACE_ID, suit: Suit.Hearts, rank: Rank.Ace, value: 1 },
];

interface TutorialEngineProps {
  onExit: () => void;
}

const TutorialEngine: React.FC<TutorialEngineProps> = ({ onExit }) => {
  const [step, setStep] = useState(0);
  const [hand, setHand] = useState<CardData[]>(INITIAL_HAND);
  const [deck, setDeck] = useState<CardData[]>(MOCK_DECK);
  const [openPile, setOpenPile] = useState<CardData[]>([]);
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [pendingDiscard, setPendingDiscard] = useState<CardData | null>(null);
  const [pendingToss, setPendingToss] = useState<CardData[]>([]);

  const roundJoker = { rank: Rank.Ace } as any;

  const handleCardClick = (card: CardData) => {
    if (step === 1 && card.id === KING_ID) {
      setSelectedIds([card.id]);
      setStep(2);
    } else if (step === 4 && (card.id === SEVEN_A_ID || card.id === SEVEN_B_ID)) {
      setSelectedIds(prev => {
        const next = prev.includes(card.id) ? prev.filter(id => id !== card.id) : [...prev, card.id];
        if (next.length === 2) setStep(5);
        return next;
      });
    }
  };

  const handleDiscardAction = () => {
    if (step === 2 && selectedIds.includes(KING_ID)) {
      const king = hand.find(c => c.id === KING_ID)!;
      setHand(prev => prev.filter(c => c.id !== KING_ID));
      setPendingDiscard(king);
      setSelectedIds([]);
      setStep(3);
    }
  };

  const handleDrawAction = () => {
    if ((step === 3 || step === 6) && deck.length > 0) {
      const drawn = deck[0];
      setDeck(prev => prev.slice(1));
      const newHand = [...hand, drawn];
      if (pendingDiscard) setOpenPile(prev => [...prev, pendingDiscard]);
      if (pendingToss.length) setOpenPile(prev => [...prev, ...pendingToss]);
      setHand(newHand);
      setPendingDiscard(null);
      setPendingToss([]);
      setStep(step + 1);
    }
  };

  const handleTossAction = () => {
    if (step === 5 && selectedIds.length === 2) {
      const tossed = hand.filter(c => selectedIds.includes(c.id));
      setHand(prev => prev.filter(c => !selectedIds.includes(c.id)));
      setPendingToss(tossed);
      setSelectedIds([]);
      setStep(6);
    }
  };

  const handleShowAction = () => {
    if (step === 8) setStep(9);
  };

  const currentStepData = TUTORIAL_STEPS[step];

  return (
    <div className="h-[100dvh] flex flex-col overflow-hidden bg-[#0d140d] relative font-sans">

      {/* Academy HUD */}
      <TutorialSensei stepIndex={step} onNext={() => setStep(s => s + 1)} onExit={onExit} />

      {/* Persistent Subtle Grid Overlay */}
      <div className="absolute inset-0 opacity-[0.03] pointer-events-none bg-[url('https://www.transparenttextures.com/patterns/carbon-fibre.png')]" />

      {/* Table Arena */}
      <div className="flex-1 relative flex flex-col justify-between p-4 md:p-8 max-w-7xl mx-auto w-full overflow-hidden">

        {/* Opponents (Offline for Simulation) */}
        <div className="flex justify-center gap-4 md:gap-12 opacity-10 grayscale pointer-events-none scale-90 origin-top">
           {[1, 2].map(id => (
             <div key={id} className="flex flex-col items-center p-2 rounded-2xl bg-black/40 border border-white/5">
                <div className="w-10 h-10 bg-slate-800 rounded-xl flex items-center justify-center border border-slate-700">
                  <Bot size={18} className="text-slate-500" />
                </div>
                <div className="flex -space-x-4 mt-2">
                   {[1, 2, 3].map(i => <Card key={i} small className="scale-75" />)}
                </div>
             </div>
           ))}
        </div>

        {/* Tactical Table Area */}
        <div className="flex-1 flex items-center justify-center gap-8 md:gap-24 relative">
            {/* Deck with Ghost Hint */}
            <div className="flex flex-col items-center gap-3 relative">
               <Card 
                 disabled={step !== 3 && step !== 6} 
                 onClick={handleDrawAction}
                 className={`transition-all duration-500 ${(step === 3 || step === 6) ? 'ring-4 ring-yellow-400 scale-105 shadow-[0_0_30px_rgba(234,179,8,0.4)] z-20' : 'opacity-40'}`} 
               />
               {(step === 3 || step === 6) && (
                 <div className="absolute -top-12 animate-bounce z-30">
                    <div className="bg-yellow-500 text-black p-1.5 rounded-full shadow-2xl">
                       <ArrowRight size={20} className="rotate-90" />
                    </div>
                 </div>
               )}
               <span className="text-[10px] uppercase tracking-[0.3em] font-black text-slate-600">Stockpile</span>
            </div>

            <div className="flex gap-6 items-center">
              <div className="flex flex-col items-center gap-3 relative">
                 {openPile.length > 0 ? (
                   <Card card={openPile[openPile.length - 1]} isJoker={openPile[openPile.length - 1].rank === Rank.Ace} disabled={true} className="opacity-40" />
                 ) : (
                   <div className="w-20 h-28 md:w-24 md:h-36 border-2 border-dashed border-white/5 rounded-2xl flex items-center justify-center">
                     <span className="text-white/5 text-[10px] uppercase tracking-widest font-black">Refuse</span>
                   </div>
                 )}
                 <span className="text-[10px] uppercase tracking-[0.3em] font-black text-slate-600">Open Pile</span>
              </div>

              {/* Action Animation Layer */}
              <div className="relative min-w-[60px] h-28 md:h-36 flex items-center justify-center">
                 {pendingDiscard && (
                    <div className="flex flex-col items-center gap-2 animate-in slide-in-from-left-4 fade-in">
                        <Card card={pendingDiscard} disabled={true} className="opacity-70 scale-90 ring-2 ring-yellow-500/50" />
                        <span className="text-[8px] uppercase tracking-widest font-black text-yellow-500/60">Purging...</span>
                    </div>
                 )}
                 {pendingToss.length > 0 && (
                    <div className="flex flex-col items-center gap-2 animate-in slide-in-from-left-4 fade-in">
                        <div className="flex -space-x-8 scale-90">
                           {pendingToss.map(c => <Card key={c.id} card={c} disabled={true} className="opacity-70 ring-2 ring-blue-500/50" />)}
                        </div>
                        <span className="text-[8px] uppercase tracking-widest font-black text-blue-500/60">Tossing...</span>
                    </div>
                 )}
              </div>
            </div>

            {/* Victory Protocol Success */}
            {step === 9 && (
               <div className="absolute inset-0 z-[110] flex items-center justify-center bg-black/95 backdrop-blur-3xl animate-in fade-in duration-1000">
                 <div className="bg-[#0a0a0a] border border-yellow-500/20 p-12 rounded-[3rem] shadow-[0_0_100px_rgba(234,179,8,0.1)] max-w-sm w-full text-center m-4 scale-in-center overflow-hidden relative">
                    <div className="absolute inset-0 opacity-[0.02] bg-[url('https://www.transparenttextures.com/patterns/carbon-fibre.png')]" />
                    <div className="w-20 h-20 bg-yellow-500 rounded-[2rem] flex items-center justify-center mx-auto mb-8 rotate-12 shadow-[0_0_50px_rgba(234,179,8,0.3)]">
                       <Trophy className="text-black" size={40} />
                    </div>
                    <h2 className="text-4xl font-serif font-black text-white mb-2 leading-none">Simulation Verified</h2>
                    <p className="text-gray-500 mb-12 text-[10px] uppercase tracking-[0.4em] font-black">Rank: Junior Strategist</p>

                    <button 
                      onClick={onExit} 
                      className="w-full bg-yellow-500 hover:bg-yellow-400 text-black font-black py-5 rounded-2xl flex items-center justify-center gap-3 transition-transform hover:scale-[1.05] active:scale-95 shadow-[0_20px_40px_rgba(234,179,8,0.3)]"
                    >
                       ENTER ARENA <ChevronRight size={24} />
                    </button>
                 </div>
               </div>
            )}
        </div>

        {/* Minimal Action Console */}
        <div className="flex flex-col items-center gap-6 pb-12 shrink-0 relative">

           <div className={`flex items-center gap-3 bg-black/60 backdrop-blur-2xl p-2.5 rounded-full border border-white/5 shadow-2xl transition-all duration-500 ${step === 2 || step === 5 || step === 8 ? 'opacity-100 translate-y-0 scale-100' : 'opacity-0 translate-y-8 scale-90 pointer-events-none'}`}>
              <button 
                onClick={handleShowAction} 
                className={`px-6 py-2.5 rounded-full font-black flex items-center gap-2 text-[10px] transition-all ${step === 8 ? 'bg-red-600 text-white shadow-lg ring-4 ring-yellow-400 animate-pulse' : 'bg-slate-800 text-slate-500 opacity-20'}`}
              >
                <AlertCircle size={14} /> SHOW
              </button>
              <div className="w-px h-6 bg-white/10" />
              <button 
                onClick={handleTossAction} 
                className={`px-6 py-2.5 rounded-full font-black flex items-center gap-2 text-[10px] transition-all ${step === 5 ? 'bg-blue-600 text-white shadow-lg ring-4 ring-yellow-400 animate-pulse' : 'bg-slate-800 text-slate-500 opacity-20'}`}
              >
                <RefreshCw size={14} /> TOSS (2)
              </button>
              <button 
                onClick={handleDiscardAction} 
                className={`px-6 py-2.5 rounded-full font-black flex items-center gap-2 text-[10px] transition-all ${step === 2 ? 'bg-green-600 text-white shadow-lg ring-4 ring-yellow-400 animate-pulse' : 'bg-slate-800 text-slate-500 opacity-20'}`}
              >
                <Hand size={14} /> DISCARD (1)
              </button>
           </div>

           {/* Interactive Hand Area */}
           <div className="flex items-end justify-center -space-x-8 md:-space-x-10 h-[140px] md:h-[180px] transition-all duration-700">
              {hand.map((card) => {
                const isSelected = selectedIds.includes(card.id);
                const isTarget = (step === 1 && card.id === KING_ID) || 
                               (step === 4 && (card.id === SEVEN_A_ID || card.id === SEVEN_B_ID));

                return (
                  <div key={card.id} className="relative transition-all duration-300">
                    <Card 
                      card={card} 
                      isJoker={card.rank === Rank.Ace}
                      selected={isSelected}
                      onClick={() => handleCardClick(card)}
                      className={`transition-all origin-bottom ${isTarget && !isSelected ? 'ring-4 ring-yellow-400 scale-110 z-30' : (isSelected ? 'z-20' : 'opacity-60 scale-95 grayscale-[0.5]')}`}
                    />
                    {isTarget && !isSelected && (
                       <div className="absolute -top-10 left-1/2 -translate-x-1/2 animate-bounce z-40">
                          <MousePointer2 className="text-yellow-500 fill-yellow-500 drop-shadow-md" size={24} />
                       </div>
                    )}
                  </div>
                );
              })}
           </div>

           {/* Tactical Telemetry */}
           <div className="flex flex-col items-center gap-1.5 mt-2">
              <div className="flex items-center gap-3 px-4 py-1.5 rounded-full bg-white/[0.02] border border-white/5">
                <span className="text-green-500/60 font-black uppercase tracking-[0.3em] text-[8px]">Simulation Mode</span>
                <div className="w-1 h-1 bg-white/10 rounded-full" />
                <span className="text-gray-500 font-bold text-[8px] uppercase tracking-widest">Energy Target: 5</span>
              </div>
              <div className="text-white/40 font-black text-xl flex items-baseline gap-2 tabular-nums">
                <span className="text-[9px] text-white/20 font-black uppercase tracking-widest">Calculated Energy:</span>
                <span className="text-white font-mono">{calculateHandValue(hand, roundJoker)}</span>
              </div>
           </div>
        </div>
      </div>

      <style>{`
        @keyframes scale-in-center {
          0% { transform: scale(0); opacity: 0; }
          100% { transform: scale(1); opacity: 1; }
        }
        .scale-in-center { animation: scale-in-center 0.6s cubic-bezier(0.175, 0.885, 0.32, 1.275) both; }
      `}</style>
    </div>
  );
};

