export default TutorialSensei;

import React, { useState, useEffect } from 'react';
import { CardData, Suit, Rank, GamePhase } from '../types';
import Card from '../components/Card';
import TutorialSensei from '../components/TutorialSensei';
import { calculateHandValue } from '../services/gameLogic';
import { RefreshCw, Hand, AlertCircle, Bot, Trophy, ChevronRight, MousePointer2 } from 'lucide-react';

const KING_ID = 'tut-king';
const SEVEN_A_ID = 'tut-seven-a';
const SEVEN_B_ID = 'tut-seven-b';
const FIVE_ID = 'tut-five';
const ACE_ID = 'tut-ace-joker';

const TutorialEngine: React.FC<{ onExit: () => void }> = ({ onExit }) => {
  const [phase, setPhase] = useState<GamePhase>(GamePhase.PLAYER_TURN_START);
  const [currentPlayer, setCurrentPlayer] = useState(0); // 0 = Human, 1-3 = Bots
  const [hand, setHand] = useState<CardData[]>([
    { id: KING_ID, suit: Suit.Hearts, rank: Rank.King, value: 10 },
    { id: SEVEN_A_ID, suit: Suit.Clubs, rank: Rank.Seven, value: 7 },
    { id: FIVE_ID, suit: Suit.Diamonds, rank: Rank.Five, value: 5 }
  ]);
  const [deck] = useState<CardData[]>([
    { id: SEVEN_B_ID, suit: Suit.Spades, rank: Rank.Seven, value: 7 },
    { id: ACE_ID, suit: Suit.Hearts, rank: Rank.Ace, value: 1 },
    { id: 'fill-1', suit: Suit.Diamonds, rank: Rank.Two, value: 2 }
  ]);
  const [openPile, setOpenPile] = useState<CardData[]>([]);
  const [selectedIds, setSelectedIds] = useState<string[]>([]);
  const [pendingDiscard, setPendingDiscard] = useState<CardData | null>(null);
  const [pendingToss, setPendingToss] = useState<CardData[]>([]);
  const [step, setStep] = useState(0);
  const [isSuccess, setIsSuccess] = useState(false);

  const roundJoker = { rank: Rank.Ace } as any;

  // Real-time Guidance Feed
  const getMessage = () => {
    if (step === 0) return "MISSION: Minimize Energy. Aces are JOKERS (0 pts). Aim for 5 Energy or less.";
    if (currentPlayer !== 0) return `OPPONENT TURN: ${['Mohan', 'Kabilesh', 'Perarasan'][currentPlayer - 1]} is maneuvering...`;
    if (step === 1) return "The King is 10 Energy. High threat. Select it to purge from your hand.";
    if (step === 2) return "Execute DISCARD. Get rid of that heavy energy unit.";
    if (step === 3) return "Draw from the STOCKPILE to complete your operational cycle.";
    if (step === 4) return "TWIN TOSS DETECTED: Select both Sevens to dump a pair simultaneously.";
    if (step === 5) return "Execute TOSS. This maneuver drops your hand count permanently.";
    if (step === 6) return "RECOVER: Draw one final unit. The deck is weighted for a JOKER.";
    if (step === 7) return "STABILIZED: You hold a Joker. Hand energy is 5. Call SHOW to win.";
    return "ANALYZING...";
  };

  // Bot Turn Simulation (Guided but feels real)
  useEffect(() => {
    if (currentPlayer !== 0 && !isSuccess) {
      const timer = setTimeout(() => {
        setCurrentPlayer(curr => (curr + 1) % 4);
      }, 1200);
      return () => clearTimeout(timer);
    }
  }, [currentPlayer, isSuccess]);

  const handleCardClick = (card: CardData) => {
    if (currentPlayer !== 0) return;
    if (step === 0) setStep(1);

    if (step === 1 && card.id === KING_ID) {
      setSelectedIds([card.id]);
      setStep(2);
    } else if (step === 4 && (card.id === SEVEN_A_ID || card.id === SEVEN_B_ID)) {
      setSelectedIds(prev => {
        const next = prev.includes(card.id) ? prev.filter(id => id !== card.id) : [...prev, card.id];
        if (next.length === 2) setStep(5);
        return next;
      });
    }
  };

  const handleDiscardAction = () => {
    if (step === 2 && selectedIds.length === 1) {
      const king = hand.find(c => c.id === KING_ID)!;
      setHand(prev => prev.filter(c => c.id !== KING_ID));
      setPendingDiscard(king);
      setSelectedIds([]);
      setPhase(GamePhase.PLAYER_DRAW);
      setStep(3);
    }
  };

  const handleTossAction = () => {
    if (step === 5 && selectedIds.length === 2) {
      const tossed = hand.filter(c => selectedIds.includes(c.id));
      setHand(prev => prev.filter(c => !selectedIds.includes(c.id)));
      setPendingToss(tossed);
      setSelectedIds([]);
      setPhase(GamePhase.PLAYER_TOSSING_DRAW);
      setStep(6);
    }
  };

  const handleDrawAction = () => {
    if ((step === 3 || step === 6) && deck.length > 0) {
      const drawn = deck[0];
      deck.shift();
      const newHand = [...hand, drawn];
      if (pendingDiscard) setOpenPile(prev => [...prev, pendingDiscard]);
      if (pendingToss.length) setOpenPile(prev => [...prev, ...pendingToss]);
      setHand(newHand);
      setPendingDiscard(null);
      setPendingToss([]);
      setPhase(GamePhase.PLAYER_TURN_START);

      if (step === 3) {
        setCurrentPlayer(1); // Simulate other players
        setTimeout(() => setStep(4), 4500); 
      } else {
        setStep(7);
      }
    }
  };

  const handleShowAction = () => {
    if (step === 7) setIsSuccess(true);
  };

  return (
    <div className="h-[100dvh] flex flex-col overflow-hidden bg-[#0d140d] relative font-sans">

      <TutorialSensei 
        message={getMessage()} 
        onExit={onExit} 
        isNarrative={step === 0} 
        onNext={() => setStep(1)} 
      />

      <div className="flex-1 relative flex flex-col justify-between p-4 max-w-7xl mx-auto w-full overflow-hidden">

        {/* Compact Opponents Row */}
        <div className="flex justify-center gap-4 opacity-40 scale-[0.85] origin-top pointer-events-none">
           {['Mohan', 'Kabilesh', 'Perarasan'].map((name, i) => (
             <div key={name} className={`flex flex-col items-center p-2 rounded-xl border transition-colors ${currentPlayer === i + 1 ? 'border-yellow-500 bg-yellow-500/10' : 'border-white/5 bg-black/20'}`}>
                <div className="w-8 h-8 bg-slate-800 rounded-lg flex items-center justify-center border border-slate-700">
                  <Bot size={14} className="text-slate-400" />
                </div>
                <span className="text-[9px] font-black text-white mt-1 uppercase tracking-tighter">{name}</span>
                <div className="flex -space-x-3 mt-1">
                   {[1, 2, 3].map(j => <Card key={j} small className="scale-75" />)}
                </div>
             </div>
           ))}
        </div>

        {/* Table Area (Clean & Minimal) */}
        <div className="flex-1 flex items-center justify-center gap-6 md:gap-20 my-2 relative">
            <div className="flex flex-col items-center gap-2">
               <Card 
                 disabled={phase === GamePhase.PLAYER_TURN_START} 
                 onClick={handleDrawAction}
                 className={phase !== GamePhase.PLAYER_TURN_START && currentPlayer === 0 ? 'ring-2 ring-yellow-400 shadow-[0_0_20px_rgba(234,179,8,0.4)] scale-105 transition-transform' : 'opacity-30'} 
               />
               <span className="text-[9px] uppercase tracking-[0.2em] font-black text-slate-600">Stockpile</span>
            </div>

            <div className="flex gap-4 items-center">
              <div className="flex flex-col items-center gap-2">
                 {openPile.length > 0 ? (
                   <Card card={openPile[openPile.length - 1]} small disabled className="opacity-20" />
                 ) : (
                   <div className="w-16 h-24 md:w-20 md:h-28 border border-dashed border-white/5 rounded-xl flex items-center justify-center">
                     <span className="text-white/5 text-[8px] uppercase tracking-widest font-black">Refuse</span>
                   </div>
                 )}
                 <span className="text-[9px] uppercase tracking-[0.2em] font-black text-slate-600">Open Pile</span>
              </div>

              {/* Action Preview */}
              <div className="relative min-w-[50px] flex items-center justify-center">
                 {pendingDiscard && (
                    <div className="animate-in slide-in-from-left-4 fade-in">
                        <Card card={pendingDiscard} disabled className="opacity-70 scale-75" />
                    </div>
                 )}
                 {pendingToss.length > 0 && (
                    <div className="flex -space-x-6 animate-in slide-in-from-left-4 fade-in">
                        {pendingToss.map(c => <Card key={c.id} card={c} disabled className="opacity-70 scale-75" />)}
                    </div>
                 )}
              </div>
            </div>

            {/* Shrunken Success Card */}
            {isSuccess && (
               <div className="absolute inset-0 z-[110] flex items-center justify-center bg-black/80 backdrop-blur-md animate-in fade-in">
                 <div className="bg-[#121212] border border-yellow-500/20 p-6 rounded-[2rem] shadow-2xl max-w-[280px] w-full text-center m-4 scale-in-center">
                    <div className="w-14 h-14 bg-yellow-500 rounded-2xl flex items-center justify-center mx-auto mb-5 rotate-12 shadow-lg shadow-yellow-500/20">
                       <Trophy className="text-black" size={28} />
                    </div>
                    <h2 className="text-xl font-serif font-black text-white mb-1">Academy Clear</h2>
                    <p className="text-gray-500 mb-6 text-[8px] uppercase tracking-[0.3em] font-black">Simulation: Verified</p>
                    <button 
                      onClick={onExit} 
                      className="w-full bg-yellow-500 hover:bg-yellow-400 text-black font-black py-4 rounded-xl flex items-center justify-center gap-2 text-[11px] transition-all active:scale-95 shadow-lg shadow-yellow-900/20"
                    >
                       ENTER ARENA <ChevronRight size={16} />
                    </button>
                 </div>
               </div>
            )}
        </div>

        {/* Action Controls & Hand (MINIMAL BOTTOM) */}
        <div className="flex flex-col items-center gap-4 pb-12 shrink-0 relative">

           {/* UI PARITY ACTION BAR: Exact replica of App.tsx Arena */}
           <div className={`flex items-center gap-1.5 bg-black/50 backdrop-blur-2xl p-1.5 rounded-full border border-white/5 shadow-2xl transition-all duration-500 ${currentPlayer === 0 && phase === GamePhase.PLAYER_TURN_START ? 'opacity-100 translate-y-0' : 'opacity-10 translate-y-4 pointer-events-none'}`}>
              <button 
                onClick={handleShowAction} 
                className={`px-4 py-2 rounded-full font-black flex items-center gap-1.5 text-[9px] md:text-[10px] transition-all ${step === 7 ? 'bg-red-600 text-white shadow-lg ring-2 ring-yellow-400 animate-pulse' : 'bg-slate-800 text-slate-500'}`}
              >
                <AlertCircle size={14} /> SHOW
              </button>

              <div className="w-px h-5 bg-white/10 mx-0.5"></div>

              <button 
                onClick={handleTossAction} 
                className={`px-4 py-2 rounded-full font-black flex items-center gap-1.5 text-[9px] md:text-[10px] transition-all ${step === 5 ? 'bg-blue-600 text-white shadow-lg ring-2 ring-yellow-400 animate-pulse' : 'bg-slate-800 text-slate-500'}`}
              >
                <RefreshCw size={14} /> TOSS (2)
              </button>

              <button 
                onClick={handleDiscardAction} 
                className={`px-4 py-2 rounded-full font-black flex items-center gap-1.5 text-[9px] md:text-[10px] transition-all ${step === 2 ? 'bg-green-600 text-white shadow-lg ring-2 ring-yellow-400 animate-pulse' : 'bg-slate-800 text-slate-500'}`}
              >
                <Hand size={14} /> DISCARD (1)
              </button>
           </div>

           {/* Guided Hand Area */}
           <div className="flex items-end justify-center -space-x-8 md:-space-x-10 h-[120px] md:h-[140px]">
              {hand.map((card) => {
                const isSelected = selectedIds.includes(card.id);
                const isTarget = (step === 1 && card.id === KING_ID) || 
                               (step === 4 && (card.id === SEVEN_A_ID || card.id === SEVEN_B_ID));

                return (
                  <div key={card.id} className="relative transition-all duration-300">
                    <Card 
                      card={card} 
                      isJoker={card.rank === Rank.Ace}
                      selected={isSelected}
                      onClick={() => handleCardClick(card)}
                      className={`transition-all origin-bottom ${currentPlayer === 0 ? '' : 'grayscale-[0.5] opacity-50'} ${isTarget && !isSelected ? 'ring-2 ring-yellow-400 scale-105 z-30 shadow-[0_0_20px_rgba(234,179,8,0.3)]' : ''}`}
                    />
                    {isTarget && !isSelected && (
                       <div className="absolute -top-10 left-1/2 -translate-x-1/2 animate-bounce z-40">
                          <MousePointer2 className="text-yellow-500 drop-shadow-md" size={18} />
                       </div>
                    )}
                  </div>
                );
              })}
           </div>

           {/* Subdued Telemetry */}
           <div className="flex flex-col items-center gap-1">
              <div className="flex items-center gap-2 px-3 py-1 rounded-full bg-white/[0.02] border border-white/5">
                <span className="text-green-500/40 font-black uppercase tracking-[0.2em] text-[7px]">Sim Active</span>
                <span className="text-gray-700 font-bold text-[7px] uppercase tracking-widest">Energy Goal: 5</span>
              </div>
              <div className="text-white/20 font-black flex items-baseline gap-1.5 tabular-nums">
                <span className="text-[8px] uppercase tracking-widest">Calculated:</span>
                <span className="text-white/50 text-sm font-mono">{calculateHandValue(hand, roundJoker)}</span>
