    if (step === 1) return "The King is 10 Energy. High threat. Select it to purge from your hand.";
    if (step === 2) return "Execute DISCARD. Get rid of that heavy unit to stabilize your score.";
    if (step === 3) return "Now DRAW. You can take from the DECK or the OPEN PILE (if available).";
    if (step === 4) return "TWIN TOSS DETECTED: You have two Sevens. Select both to dump them at once.";
    if (step === 5) return "Execute TOSS. This V3 maneuver drops your hand count permanently.";
    if (step === 6) return "FINAL DRAW: Refill your hand. The system has rigged this draw for an ACE (Joker).";
    if (step === 7) return "STABILIZED: You hold a Joker. Hand Energy is 5. Call SHOW to win.";
