  };

  // Bot Turn Simulation (Fast & Visual)
  useEffect(() => {
    if (currentPlayerIndex !== 0 && !isSuccess) {
      const timer = setTimeout(() => {
        const next = (currentPlayerIndex + 1) % 4;
        setCurrentPlayerIndex(next);
        if (next === 0 && step === 3) setStep(4); // Advance tutorial when turn returns
      }, 1000);
      return () => clearTimeout(timer);
    }
  }, [currentPlayerIndex, isSuccess, step]);

  const handleCardClick = (card: CardData) => {
    if (currentPlayerIndex !== 0 || phase !== GamePhase.PLAYER_TURN_START) return;
