    setSelectedCardIds(prev => {
      const isSelected = prev.includes(card.id);
      let next;
      if (isSelected) next = prev.filter(id => id !== card.id);
      else next = prev.length >= 2 ? [prev[1], card.id] : [...prev, card.id];

      // Tutorial Step Progression
      if (step === 1 && next.includes(KING_ID)) setStep(2);
      if (step === 4 && next.length === 2 && hand.filter(c => next.includes(c.id)).every(c => c.rank === Rank.Seven)) setStep(5);

      return next;
    });
  };

  const handleDiscardAction = () => {
    if (step === 2 && selectedCardIds.length === 1 && selectedCardIds[0] === KING_ID) {
      const card = hand.find(c => c.id === KING_ID)!;
      setHand(prev => prev.filter(c => c.id !== KING_ID));
      setPendingDiscard(card);
      setSelectedCardIds([]);
      setPhase(GamePhase.PLAYER_DRAW);
      setStep(3);
    }
  };

  const handleTossAction = () => {
    if (step === 5 && selectedCardIds.length === 2) {
      const tossed = hand.filter(c => selectedCardIds.includes(c.id));
      setHand(prev => prev.filter(c => !selectedCardIds.includes(c.id)));
      setPendingToss(tossed);
      setSelectedCardIds([]);
      setPhase(GamePhase.PLAYER_TOSSING_DRAW);
      setStep(6);
    }
  };

  const handleDrawAction = (source: 'DECK' | 'OPEN') => {
    if (currentPlayerIndex !== 0 || (phase !== GamePhase.PLAYER_DRAW && phase !== GamePhase.PLAYER_TOSSING_DRAW)) return;

    let drawn: CardData;
    const newDeck = [...deck];
    if (source === 'OPEN') {
      if (openPile.length === 0) return;
      drawn = openPile[openPile.length - 1];
      setOpenPile(prev => prev.slice(0, -1));
    } else {
      drawn = newDeck.shift()!;
      setDeck(newDeck);
    }

    const newHand = [...hand, drawn];
    setHand(newHand);

    // Cleanup pending
    if (pendingDiscard) setOpenPile(prev => [...prev, pendingDiscard]);
    if (pendingToss.length) setOpenPile(prev => [...prev, ...pendingToss]);
    setPendingDiscard(null);
    setPendingToss([]);
    setPhase(GamePhase.PLAYER_TURN_START);

    if (step === 3) {
      setCurrentPlayerIndex(1); // Bots take turns
    } else if (step === 6) {
      setStep(7);
    }
  };

  const handleShowAction = () => {
    if (step === 7) setIsSuccess(true);
  };

