           <div className="flex items-center gap-2">
             <div className="w-2.5 h-2.5 rounded-full bg-green-500 animate-pulse" />
             <span className="text-xs font-black text-white uppercase tracking-tighter">Candidate</span>
           </div>
        </div>
      </div>

      {/* Arena Table */}
      <div className="flex-1 relative flex flex-col justify-between p-2 md:p-4 max-w-7xl mx-auto w-full overflow-hidden">

        {/* Opponent Row */}
        <div className="flex justify-center gap-3 md:gap-8 mb-2">
           {['Mohan', 'Kabilesh', 'Perarasan'].map((name, i) => (
             <div key={name} className={`flex flex-col items-center p-2 rounded-xl transition-all ${currentPlayerIndex === i + 1 ? 'bg-yellow-500/10 scale-105 border border-yellow-500/30' : 'bg-black/20 opacity-40 grayscale-[0.5]'}`}>
                <div className="w-10 h-10 md:w-12 md:h-12 bg-slate-700 rounded-lg flex items-center justify-center border-2 border-slate-500">
                   <Bot size={20} className="text-slate-300" />
                </div>
                <span className="text-[10px] font-black mt-1 uppercase text-white truncate max-w-[60px]">{name}</span>
                <div className="flex -space-x-4 mt-1 scale-75">
                   {[1, 2, 3].map(j => <Card key={j} small />)}
