        {/* Central Tactical Area */}
        <div className="flex-1 flex items-center justify-center gap-4 md:gap-16 my-2 relative">
            <div className="flex flex-col items-center gap-2">
               <Card 
                  disabled={currentPlayerIndex !== 0 || (phase !== GamePhase.PLAYER_DRAW && phase !== GamePhase.PLAYER_TOSSING_DRAW)} 
                  onClick={() => handleDrawAction('DECK')} 
                  className={(phase !== GamePhase.PLAYER_TURN_START && currentPlayerIndex === 0) ? 'ring-2 ring-yellow-400 shadow-[0_0_20px_rgba(234,179,8,0.4)] scale-105' : 'opacity-40'}
               />
               <span className="text-[10px] uppercase tracking-widest font-black text-slate-500">Stockpile</span>
            </div>

            <div className="flex gap-4 items-center">
              <div className="flex flex-col items-center gap-2 relative">
                 {openPile.length > 0 ? (
                   <Card 
                     card={openPile[openPile.length - 1]} 
                     isJoker={openPile[openPile.length - 1].rank === Rank.Ace} 
                     onClick={() => handleDrawAction('OPEN')}
                     disabled={currentPlayerIndex !== 0 || (phase !== GamePhase.PLAYER_DRAW && phase !== GamePhase.PLAYER_TOSSING_DRAW)}
                   />
                 ) : (
                   <div className="w-20 h-28 md:w-24 md:h-36 border-2 border-dashed border-white/10 rounded-xl flex items-center justify-center">
                      <span className="text-white/10 text-[10px] uppercase font-black tracking-widest">Empty</span>
                   </div>
                 )}
                 <span className="text-[10px] uppercase tracking-widest font-black text-slate-500">Open Pile</span>
              </div>

              {/* Action Preview */}
              <div className="relative min-w-[60px] flex items-center justify-center">
                 {pendingDiscard && (
                    <div className="animate-in slide-in-from-left-4 fade-in">
                        <Card card={pendingDiscard} disabled className="opacity-70 scale-90 ring-2 ring-yellow-500/40" />
                    </div>
                 )}
                 {pendingToss.length > 0 && (
                    <div className="flex -space-x-8 animate-in slide-in-from-left-4 fade-in">
                        {pendingToss.map(c => <Card key={c.id} card={c} disabled className="opacity-70 scale-90 ring-2 ring-blue-500/40" />)}
                    </div>
                 )}
