        {/* BOTTOM HUD: Player Status & Actions (Exact App.tsx Parity) */}
        <div className="flex flex-col items-center gap-4 pb-12 shrink-0">

           {/* UI PARITY ACTION BAR */}
           <div className={`flex items-center gap-2 bg-black/40 backdrop-blur-md p-2 rounded-full border border-white/10 shadow-xl transition-all duration-500 ${currentPlayerIndex === 0 && phase === GamePhase.PLAYER_TURN_START ? 'opacity-100 translate-y-0' : 'opacity-20 translate-y-4'}`}>
              <button 
                onClick={handleShowAction} 
                className={`px-4 py-2 rounded-full font-black flex items-center gap-2 text-[10px] md:text-xs transition-all ${step === 7 ? 'bg-red-600 text-white shadow-lg ring-2 ring-yellow-400 animate-pulse' : 'bg-slate-700 text-slate-500'}`}
              >
                <AlertCircle size={14} /> SHOW
              </button>

              <div className="w-px h-5 bg-white/20 mx-1"></div>

              <button 
                onClick={handleTossAction} 
                className={`px-4 py-2 rounded-full font-black flex items-center gap-2 text-[10px] md:text-xs transition-all ${step === 5 ? 'bg-blue-600 text-white shadow-lg ring-2 ring-yellow-400 animate-pulse' : 'bg-slate-700 text-slate-500'}`}
              >
                <RefreshCw size={14} /> TOSS (2)
              </button>

              <button 
                onClick={handleDiscardAction} 
                className={`px-4 py-2 rounded-full font-black flex items-center gap-2 text-[10px] md:text-xs transition-all ${step === 2 ? 'bg-green-600 text-white shadow-lg ring-2 ring-yellow-400 animate-pulse' : 'bg-slate-700 text-slate-500'}`}
              >
                <Hand size={14} /> DISCARD (1)
              </button>
           </div>

           {/* Guided Hand Area */}
           <div className="flex items-end justify-center -space-x-8 md:-space-x-10 h-[120px] md:h-[150px]">
              {hand.map((card) => {
                const isSelected = selectedCardIds.includes(card.id);
                const isTarget = (step === 1 && card.id === KING_ID) || 
                               (step === 4 && (card.id === SEVEN_A_ID || card.id === SEVEN_B_ID));

                return (
                  <div key={card.id} className="relative transition-all duration-300">
                    <Card 
                      card={card} 
                      isJoker={card.rank === Rank.Ace}
                      selected={isSelected}
                      onClick={() => handleCardClick(card)}
                      className={`transition-all origin-bottom ${currentPlayerIndex === 0 ? '' : 'grayscale-[0.5] opacity-50'} ${isTarget && !isSelected ? 'ring-2 ring-yellow-400 scale-105 z-30 shadow-[0_0_20px_rgba(234,179,8,0.4)]' : ''}`}
                    />
                    {isTarget && !isSelected && (
                       <div className="absolute -top-10 left-1/2 -translate-x-1/2 animate-bounce z-40">
                          <MousePointer2 className="text-yellow-500 drop-shadow-md" size={24} />
                       </div>
                    )}
                  </div>
                );
              })}
           </div>

           {/* Telemetry Footer */}
           <div className="flex flex-col items-center gap-1">
              <div className="flex items-center gap-2 px-3 py-1 rounded-full bg-white/[0.03] border border-white/5">
                <span className="text-green-500/60 font-black uppercase tracking-[0.2em] text-[8px]">Simulation: Online</span>
                <span className="text-gray-600 font-bold text-[8px] uppercase tracking-widest">Energy Target: 5</span>
              </div>
              <div className="text-white/40 font-black flex items-baseline gap-1.5 tabular-nums">
                <span className="text-[10px] uppercase tracking-widest text-white/20">Energy:</span>
                <span className="text-white text-xl font-mono">{calculateHandValue(hand, roundJoker)}</span>
              </div>
           </div>
        </div>
      </div>

      <style>{`
        @keyframes scale-in-center {
          0% { transform: scale(0.9); opacity: 0; }
          100% { transform: scale(1); opacity: 1; }
        }
        .scale-in-center { animation: scale-in-center 0.4s cubic-bezier(0.175, 0.885, 0.32, 1.275) both; }
      `}</style>
    </div>
  );
};

