             <div key={name} className={`flex flex-col items-center p-2 rounded-xl transition-all ${currentPlayerIndex === i + 1 ? 'bg-yellow-500/10 scale-105 border border-yellow-500/30' : 'bg-black/20 opacity-40 grayscale-[0.5]'}`}>
                <div className="w-10 h-10 md:w-12 md:h-12 bg-slate-700 rounded-lg flex items-center justify-center border-2 border-slate-500 shadow-xl overflow-hidden">
                   {/* Opponent Card Backs */}
                   <div className="absolute inset-0 bg-blue-950 opacity-20 flex items-center justify-center font-black text-[8px] text-yellow-500">TS</div>
                   <Bot size={20} className="text-slate-300 relative z-10" />
                </div>
                <span className="text-[10px] font-black mt-1 uppercase text-white truncate max-w-[60px]">{name}</span>
                <div className="flex -space-x-4 mt-1 scale-75">
