                 {pendingToss.length > 0 && (
                    <div className="flex -space-x-8 animate-in slide-in-from-left-4 fade-in">
                        {pendingToss.map(c => <Card key={c.id} card={c} disabled className="opacity-70 scale-90 ring-2 ring-blue-500/40" />)}
                    </div>
                 )}
              </div>
            </div>

            {isSuccess && (
               <div className="absolute inset-0 z-[110] flex items-center justify-center bg-black/80 backdrop-blur-md animate-in fade-in">
                 <div className="bg-[#121212] border border-yellow-500/20 p-8 rounded-[2.5rem] shadow-2xl max-w-xs w-full text-center scale-in-center overflow-hidden">
                    <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-yellow-500/40 to-transparent" />
                    <div className="w-16 h-16 bg-yellow-500 rounded-2xl flex items-center justify-center mx-auto mb-6 rotate-12 shadow-lg shadow-yellow-500/20">
                       <Trophy className="text-black" size={32} />
                    </div>
                    <h2 className="text-2xl font-serif font-black text-white mb-1">Academy Clear</h2>
                    <p className="text-gray-500 mb-8 text-[9px] uppercase tracking-[0.4em] font-black">Energy Level: Stable</p>
                    <button 
                      onClick={onExit} 
                      className="w-full bg-yellow-500 hover:bg-yellow-400 text-black font-black py-5 rounded-2xl flex items-center justify-center gap-2 text-xs transition-all active:scale-95 shadow-xl shadow-yellow-900/20"
                    >
                       ENTER ARENA <ChevronRight size={20} />
                    </button>
                 </div>
               </div>
            )}
        </div>

        {/* Interaction Console */}
        <div className="flex flex-col items-center gap-4 pb-12 shrink-0">

           <div className={`flex items-center gap-1.5 bg-black/40 backdrop-blur-md p-1.5 rounded-full border border-white/10 shadow-xl transition-all duration-500 ${currentPlayerIndex === 0 && phase === GamePhase.PLAYER_TURN_START ? 'opacity-100 translate-y-0' : 'opacity-10 translate-y-4'}`}>
              <button 
                onClick={handleShowAction} 
                className={`relative px-4 py-2 rounded-full font-black flex items-center gap-1.5 text-[10px] md:text-xs transition-all ${step === 7 ? 'bg-red-600 text-white shadow-lg ring-2 ring-yellow-400 animate-pulse z-20' : 'bg-slate-800 text-slate-500'}`}
              >
                <AlertCircle size={14} /> SHOW
                {step === 7 && <TacticalPointer className="absolute -top-14 left-1/2 -translate-x-1/2" />}
              </button>

              <div className="w-px h-5 bg-white/10 mx-0.5" />

              <button 
                onClick={handleTossAction} 
                className={`relative px-4 py-2 rounded-full font-black flex items-center gap-1.5 text-[10px] md:text-xs transition-all ${step === 5 ? 'bg-blue-600 text-white shadow-lg ring-2 ring-yellow-400 animate-pulse z-20' : 'bg-slate-800 text-slate-500'}`}
              >
                <RefreshCw size={14} /> TOSS (2)
                {step === 5 && <TacticalPointer className="absolute -top-14 left-1/2 -translate-x-1/2" />}
              </button>

              <button 
                onClick={handleDiscardAction} 
                className={`relative px-4 py-2 rounded-full font-black flex items-center gap-1.5 text-[10px] md:text-xs transition-all ${step === 2 ? 'bg-green-600 text-white shadow-lg ring-2 ring-yellow-400 animate-pulse z-20' : 'bg-slate-800 text-slate-500'}`}
              >
                <Hand size={14} /> DISCARD (1)
                {step === 2 && <TacticalPointer className="absolute -top-14 left-1/2 -translate-x-1/2" />}
              </button>
           </div>

           {/* Hand Area with Blue Arrows */}
           <div className="flex items-end justify-center -space-x-8 md:-space-x-10 h-[120px] md:h-[150px]">
              {hand.map((card) => {
                const isSelected = selectedCardIds.includes(card.id);
                const isTarget = (step === 1 && card.id === KING_ID) || 
                               (step === 4 && (card.id === SEVEN_A_ID || card.id === SEVEN_B_ID));

                return (
                  <div key={card.id} className="relative transition-all duration-300">
                    <Card 
                      card={card} 
                      isJoker={card.rank === Rank.Ace}
                      selected={isSelected}
                      onClick={() => handleCardClick(card)}
                      className={`transition-all origin-bottom ${currentPlayerIndex === 0 ? '' : 'grayscale-[0.5] opacity-50'} ${isTarget && !isSelected ? 'ring-2 ring-yellow-400 scale-105 z-30' : ''}`}
                    />
                    {isTarget && !isSelected && (
                       <TacticalPointer className="absolute -top-14 left-1/2 -translate-x-1/2" />
                    )}
                  </div>
                );
              })}
           </div>

           <div className="flex flex-col items-center gap-1 mt-2">
              <div className="flex items-center gap-2 px-3 py-1 rounded-full bg-white/[0.03] border border-white/5 shadow-inner">
                <span className="text-green-500/60 font-black uppercase tracking-[0.2em] text-[8px]">Academy Mode</span>
                <span className="text-gray-700 font-bold text-[8px] uppercase tracking-widest">Target: 5</span>
              </div>
              <div className="text-white/40 font-black flex items-baseline gap-1.5 tabular-nums">
                <span className="text-[10px] uppercase tracking-widest text-white/20">Current:</span>
                <span className="text-white text-2xl font-mono tracking-tighter">{calculateHandValue(hand, roundJoker)}</span>
              </div>
           </div>
        </div>
      </div>

      <style>{`
        @keyframes scale-in-center {
          0% { transform: scale(0.95); opacity: 0; }
          100% { transform: scale(1); opacity: 1; }
        }
        .scale-in-center { animation: scale-in-center 0.3s cubic-bezier(0.175, 0.885, 0.32, 1.275) both; }
      `}</style>
    </div>
  );
};

