              <div className="text-white/40 font-black flex items-baseline gap-2 tabular-nums">
                <span className="text-[9px] uppercase tracking-widest text-white/10 font-black">Current Energy:</span>
                <span className="text-white text-2xl font-mono tracking-tighter drop-shadow-[0_0_10px_rgba(255,255,255,0.2)]">{calculateHandValue(hand, roundJoker)}</span>
