export default TutorialEngine;

import React, { useState, useEffect } from 'react';
import { CardData, Suit, Rank, GamePhase } from '../types';
import Card from '../components/Card';
import TutorialSensei from '../components/TutorialSensei';
import { calculateHandValue } from '../services/gameLogic';
import { RefreshCw, Hand, AlertCircle, Bot, Trophy, ChevronRight, LogOut, Globe, ArrowDown } from 'lucide-react';

// Scripted IDs for pre-seeded tutorial deck
const KING_ID = 'tut-king';
const SEVEN_A_ID = 'tut-seven-a';
const SEVEN_B_ID = 'tut-seven-b'; 
const FIVE_ID = 'tut-five';
const ACE_ID = 'tut-ace-joker';

const TacticalPointer = ({ className = "" }: { className?: string }) => (
  <div className={`flex flex-col items-center animate-bounce z-[100] pointer-events-none ${className}`}>
    <div className="relative">
      <ArrowDown className="text-blue-400 drop-shadow-[0_0_12px_rgba(96,165,250,0.9)]" size={32} strokeWidth={3} />
      <div className="absolute top-0 -left-3 w-6 h-0.5 bg-blue-400/60 rotate-[45deg]" />
      <div className="absolute top-0 -right-3 w-6 h-0.5 bg-blue-400/60 -rotate-[45deg]" />
      <div className="absolute -bottom-2 left-1/2 -translate-x-1/2 w-8 h-8 rounded-full border-2 border-blue-400/20 scale-[2] animate-ping" />
    </div>
  </div>
);

const TutorialEngine: React.FC<{ onExit: () => void }> = ({ onExit }) => {
  // --- Simulation State ---
  const [phase, setPhase] = useState<GamePhase>(GamePhase.PLAYER_TURN_START);
  const [currentPlayerIndex, setCurrentPlayerIndex] = useState(0); 
  const [hand, setHand] = useState<CardData[]>([
    { id: KING_ID, suit: Suit.Hearts, rank: Rank.King, value: 10 },
    { id: SEVEN_A_ID, suit: Suit.Clubs, rank: Rank.Seven, value: 7 },
    { id: FIVE_ID, suit: Suit.Diamonds, rank: Rank.Five, value: 5 }
  ]);
  const [deck, setDeck] = useState<CardData[]>([
    { id: SEVEN_B_ID, suit: Suit.Spades, rank: Rank.Seven, value: 7 }, // Draw 1
    { id: 'filler-1', suit: Suit.Hearts, rank: Rank.Two, value: 2 },
    { id: ACE_ID, suit: Suit.Hearts, rank: Rank.Ace, value: 1 },    // Draw 2 (Joker)
    { id: 'filler-2', suit: Suit.Clubs, rank: Rank.Three, value: 3 },
  ]);
  const [openPile, setOpenPile] = useState<CardData[]>([]);
  const [selectedCardIds, setSelectedCardIds] = useState<string[]>([]);
  const [pendingDiscard, setPendingDiscard] = useState<CardData | null>(null);
  const [pendingToss, setPendingToss] = useState<CardData[]>([]);

  const [step, setStep] = useState(0); // 0: Select King, 1: Discard, 2: Draw, 3: Bots, 4: Select 7s, 5: Toss, 6: Final Draw, 7: Show
  const [isSuccess, setIsSuccess] = useState(false);
  const roundJoker = { rank: Rank.Ace } as any;

  // --- Dynamic Mission Feed ---
  const getMessage = () => {
    switch (step) {
      case 0: return "MISSION START: Achieve the LOWEST Energy. Tap the King (10 pts) to begin neutralization.";
      case 1: return "The King is heavy weight. Select it to ready a purge.";
      case 2: return "Execute DISCARD. In Tri-Stack, shedding high energy units is the path to victory.";
      case 3: return "SYSTEM REFILL: Draw a new card from the Stockpile to conclude your tactical cycle.";
      case 4: return "OBSERVING... Opponents Mohan, Lakshman, and Kishore are calculating their moves.";
      case 5: return "TWIN TOSS AVAILABLE: You hold a pair of Sevens. Select BOTH to dump them at once.";
      case 6: return "Execute TOSS. This V3 maneuver permanently reduces your total hand weight.";
      case 7: return "FINAL RECOVERY: Draw from the Stockpile. The system has rigged a Joker (0 pts) for you.";
      case 8: return "TARGET OPTIMIZED: You have 5 Energy (Lowest). Call SHOW to terminate the simulation.";
      default: return "ANALYZING BATTLEFIELD...";
    }
  };

  // --- Bot Turn Simulation ---
  useEffect(() => {
    if (step === 4 && !isSuccess) {
      const runBotTurns = async () => {
        await new Promise(r => setTimeout(r, 1000));
        setCurrentPlayerIndex(1); // Mohan
        await new Promise(r => setTimeout(r, 800));
        setCurrentPlayerIndex(2); // Lakshman
        await new Promise(r => setTimeout(r, 800));
        setCurrentPlayerIndex(3); // Kishore
        await new Promise(r => setTimeout(r, 800));
        setCurrentPlayerIndex(0); // Player
        setStep(5);
      };
      runBotTurns();
    }
  }, [step, isSuccess]);

  // --- Handlers ---
  const handleCardClick = (card: CardData) => {
    if (currentPlayerIndex !== 0 || phase !== GamePhase.PLAYER_TURN_START) return;

    setSelectedCardIds(prev => {
      const isSelected = prev.includes(card.id);
      let next;
      if (isSelected) next = prev.filter(id => id !== card.id);
      else next = prev.length >= 2 ? [prev[1], card.id] : [...prev, card.id];

      // Auto-step Progression
      if (step === 0 && next.includes(KING_ID)) setStep(2);
      if (step === 5 && next.length === 2 && hand.filter(c => next.includes(c.id)).every(c => c.rank === Rank.Seven)) setStep(6);

      return next;
    });
  };

  const handleDiscardAction = () => {
    if (step === 2 && selectedCardIds.includes(KING_ID)) {
      const card = hand.find(c => c.id === KING_ID)!;
      setHand(prev => prev.filter(c => c.id !== KING_ID));
      setPendingDiscard(card);
      setSelectedCardIds([]);
      setPhase(GamePhase.PLAYER_DRAW);
      setStep(3);
    }
  };

  const handleTossAction = () => {
    if (step === 6 && selectedCardIds.length === 2) {
      const tossed = hand.filter(c => selectedCardIds.includes(c.id));
      setHand(prev => prev.filter(c => !selectedCardIds.includes(c.id)));
      setPendingToss(tossed);
      setSelectedCardIds([]);
      setPhase(GamePhase.PLAYER_TOSSING_DRAW);
      setStep(7);
    }
  };

  const handleDrawAction = () => {
    if (currentPlayerIndex !== 0 || (phase !== GamePhase.PLAYER_DRAW && phase !== GamePhase.PLAYER_TOSSING_DRAW)) return;

    const newDeck = [...deck];
    const drawn = newDeck.shift()!;
    setDeck(newDeck);
    setHand(prev => [...prev, drawn]);

    // Transfer pendings to pile
    if (pendingDiscard) setOpenPile(prev => [...prev, pendingDiscard]);
    if (pendingToss.length) setOpenPile(prev => [...prev, ...pendingToss]);
    setPendingDiscard(null);
    setPendingToss([]);
    setPhase(GamePhase.PLAYER_TURN_START);

    if (step === 3) setStep(4);
    if (step === 7) setStep(8);
  };

  const handleShowAction = () => {
    if (step === 8) setIsSuccess(true);
  };

  return (
    <div className="h-[100dvh] flex flex-col overflow-hidden bg-[#0a1a0a]">
      <TutorialSensei message={getMessage()} onExit={onExit} />

      {/* Arena Header - Mirroring App.tsx */}
      <div className="h-14 bg-[#0f1f0f] flex items-center justify-between px-4 shadow-xl z-20 shrink-0 border-b border-white/5">
        <div className="flex items-center gap-3">
          <button onClick={onExit} className="text-red-400 bg-white/5 p-2 rounded-lg"><LogOut size={18} /></button>
          <div className="bg-slate-800 px-3 py-1.5 rounded-lg text-[10px] flex items-center gap-2 border border-white/5">
             <span className="text-gray-400 uppercase tracking-widest font-black">Protocol</span>
             <span className="font-black text-yellow-500">SIMULATION</span>
          </div>
          <div className="bg-blue-900/30 px-3 py-1.5 rounded-lg text-[10px] flex items-center gap-2 border border-blue-500/30">
            <Globe size={12} className="text-blue-400" />
            <span className="font-mono font-black text-blue-200 uppercase tracking-tighter">Academy</span>
          </div>
        </div>

        <div className="flex bg-white text-black px-2 py-1 rounded border-2 border-purple-500 items-center gap-1.5 shadow-[0_0_15px_rgba(168,85,247,0.4)]">
           <span className="text-[10px] font-black uppercase opacity-50">Joker</span>
           <span className="font-bold text-sm">A</span>
        </div>

        <div className="flex items-center gap-2 bg-black/40 px-3 py-1.5 rounded-full border border-green-500/20">
           <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse" />
           <span className="text-[10px] font-black text-white uppercase tracking-widest">Candidate</span>
        </div>
      </div>

      <div className="flex-1 relative flex flex-col justify-between p-2 md:p-4 max-w-7xl mx-auto w-full">

        {/* Full Opponent Row */}
        <div className="flex justify-center gap-6 mt-2">
           {['Mohan', 'Lakshman', 'Kishore'].map((name, i) => (
             <div key={name} className={`flex flex-col items-center p-2 rounded-2xl transition-all duration-500 ${currentPlayerIndex === i + 1 ? 'bg-yellow-500/10 scale-105 border border-yellow-500/40 shadow-2xl' : 'bg-black/20 opacity-30 grayscale'}`}>
                <div className="w-12 h-12 md:w-14 md:h-14 bg-slate-800 rounded-xl flex items-center justify-center border-2 border-slate-600 shadow-xl relative overflow-hidden">
                   <div className="absolute inset-0 bg-blue-950 opacity-10 flex items-center justify-center font-black text-[10px] text-yellow-500">TS</div>
                   <Bot size={24} className="text-slate-400 relative z-10" />
                </div>
                <span className="text-[9px] font-black mt-1.5 uppercase text-white tracking-widest">{name}</span>
                <span className="text-[8px] text-yellow-500/60 font-bold uppercase">0 pts</span>
             </div>
           ))}
        </div>

        {/* Central Tactical Area */}
        <div className="flex-1 flex items-center justify-center gap-6 md:gap-24 relative">
            <div className="flex flex-col items-center gap-2 relative">
               <Card 
                  disabled={currentPlayerIndex !== 0 || (phase !== GamePhase.PLAYER_DRAW && phase !== GamePhase.PLAYER_TOSSING_DRAW)} 
                  onClick={handleDrawAction} 
                  className={(phase !== GamePhase.PLAYER_TURN_START && currentPlayerIndex === 0) ? 'ring-2 ring-yellow-400 scale-105' : 'opacity-30'}
               />
               {(step === 3 || step === 7) && <TacticalPointer className="absolute -top-16" />}
               <span className="text-[10px] uppercase tracking-[0.2em] font-black text-slate-500">Stockpile ({deck.length})</span>
            </div>

            <div className="flex gap-6 items-center">
              <div className="flex flex-col items-center gap-2">
                 {openPile.length > 0 ? (
                   <Card card={openPile[openPile.length - 1]} disabled className="opacity-40 grayscale" />
                 ) : (
                   <div className="w-20 h-28 md:w-24 md:h-36 border-2 border-dashed border-white/5 rounded-2xl flex items-center justify-center bg-black/10">
                      <span className="text-white/5 text-[10px] uppercase font-black tracking-widest">Empty</span>
                   </div>
                 )}
                 <span className="text-[10px] uppercase tracking-[0.2em] font-black text-slate-500">Open Pile</span>
              </div>

              {/* Action Preview */}
              <div className="relative min-w-[60px] flex items-center justify-center">
                 {pendingDiscard && (
                    <div className="animate-in slide-in-from-left-4 fade-in">
                        <Card card={pendingDiscard} disabled className="opacity-70 scale-90 ring-2 ring-yellow-500/40" />
                    </div>
                 )}
                 {pendingToss.length > 0 && (
                    <div className="flex -space-x-8 animate-in slide-in-from-left-4 fade-in">
                        {pendingToss.map(c => <Card key={c.id} card={c} disabled className="opacity-70 scale-90 ring-2 ring-blue-500/40" />)}
                    </div>
                 )}
              </div>
            </div>

            {/* Victory Protocol */}
            {isSuccess && (
               <div className="absolute inset-0 z-[110] flex items-center justify-center bg-black/85 backdrop-blur-xl animate-in fade-in">
                 <div className="bg-[#0f1f0f] border-2 border-yellow-500/30 p-8 rounded-[3rem] shadow-[0_0_60px_rgba(0,0,0,0.8)] max-w-xs w-full text-center scale-in-center">
                    <div className="w-16 h-16 bg-yellow-500 rounded-2xl flex items-center justify-center mx-auto mb-6 rotate-12 shadow-lg shadow-yellow-500/30">
                       <Trophy className="text-black" size={32} />
                    </div>
                    <h2 className="text-2xl font-serif font-black text-white mb-2 tracking-tight">Verified</h2>
                    <p className="text-slate-500 mb-8 text-[9px] uppercase tracking-[0.4em] font-black">Strategy: Lowest Energy Achieved</p>
                    <button 
                      onClick={onExit} 
                      className="w-full bg-yellow-500 hover:bg-yellow-400 text-black font-black py-5 rounded-2xl flex items-center justify-center gap-2 text-xs transition-all active:scale-95 shadow-xl shadow-yellow-900/40 uppercase tracking-widest"
                    >
                       Enter Arena <ChevronRight size={18} />
                    </button>
                 </div>
               </div>
            )}
        </div>

        {/* Console & Hand */}
        <div className="flex flex-col items-center gap-4 pb-14 shrink-0">

           <div className={`flex items-center gap-2 bg-black/60 backdrop-blur-3xl p-1.5 rounded-full border border-white/10 shadow-2xl transition-all duration-700 ${currentPlayerIndex === 0 && phase === GamePhase.PLAYER_TURN_START ? 'opacity-100 translate-y-0 scale-100' : 'opacity-10 translate-y-6 scale-95 pointer-events-none'}`}>
              <button 
                onClick={handleShowAction} 
                className={`relative px-5 py-2.5 rounded-full font-black flex items-center gap-2 text-[10px] transition-all ${step === 8 ? 'bg-red-600 text-white shadow-xl ring-2 ring-white/20 animate-pulse' : 'bg-slate-800 text-slate-500 opacity-50'}`}
              >
                <AlertCircle size={14} /> SHOW
                {step === 8 && <TacticalPointer className="absolute -top-16 left-1/2 -translate-x-1/2" />}
              </button>

              <div className="w-[1px] h-6 bg-white/10 mx-0.5" />

              <button 
                onClick={handleTossAction} 
                className={`relative px-5 py-2.5 rounded-full font-black flex items-center gap-2 text-[10px] transition-all ${step === 6 ? 'bg-blue-600 text-white shadow-xl ring-2 ring-white/20 animate-pulse' : 'bg-slate-800 text-slate-500 opacity-50'}`}
              >
                <RefreshCw size={14} /> TOSS (2)
                {step === 6 && <TacticalPointer className="absolute -top-16 left-1/2 -translate-x-1/2" />}
              </button>

              <button 
                onClick={handleDiscardAction} 
                className={`relative px-5 py-2.5 rounded-full font-black flex items-center gap-2 text-[10px] transition-all ${step === 2 ? 'bg-green-600 text-white shadow-xl ring-2 ring-white/20 animate-pulse' : 'bg-slate-800 text-slate-500 opacity-50'}`}
              >
                <Hand size={14} /> DISCARD (1)
                {step === 2 && <TacticalPointer className="absolute -top-16 left-1/2 -translate-x-1/2" />}
