                <span className="text-[9px] uppercase tracking-widest text-white/10 font-black">Energy Trace:</span>
                <span className="text-white text-2xl font-mono tracking-tighter">{calculateHandValue(hand, roundJoker)}</span>
              </div>
           </div>
        </div>
