                  className={(phase !== GamePhase.PLAYER_TURN_START && currentPlayerIndex === 0) ? 'ring-2 ring-yellow-400 scale-105' : 'opacity-30'}
               />
               {guidance.target === 'DECK' && <TacticalPointer className="absolute -top-16" />}
               <span className="text-[10px] uppercase tracking-[0.2em] font-black text-slate-500">Stockpile ({deck.length})</span>
            </div>

            <div className="flex gap-6 items-center">
              <div className="flex flex-col items-center gap-2 relative">
                 {openPile.length > 0 ? (
                   <Card 
                    card={openPile[openPile.length - 1]} 
                    isJoker={openPile[openPile.length - 1].rank === Rank.Ace} 
                    onClick={() => handleDrawAction('OPEN')}
                    disabled={currentPlayerIndex !== 0 || (phase !== GamePhase.PLAYER_DRAW && phase !== GamePhase.PLAYER_TOSSING_DRAW)}
                    className="shadow-xl"
                   />
                 ) : (
                   <div className="w-20 h-28 md:w-24 md:h-36 border-2 border-dashed border-white/5 rounded-2xl flex items-center justify-center bg-black/10">
                      <span className="text-white/5 text-[10px] uppercase font-black tracking-widest">Empty</span>
                   </div>
                 )}
                 <span className="text-[10px] uppercase tracking-[0.2em] font-black text-slate-500">Open Pile</span>
              </div>

              {/* Action Preview */}
              <div className="relative min-w-[60px] flex items-center justify-center">
                 {pendingDiscard && (
                    <div className="animate-in slide-in-from-left-4 fade-in">
                        <Card card={pendingDiscard} disabled className="opacity-70 scale-90 ring-2 ring-yellow-500/40 shadow-2xl" />
                    </div>
                 )}
                 {pendingToss.length > 0 && (
                    <div className="flex -space-x-8 animate-in slide-in-from-left-4 fade-in">
                        {pendingToss.map(c => <Card key={c.id} card={c} disabled className="opacity-70 scale-90 ring-2 ring-blue-500/40 shadow-2xl" />)}
                    </div>
                 )}
              </div>
            </div>

            {/* Victory Verification */}
            {isSuccess && (
               <div className="absolute inset-0 z-[110] flex items-center justify-center bg-black/85 backdrop-blur-xl animate-in fade-in duration-500">
                 <div className="bg-[#0f240f] border-2 border-yellow-500/30 p-8 rounded-[3rem] shadow-[0_0_80px_rgba(0,0,0,0.8)] max-w-xs w-full text-center scale-in-center overflow-hidden">
                    <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-yellow-500/50 to-transparent" />
                    <div className="w-16 h-16 bg-yellow-500 rounded-[1.5rem] flex items-center justify-center mx-auto mb-6 rotate-[15deg] shadow-lg shadow-yellow-500/40 ring-4 ring-black">
                       <Trophy className="text-black" size={32} />
                    </div>
                    <h2 className="text-2xl font-serif font-black text-white mb-2 tracking-tight">Verified</h2>
                    <p className="text-slate-500 mb-8 text-[9px] uppercase tracking-[0.4em] font-black">Simulation Mastered: {energy} Energy</p>
                    <button 
                      onClick={onExit} 
                      className="w-full bg-yellow-500 hover:bg-yellow-400 text-black font-black py-5 rounded-2xl flex items-center justify-center gap-2 text-xs transition-all active:scale-95 shadow-xl shadow-yellow-900/40 uppercase tracking-widest"
                    >
                       Enter Arena <ChevronRight size={18} />
                    </button>
                 </div>
               </div>
            )}
        </div>

        {/* Console & Guided Hand */}
        <div className="flex flex-col items-center gap-4 pb-14 shrink-0">

           <div className={`flex items-center gap-1.5 bg-black/60 backdrop-blur-3xl p-1.5 rounded-full border border-white/10 shadow-2xl transition-all duration-700 ${currentPlayerIndex === 0 && phase === GamePhase.PLAYER_TURN_START ? 'opacity-100 translate-y-0 scale-100' : 'opacity-10 translate-y-6 scale-95 pointer-events-none'}`}>
              <button 
                onClick={handleShowAction} 
                className={`relative px-5 py-2.5 rounded-full font-black flex items-center gap-2 text-[10px] transition-all ${guidance.target === 'SHOW_BTN' ? 'bg-red-600 text-white shadow-[0_0_25px_rgba(220,38,38,0.5)] ring-2 ring-white/30 animate-pulse' : 'bg-slate-800 text-slate-500'}`}
              >
                <AlertCircle size={14} /> SHOW
                {guidance.target === 'SHOW_BTN' && <TacticalPointer className="absolute -top-16 left-1/2 -translate-x-1/2" />}
              </button>

              <div className="w-[1px] h-6 bg-white/10 mx-0.5" />

              <button 
                onClick={handleTossAction} 
                className={`relative px-5 py-2.5 rounded-full font-black flex items-center gap-2 text-[10px] transition-all ${guidance.target === 'TOSS_BTN' ? 'bg-blue-600 text-white shadow-[0_0_25px_rgba(37,99,235,0.5)] ring-2 ring-white/30 animate-pulse' : 'bg-slate-800 text-slate-500'}`}
              >
                <RefreshCw size={14} /> TOSS (2)
                {guidance.target === 'TOSS_BTN' && <TacticalPointer className="absolute -top-16 left-1/2 -translate-x-1/2" />}
              </button>

              <button 
                onClick={handleDiscardAction} 
                className={`relative px-5 py-2.5 rounded-full font-black flex items-center gap-2 text-[10px] transition-all ${guidance.target === 'DISCARD_BTN' ? 'bg-green-600 text-white shadow-[0_0_25px_rgba(22,163,74,0.5)] ring-2 ring-white/30 animate-pulse' : 'bg-slate-800 text-slate-500'}`}
              >
                <Hand size={14} /> DISCARD (1)
                {guidance.target === 'DISCARD_BTN' && <TacticalPointer className="absolute -top-16 left-1/2 -translate-x-1/2" />}
              </button>
           </div>

           {/* Hand Area with Dynamic Blue Arrows */}
           <div className="flex items-end justify-center -space-x-8 md:-space-x-12 h-[130px] md:h-[160px]">
              {hand.map((card) => {
                const isSelected = selectedCardIds.includes(card.id);
                const isTarget = (guidance.target === 'PAIR' && guidance.ids?.includes(card.id)) || 
                               (guidance.target === 'HIGH_CARD' && guidance.id === card.id);

                return (
                  <div key={card.id} className="relative transition-all duration-500">
                    <Card 
                      card={card} 
                      isJoker={card.rank === Rank.Ace}
                      selected={isSelected}
                      onClick={() => handleCardClick(card)}
                      className={`transition-all origin-bottom duration-500 ${currentPlayerIndex === 0 ? '' : 'grayscale opacity-40'} ${isTarget && !isSelected ? 'ring-2 ring-yellow-400 scale-110 z-30 shadow-[0_0_30px_rgba(234,179,8,0.4)]' : ''}`}
                    />
                    {isTarget && !isSelected && (
                       <TacticalPointer className="absolute -top-16 left-1/2 -translate-x-1/2" />
                    )}
                  </div>
                );
              })}
           </div>

           {/* Real-time Telemetry */}
           <div className="flex flex-col items-center gap-1.5 mt-3">
              <div className="flex items-center gap-2 px-4 py-1.5 rounded-full bg-white/[0.02] border border-white/5 shadow-inner backdrop-blur-sm">
                <span className="text-green-500/50 font-black uppercase tracking-[0.25em] text-[8px]">Academy Mode</span>
                <span className="text-gray-700 font-bold text-[8px] uppercase tracking-widest">Goal: Lowest Energy</span>
              </div>
              <div className="text-white/40 font-black flex items-baseline gap-2 tabular-nums">
                <span className="text-[9px] uppercase tracking-widest text-white/10 font-black">Energy Trace:</span>
                <span className="text-white text-2xl font-mono tracking-tighter drop-shadow-[0_0_10px_rgba(255,255,255,0.2)]">{energy}</span>
              </div>
           </div>
        </div>
      </div>

      <style>{`
        @keyframes scale-in-center {
          0% { transform: scale(0.9); opacity: 0; filter: blur(5px); }
          100% { transform: scale(1); opacity: 1; filter: blur(0); }
        }
        .scale-in-center { animation: scale-in-center 0.6s cubic-bezier(0.19, 1, 0.22, 1) both; }
      `}</style>
    </div>
  );
};

export default TutorialEngine;

import React, { useState, useEffect, useMemo } from 'react';
import { CardData, Suit, Rank, GamePhase } from '../types';
import Card from '../components/Card';
import TutorialSensei from '../components/TutorialSensei';
import { calculateHandValue, createDeck, shuffleDeck, decideBotAction } from '../services/gameLogic';
import { RefreshCw, Hand, AlertCircle, Bot, Trophy, ChevronRight, LogOut, Globe, ArrowDown, Zap, ShieldCheck } from 'lucide-react';

// Tactical Pointer Component
const TacticalPointer = ({ className = "" }: { className?: string }) => (
  <div className={`flex flex-col items-center animate-bounce z-[100] pointer-events-none ${className}`}>
    <div className="relative">
      <ArrowDown className="text-blue-400 drop-shadow-[0_0_12px_rgba(96,165,250,0.9)]" size={32} strokeWidth={3} />
      <div className="absolute top-0 -left-3 w-6 h-0.5 bg-blue-400/60 rotate-[45deg]" />
      <div className="absolute top-0 -right-3 w-6 h-0.5 bg-blue-400/60 -rotate-[45deg]" />
      <div className="absolute -bottom-2 left-1/2 -translate-x-1/2 w-8 h-8 rounded-full border-2 border-blue-400/20 scale-[2] animate-ping" />
    </div>
  </div>
);

const TutorialEngine: React.FC<{ onExit: () => void }> = ({ onExit }) => {
  // --- Game State (Full Interactive Round) ---
  const [phase, setPhase] = useState<GamePhase>(GamePhase.PLAYER_TURN_START);
  const [currentPlayerIndex, setCurrentPlayerIndex] = useState(0); 
  const [hand, setHand] = useState<CardData[]>([]);
  const [deck, setDeck] = useState<CardData[]>([]);
  const [openPile, setOpenPile] = useState<CardData[]>([]);
  const [selectedCardIds, setSelectedCardIds] = useState<string[]>([]);
  const [pendingDiscard, setPendingDiscard] = useState<CardData | null>(null);
  const [pendingToss, setPendingToss] = useState<CardData[]>([]);
  const [isSuccess, setIsSuccess] = useState(false);
  const [tossedThisTurn, setTossedThisTurn] = useState(false);
  const [showCaller, setShowCaller] = useState<string | null>(null);
  const roundJoker = { rank: Rank.Ace } as any;

  // --- Initial Setup (Semi-Rigged only for first hand) ---
  useEffect(() => {
    const fullDeck = createDeck();
    // Guarantee a pair and one high card for the first hand to explain mechanics
    const startHand: CardData[] = [
      { id: 'tut-start-1', suit: Suit.Clubs, rank: Rank.Seven, value: 7 },
      { id: 'tut-start-2', suit: Suit.Spades, rank: Rank.Seven, value: 7 },
      { id: 'tut-start-3', suit: Suit.Hearts, rank: Rank.King, value: 10 }
    ];
    setHand(startHand);
    // Shuffle the rest of the deck
    setDeck(fullDeck.filter(c => !['7', 'K'].includes(c.rank) || Math.random() > 0.5));
    setPhase(GamePhase.PLAYER_TURN_START);
  }, []);

  // --- Dynamic Guidance Engine ---
  const energy = useMemo(() => calculateHandValue(hand, roundJoker), [hand]);

  const guidance = useMemo(() => {
    if (showCaller) return { msg: `Simulation Halted: ${showCaller} called SHOW. Let's analyze the scores.`, target: null };
    if (currentPlayerIndex !== 0) return { msg: `Operational Pulse: ${['Mohan', 'Lakshman', 'Kishore'][currentPlayerIndex - 1]} is executing their strategy...`, target: null };

    if (phase === GamePhase.PLAYER_DRAW || phase === GamePhase.PLAYER_TOSSING_DRAW) {
      return { msg: "Strategy: Draw a new unit from the Stockpile to complete your turn cycle.", target: 'DECK' };
    }

    // Check for pairs in hand
    const ranks: Record<string, string[]> = {};
    hand.forEach(c => {
      if (!ranks[c.rank]) ranks[c.rank] = [];
      ranks[c.rank].push(c.id);
    });
    const pairRank = Object.keys(ranks).find(r => ranks[r].length >= 2);

    if (pairRank && !tossedThisTurn) {
      const isBothSelected = ranks[pairRank].every(id => selectedCardIds.includes(id));
      if (isBothSelected) return { msg: "Aggressive Play: TOSS these matching ranks to permanently reduce your hand count.", target: 'TOSS_BTN' };
      return { msg: "Tactical Insight: You have a pair. Select BOTH to enable the Twin Toss maneuver.", target: 'PAIR', ids: ranks[pairRank] };
    }

    if (energy <= 5) {
      return { msg: `Intuition Test: Energy is ${energy}. You CAN call SHOW, but only do so if you feel you have the LOWEST score at the table.`, target: 'SHOW_BTN' };
    }

    // High card suggestion
    const highest = [...hand].sort((a, b) => b.value - a.value)[0];
    if (highest && highest.value > 5) {
      if (selectedCardIds.includes(highest.id)) return { msg: "Neutralization Ready: DISCARD this high-value unit to lower your total energy.", target: 'DISCARD_BTN' };
      return { msg: `Efficiency Tip: That ${highest.rank} is heavy. Select it to ready a discard.`, target: 'HIGH_CARD', id: highest.id };
    }

    return { msg: "Tactical Freedom: Choose your next move. Aim for the lowest energy signature.", target: null };
  }, [hand, phase, currentPlayerIndex, selectedCardIds, energy, tossedThisTurn, showCaller]);

  // --- Bot Simulation ---
  useEffect(() => {
    if (currentPlayerIndex !== 0 && !showCaller) {
      const runBot = async () => {
        await new Promise(r => setTimeout(r, 1200));

        // Simple bot logic for tutorial
        const botHand = [{ value: 7 }, { value: 7 }, { value: 2 }] as any; // Simulated
        const action = decideBotAction({ id: currentPlayerIndex, hand: botHand } as any, roundJoker, false);

        if (action.type === 'SHOW') {
          setShowCaller(['Mohan', 'Lakshman', 'Kishore'][currentPlayerIndex - 1]);
          await new Promise(r => setTimeout(r, 1000));
          setIsSuccess(true);
        } else {
          const next = (currentPlayerIndex + 1) % 4;
          setCurrentPlayerIndex(next);
          if (next === 0) setTossedThisTurn(false);
        }
      };
      runBot();
    }
  }, [currentPlayerIndex, showCaller]);

  // --- Handlers ---
  const handleCardClick = (card: CardData) => {
    if (currentPlayerIndex !== 0 || phase !== GamePhase.PLAYER_TURN_START) return;
    setSelectedCardIds(prev => {
      if (prev.includes(card.id)) return prev.filter(id => id !== card.id);
      if (prev.length >= 2) return [prev[1], card.id];
      return [...prev, card.id];
    });
  };

  const handleDiscardAction = () => {
    if (selectedCardIds.length === 1) {
      const card = hand.find(c => c.id === selectedCardIds[0])!;
      setHand(prev => prev.filter(c => c.id !== card.id));
      setPendingDiscard(card);
      setSelectedCardIds([]);
      setPhase(GamePhase.PLAYER_DRAW);
    }
  };

  const handleTossAction = () => {
    if (selectedCardIds.length === 2) {
      const tossed = hand.filter(c => selectedCardIds.includes(c.id));
      if (tossed[0].rank !== tossed[1].rank) return;
      setHand(prev => prev.filter(c => !selectedCardIds.includes(c.id)));
      setPendingToss(tossed);
      setSelectedCardIds([]);
      setPhase(GamePhase.PLAYER_TOSSING_DRAW);
      setTossedThisTurn(true);
    }
  };

  const handleDrawAction = (source: 'DECK' | 'OPEN') => {
    if (currentPlayerIndex !== 0 || (phase !== GamePhase.PLAYER_DRAW && phase !== GamePhase.PLAYER_TOSSING_DRAW)) return;

    let drawn: CardData;
    const newDeck = [...deck];
    if (source === 'OPEN' && openPile.length > 0) {
      drawn = openPile[openPile.length - 1];
      setOpenPile(prev => prev.slice(0, -1));
    } else {
      drawn = newDeck.shift()!;
      setDeck(newDeck);
    }

    setHand(prev => [...prev, drawn]);
    if (pendingDiscard) setOpenPile(prev => [...prev, pendingDiscard]);
    if (pendingToss.length) setOpenPile(prev => [...prev, ...pendingToss]);
    setPendingDiscard(null);
    setPendingToss([]);
    setPhase(GamePhase.PLAYER_TURN_START);
    if (source === 'DECK' || source === 'OPEN') setCurrentPlayerIndex(1);
  };

  const handleShowAction = () => {
    if (currentPlayerIndex === 0 && energy <= 5) {
      setShowCaller('Candidate');
      setIsSuccess(true);
    }
  };

  return (
    <div className="h-[100dvh] flex flex-col overflow-hidden bg-[#0d1a0d]">
      <TutorialSensei message={guidance.msg} onExit={onExit} />

      {/* Header */}
      <div className="h-14 bg-[#0a140a] flex items-center justify-between px-4 shadow-xl z-20 shrink-0 border-b border-white/5">
        <div className="flex items-center gap-3">
          <button onClick={onExit} className="text-red-400 bg-white/5 p-2 rounded-lg"><LogOut size={18} /></button>
          <div className="bg-slate-800 px-3 py-1.5 rounded-lg text-[10px] flex items-center gap-2 border border-white/5 shadow-inner">
             <span className="text-gray-400 uppercase tracking-widest font-black">Protocol</span>
             <span className="font-black text-yellow-500">SIMULATION</span>
          </div>
          <div className="bg-blue-900/30 px-3 py-1.5 rounded-lg text-[10px] flex items-center gap-2 border border-blue-500/30">
            <Globe size={12} className="text-blue-400" />
            <span className="font-mono font-black text-blue-200 uppercase tracking-tighter">Academy</span>
          </div>
        </div>

        <div className="flex bg-white text-black px-2 py-1 rounded border-2 border-purple-500 items-center gap-1.5 shadow-[0_0_15px_rgba(168,85,247,0.4)]">
           <span className="text-[10px] font-black uppercase opacity-50">Joker</span>
           <span className="font-bold text-sm">A</span>
        </div>

        <div className="flex items-center gap-2 bg-black/40 px-3 py-1.5 rounded-full border border-green-500/20">
           <div className="w-2 h-2 rounded-full bg-green-500 animate-pulse" />
           <span className="text-[10px] font-black text-white uppercase tracking-widest">Candidate</span>
        </div>
      </div>

      <div className="flex-1 relative flex flex-col justify-between p-2 md:p-4 max-w-7xl mx-auto w-full">

        {/* Opponents */}
        <div className="flex justify-center gap-6 mt-2">
           {['Mohan', 'Lakshman', 'Kishore'].map((name, i) => (
             <div key={name} className={`flex flex-col items-center p-2 rounded-2xl transition-all duration-500 ${currentPlayerIndex === i + 1 ? 'bg-yellow-500/10 scale-105 border border-yellow-500/40 shadow-2xl' : 'bg-black/20 opacity-30 grayscale'}`}>
                <div className="w-12 h-12 md:w-14 md:h-14 bg-slate-800 rounded-xl flex items-center justify-center border-2 border-slate-600 shadow-xl relative overflow-hidden">
                   <div className="absolute inset-0 bg-blue-950 opacity-10 flex items-center justify-center font-black text-[10px] text-yellow-500">TS</div>
                   <Bot size={24} className="text-slate-400 relative z-10" />
                </div>
                <span className="text-[9px] font-black mt-1.5 uppercase text-white tracking-widest">{name}</span>
                <span className="text-[8px] text-yellow-500/60 font-bold uppercase">Strategy Mode</span>
             </div>
           ))}
        </div>

        {/* Central Tactical Area */}
        <div className="flex-1 flex items-center justify-center gap-6 md:gap-24 relative">
            <div className="flex flex-col items-center gap-2 relative">
               <Card 
                  disabled={currentPlayerIndex !== 0 || (phase !== GamePhase.PLAYER_DRAW && phase !== GamePhase.PLAYER_TOSSING_DRAW)} 
                  onClick={() => handleDrawAction('DECK')} 
                  className={(phase !== GamePhase.PLAYER_TURN_START && currentPlayerIndex === 0) ? 'ring-2 ring-yellow-400 scale-105' : 'opacity-30'}
               />
               {guidance.target === 'DECK' && <TacticalPointer className="absolute -top-16" />}
               <span className="text-[10px] uppercase tracking-[0.2em] font-black text-slate-500">Stockpile ({deck.length})</span>
            </div>

            <div className="flex gap-6 items-center">
              <div className="flex flex-col items-center gap-2 relative">
                 {openPile.length > 0 ? (
                   <Card 
                    card={openPile[openPile.length - 1]} 
                    onClick={() => handleDrawAction('OPEN')}
                    disabled={currentPlayerIndex !== 0 || (phase !== GamePhase.PLAYER_DRAW && phase !== GamePhase.PLAYER_TOSSING_DRAW)}
                    className="shadow-xl"
                   />
                 ) : (
                   <div className="w-20 h-28 md:w-24 md:h-36 border-2 border-dashed border-white/5 rounded-2xl flex items-center justify-center bg-black/10">
                      <span className="text-white/5 text-[10px] uppercase font-black tracking-widest">Empty</span>
                   </div>
                 )}
                 <span className="text-[10px] uppercase tracking-[0.2em] font-black text-slate-500">Open Pile</span>
              </div>

              {/* Transition States */}
              <div className="relative min-w-[60px] flex items-center justify-center">
                 {pendingDiscard && (
                    <div className="animate-in slide-in-from-left-4 fade-in">
                        <Card card={pendingDiscard} disabled className="opacity-70 scale-90 ring-2 ring-yellow-500/40 shadow-2xl" />
                    </div>
                 )}
                 {pendingToss.length > 0 && (
                    <div className="flex -space-x-8 animate-in slide-in-from-left-4 fade-in">
                        {pendingToss.map(c => <Card key={c.id} card={c} disabled className="opacity-70 scale-90 ring-2 ring-blue-500/40 shadow-2xl" />)}
                    </div>
                 )}
              </div>
            </div>

            {/* End of Simulation Screen */}
            {isSuccess && (
               <div className="absolute inset-0 z-[110] flex items-center justify-center bg-black/85 backdrop-blur-xl animate-in fade-in duration-500">
                 <div className="bg-[#0f240f] border-2 border-yellow-500/30 p-8 rounded-[3rem] shadow-[0_0_80px_rgba(0,0,0,0.8)] max-w-xs w-full text-center scale-in-center">
                    <div className="absolute top-0 left-0 w-full h-1 bg-gradient-to-r from-transparent via-yellow-500/50 to-transparent" />
                    <div className="w-16 h-16 bg-yellow-500 rounded-[1.5rem] flex items-center justify-center mx-auto mb-6 rotate-[15deg] shadow-lg shadow-yellow-500/40 ring-4 ring-black">
                       <ShieldCheck className="text-black" size={32} />
                    </div>
                    <h2 className="text-2xl font-serif font-black text-white mb-2 tracking-tight">Strategy Confirmed</h2>
                    <p className="text-slate-500 mb-8 text-[9px] uppercase tracking-[0.4em] font-black">{showCaller} called SHOW. Simulation complete.</p>
                    <button 
                      onClick={onExit} 
                      className="w-full bg-yellow-500 hover:bg-yellow-400 text-black font-black py-5 rounded-2xl flex items-center justify-center gap-2 text-xs transition-all active:scale-95 shadow-xl shadow-yellow-900/40 uppercase tracking-widest"
                    >
                       Enter Real Arena <ChevronRight size={18} />
                    </button>
                 </div>
               </div>
            )}
        </div>

        {/* Console & Hand */}
        <div className="flex flex-col items-center gap-4 pb-14 shrink-0">

           {/* Intuitive Action Console */}
           <div className={`flex items-center gap-1.5 bg-black/60 backdrop-blur-3xl p-1.5 rounded-full border border-white/10 shadow-2xl transition-all duration-700 ${currentPlayerIndex === 0 && phase === GamePhase.PLAYER_TURN_START ? 'opacity-100 translate-y-0 scale-100' : 'opacity-10 translate-y-6 scale-95 pointer-events-none'}`}>
              <button 
                onClick={handleShowAction} 
                className={`relative px-5 py-2.5 rounded-full font-black flex items-center gap-2 text-[10px] transition-all ${guidance.target === 'SHOW_BTN' ? 'bg-red-600 text-white shadow-[0_0_25px_rgba(220,38,38,0.5)] ring-2 ring-white/30 animate-pulse' : 'bg-slate-800 text-slate-500'}`}
              >
                <Zap size={14} className="fill-current" /> SHOW
                {guidance.target === 'SHOW_BTN' && <TacticalPointer className="absolute -top-16 left-1/2 -translate-x-1/2" />}
              </button>

              <div className="w-[1px] h-6 bg-white/10 mx-0.5" />

              <button 
                onClick={handleTossAction} 
                className={`relative px-5 py-2.5 rounded-full font-black flex items-center gap-2 text-[10px] transition-all ${guidance.target === 'TOSS_BTN' ? 'bg-blue-600 text-white shadow-[0_0_25px_rgba(37,99,235,0.5)] ring-2 ring-white/30 animate-pulse' : 'bg-slate-800 text-slate-500'}`}
              >
                <RefreshCw size={14} /> TOSS (2)
                {guidance.target === 'TOSS_BTN' && <TacticalPointer className="absolute -top-16 left-1/2 -translate-x-1/2" />}
              </button>

              <button 
                onClick={handleDiscardAction} 
                className={`relative px-5 py-2.5 rounded-full font-black flex items-center gap-2 text-[10px] transition-all ${guidance.target === 'DISCARD_BTN' ? 'bg-green-600 text-white shadow-[0_0_25px_rgba(22,163,74,0.5)] ring-2 ring-white/30 animate-pulse' : 'bg-slate-800 text-slate-500'}`}
              >
                <Hand size={14} /> DISCARD (1)
                {guidance.target === 'DISCARD_BTN' && <TacticalPointer className="absolute -top-16 left-1/2 -translate-x-1/2" />}
              </button>
           </div>

           {/* Hand Area with Strategy Guides */}
           <div className="flex items-end justify-center -space-x-8 md:-space-x-12 h-[130px] md:h-[160px]">
              {hand.map((card) => {
                const isSelected = selectedCardIds.includes(card.id);
                const isTarget = (guidance.target === 'PAIR' && guidance.ids?.includes(card.id)) || 
                               (guidance.target === 'HIGH_CARD' && guidance.id === card.id);

                return (
                  <div key={card.id} className="relative transition-all duration-500">
                    <Card 
                      card={card} 
                      isJoker={card.rank === Rank.Ace}
                      selected={isSelected}
                      onClick={() => handleCardClick(card)}
                      className={`transition-all origin-bottom duration-500 ${currentPlayerIndex === 0 ? '' : 'grayscale opacity-40'} ${isTarget && !isSelected ? 'ring-2 ring-yellow-400 scale-110 z-30 shadow-[0_0_30px_rgba(234,179,8,0.4)]' : ''}`}
                    />
                    {isTarget && !isSelected && (
                       <TacticalPointer className="absolute -top-16 left-1/2 -translate-x-1/2" />
                    )}
                  </div>
                );
              })}
           </div>

           {/* Live Energy Telemetry */}
           <div className="flex flex-col items-center gap-1.5 mt-3">
              <div className="flex items-center gap-2 px-4 py-1.5 rounded-full bg-white/[0.02] border border-white/5 shadow-inner backdrop-blur-sm">
                <span className="text-green-500/50 font-black uppercase tracking-[0.25em] text-[8px]">Academy Mode</span>
                <span className="text-gray-700 font-bold text-[8px] uppercase tracking-widest">Lowest Wins</span>
              </div>
              <div className="text-white/40 font-black flex items-baseline gap-2 tabular-nums">
                <span className="text-[9px] uppercase tracking-widest text-white/10 font-black">Energy Trace:</span>
                <span className="text-white text-2xl font-mono tracking-tighter drop-shadow-[0_0_10px_rgba(255,255,255,0.2)]">{energy}</span>
              </div>
           </div>
        </div>
      </div>

      <style>{`
        @keyframes scale-in-center {
          0% { transform: scale(0.9); opacity: 0; filter: blur(5px); }
          100% { transform: scale(1); opacity: 1; filter: blur(0); }
        }
        .scale-in-center { animation: scale-in-center 0.6s cubic-bezier(0.19, 1, 0.22, 1) both; }
      `}</style>
