  const [selectedCardIds, setSelectedCardIds] = useState<string[]>([]);
  const [pendingDiscard, setPendingDiscard] = useState<CardData | null>(null);
  const [pendingToss, setPendingToss] = useState<CardData[]>([]);
  const [isSuccess, setIsSuccess] = useState(false);
  const [tossedThisTurn, setTossedThisTurn] = useState(false);
  const [showCaller, setShowCaller] = useState<string | null>(null);
  const [senseiError, setSenseiError] = useState<string | null>(null);

  // Tutorial Round Joker is always Ace for simplicity
  const roundJoker = { id: 'tut-joker', rank: Rank.Ace, suit: Suit.Hearts, value: 1 };

  // --- Initial Setup (Rigged for Education) ---
  useEffect(() => {
    const fullDeck = createDeck();
    // Rig first hand to show a pair of 7s and a high King
    const riggedHand: CardData[] = [
      { id: 'tut-7a', suit: Suit.Clubs, rank: Rank.Seven, value: 7 },
      { id: 'tut-7b', suit: Suit.Spades, rank: Rank.Seven, value: 7 },
      { id: 'tut-k', suit: Suit.Hearts, rank: Rank.King, value: 10 }
    ];
    setHand(riggedHand);
    // Remove the rigged cards from the deck
    setDeck(fullDeck.filter(c => !['7', 'K'].includes(c.rank)));
    setPhase(GamePhase.PLAYER_TURN_START);
  }, []);

  // --- Dynamic Strategy Analysis ---
  const energy = useMemo(() => calculateHandValue(hand, roundJoker), [hand]);

  const guidance = useMemo(() => {
    if (showCaller) return { msg: `Match Terminated: ${showCaller} initiated SHOW. Strategy confirmed.`, target: null };
    if (senseiError) return { msg: senseiError, target: null };
    if (currentPlayerIndex !== 0) return { msg: `${['Kabil...', 'PK', 'Mithul'][currentPlayerIndex - 1]} is calculating their next maneuver...`, target: null };

    if (phase === GamePhase.PLAYER_DRAW || phase === GamePhase.PLAYER_TOSSING_DRAW) {
      return { msg: "Strategy: Draw from the Stockpile or Open Pile to conclude your turn cycle.", target: 'DECK' };
    }

    // Check for pairs
    const ranks: Record<string, string[]> = {};
    hand.forEach(c => {
      if (!ranks[c.rank]) ranks[c.rank] = [];
      ranks[c.rank].push(c.id);
    });
    const pairRank = Object.keys(ranks).find(r => ranks[r].length >= 2);

    if (pairRank && !tossedThisTurn) {
      const isBothSelected = ranks[pairRank].every(id => selectedCardIds.includes(id));
      if (isBothSelected) return { msg: "Twin Toss Ready: TOSSing matching ranks reduces your hand size permanently.", target: 'TOSS_BTN' };
      return { msg: "Tactical Insight: You possess a pair. Select both matching ranks to enable a TOSS maneuver.", target: 'PAIR', ids: ranks[pairRank] };
    }

    if (energy <= 5) {
      return { msg: `Threshold Reached: Energy is ${energy}. You are eligible for SHOW. Is your score the lowest at the table?`, target: 'SHOW_BTN' };
    }

    const highest = [...hand].sort((a, b) => b.value - a.value)[0];
    if (highest && highest.value > 5) {
      if (selectedCardIds.includes(highest.id)) return { msg: "Target Identified: DISCARD this high-value unit to lower your hand energy.", target: 'DISCARD_BTN' };
      return { msg: `Neutralize High Energy: Select the ${highest.rank} to ready a discard action.`, target: 'HIGH_CARD', id: highest.id };
    }

    return { msg: "Intuitive Play: Analyze your hand. Your goal is the lowest possible total score.", target: null };
  }, [hand, phase, currentPlayerIndex, selectedCardIds, energy, tossedThisTurn, showCaller, senseiError]);

  // --- Bot Turn Logic ---
  useEffect(() => {
    if (currentPlayerIndex !== 0 && !showCaller) {
      const runBot = async () => {
        await new Promise(r => setTimeout(r, 1500));
        // Small chance for a bot to end the match if they have low cards
        if (Math.random() < 0.1 && energy > 2) {
           setShowCaller(['Kabil...', 'PK', 'Mithul'][currentPlayerIndex - 1]);
           setIsSuccess(true);
        } else {
          const next = (currentPlayerIndex + 1) % 4;
          setCurrentPlayerIndex(next);
          if (next === 0) setTossedThisTurn(false);
        }
      };
      runBot();
    }
  }, [currentPlayerIndex, showCaller]);

  // --- UI Handlers ---
  const handleCardClick = (card: CardData) => {
    if (currentPlayerIndex !== 0 || phase !== GamePhase.PLAYER_TURN_START) return;
    setSenseiError(null);
    setSelectedCardIds(prev => {
      if (prev.includes(card.id)) return prev.filter(id => id !== card.id);
      if (prev.length >= 2) return [prev[1], card.id];
      return [...prev, card.id];
    });
  };

  const handleDiscardAction = () => {
    if (selectedCardIds.length === 1) {
      const card = hand.find(c => c.id === selectedCardIds[0])!;
      setHand(prev => prev.filter(c => c.id !== card.id));
      setPendingDiscard(card);
      setSelectedCardIds([]);
      setPhase(GamePhase.PLAYER_DRAW);
    }
  };

  const handleTossAction = () => {
    if (selectedCardIds.length === 2) {
      const tossed = hand.filter(c => selectedCardIds.includes(c.id));
      if (tossed[0].rank !== tossed[1].rank) {
        setSenseiError("Invalid Move: TOSS requires cards of identical rank.");
        return;
      }
      setHand(prev => prev.filter(c => !selectedCardIds.includes(c.id)));
      setPendingToss(tossed);
      setSelectedCardIds([]);
      setPhase(GamePhase.PLAYER_TOSSING_DRAW);
      setTossedThisTurn(true);
    }
  };

  const handleDrawAction = (source: 'DECK' | 'OPEN') => {
    if (currentPlayerIndex !== 0 || (phase !== GamePhase.PLAYER_DRAW && phase !== GamePhase.PLAYER_TOSSING_DRAW)) return;

    let drawn: CardData;
    const newDeck = [...deck];
    if (source === 'OPEN' && openPile.length > 0) {
      drawn = openPile[openPile.length - 1];
      setOpenPile(prev => prev.slice(0, -1));
    } else {
      drawn = newDeck.shift()!;
      setDeck(newDeck);
    }

    setHand(prev => [...prev, drawn]);
    if (pendingDiscard) setOpenPile(prev => [...prev, pendingDiscard]);
    if (pendingToss.length) setOpenPile(prev => [...prev, ...pendingToss]);
    setPendingDiscard(null);
    setPendingToss([]);
    setPhase(GamePhase.PLAYER_TURN_START);
    if (source === 'DECK' || source === 'OPEN') setCurrentPlayerIndex(1);
  };

  const handleShowAction = () => {
    if (currentPlayerIndex !== 0) return;
    if (energy > 5) {
      setSenseiError("Show Protocol Restricted: Total energy must be 5 or less.");
      return;
    }
    setShowCaller('Guest (Candidate)');
    setIsSuccess(true);
  };

  return (
    <div className="h-[100dvh] flex flex-col overflow-hidden bg-[#1a2e1a]">
      <TutorialSensei message={guidance.msg} onExit={onExit} />

      {/* Header - Pixel Perfect Replication */}
      <div className="h-16 bg-[#0f1f0f] flex items-center justify-between px-4 shadow-lg z-20 shrink-0">
        <div className="flex items-center gap-4">
          <button onClick={onExit} className="text-red-400 bg-white/5 p-2 rounded-lg">
            <LogOut size={20} />
          </button>

          <div className="bg-slate-800 px-3 py-1 rounded-lg text-xs md:text-sm flex items-center gap-2">
             <span className="text-gray-400">Round</span>
             <span className="font-bold text-white">1/3</span>
          </div>

          <div className="hidden sm:flex bg-blue-900/50 px-3 py-1 rounded-lg text-xs md:text-sm items-center gap-2 border border-blue-500/30">
            <Globe size={12} className="text-blue-400" />
            <span className="font-mono font-bold text-blue-200">ACADEMY</span>
          </div>
        </div>

        <div className="flex items-center gap-2">
           <span className="text-xs uppercase tracking-widest text-purple-400 font-bold hidden sm:inline">JOKER: {roundJoker.rank}</span>
           <div className="flex bg-white text-black px-2 py-1 rounded border-2 border-purple-500 items-center gap-1 shadow-[0_0_15px_rgba(168,85,247,0.4)]">
             <span className="font-bold">{roundJoker.rank}</span>
           </div>
        </div>

        <div className="flex items-center gap-4">
           <div className="flex items-center gap-2">
             <div className="w-3 h-3 rounded-full bg-green-500 animate-pulse shadow-[0_0_8px_rgba(34,197,94,0.6)]" />
             <span className="text-sm font-bold text-white">Guest</span>
           </div>
        </div>
      </div>

      <div className="flex-1 relative flex flex-col justify-between p-2 md:p-4 max-w-7xl mx-auto w-full overflow-hidden">

        {/* Opponents Grid */}
        <div className="flex justify-center flex-wrap gap-2 md:gap-8 mt-2">
           {['Kabil...', 'PK', 'Mithul'].map((name, i) => (
             <div key={name} className={`flex flex-col items-center p-3 rounded-2xl transition-all duration-500 ${currentPlayerIndex === i + 1 ? 'bg-yellow-500/10 scale-105 border border-yellow-500/30 shadow-2xl' : 'bg-black/20 opacity-30 grayscale'}`}>
                <div className="relative">
                   <div className="w-12 h-12 bg-slate-700 rounded-full flex items-center justify-center border-2 border-slate-500">
                     <Bot size={20} className="text-slate-300" />
                   </div>
                   <div className="absolute -bottom-1 -right-1 w-5 h-5 bg-blue-900 rounded-full flex items-center justify-center text-[10px] font-bold border border-white">3</div>
                </div>
                <span className="text-xs font-bold mt-1 text-white uppercase tracking-tight">Bot {name}</span>
                <span className="text-[10px] text-yellow-400 font-black">0 pts</span>

                <div className="flex -space-x-4 mt-2">
                   {[1, 2, 3].map((_, idx) => (
                     <div key={idx} className="w-10 h-14 bg-blue-900 border border-white/20 rounded-lg flex items-center justify-center scale-75 shadow-md">
                        <span className="text-white/20 text-[8px] font-bold">TS</span>
                     </div>
                   ))}
                </div>
             </div>
           ))}
        </div>

        {/* Central Tactical Arena */}
        <div className="flex-1 flex items-center justify-center gap-4 md:gap-24 relative">
            <div className="flex flex-col items-center gap-2 relative">
               <Card 
                  disabled={currentPlayerIndex !== 0 || (phase !== GamePhase.PLAYER_DRAW && phase !== GamePhase.PLAYER_TOSSING_DRAW)} 
                  onClick={() => handleDrawAction('DECK')} 
                  className={(phase !== GamePhase.PLAYER_TURN_START && currentPlayerIndex === 0) ? 'ring-2 ring-yellow-400 scale-105' : 'opacity-40'}
               />
               {guidance.target === 'DECK' && <TacticalPointer className="absolute -top-20" />}
               <span className="text-xs uppercase tracking-widest font-black text-slate-400">Stockpile</span>
            </div>

            <div className="flex gap-4 items-center">
              <div className="flex flex-col items-center gap-2 relative">
                 {openPile.length > 0 ? (
                   <Card 
                    card={openPile[openPile.length - 1]} 
                    onClick={() => handleDrawAction('OPEN')}
                    disabled={currentPlayerIndex !== 0 || (phase !== GamePhase.PLAYER_DRAW && phase !== GamePhase.PLAYER_TOSSING_DRAW)}
                    className="shadow-2xl"
                   />
                 ) : (
                   <div className="w-20 h-28 md:w-24 md:h-36 border-2 border-dashed border-white/10 rounded-2xl flex items-center justify-center bg-black/5">
                      <span className="text-white/5 text-[10px] uppercase font-black tracking-[0.3em]">Empty Pile</span>
                   </div>
                 )}
                 <span className="text-xs uppercase tracking-widest font-black text-slate-400">Open Pile</span>
              </div>

              {/* State Transitions Visuals */}
              <div className="relative min-w-[60px] flex items-center justify-center">
                 {pendingDiscard && (
                    <div className="flex flex-col items-center gap-1 animate-in slide-in-from-left-4 fade-in">
                        <Card card={pendingDiscard} disabled className="opacity-70 scale-90 ring-2 ring-yellow-500/40 shadow-xl" />
                        <span className="text-[8px] font-black text-yellow-500 uppercase">Discarding</span>
                    </div>
                 )}
                 {pendingToss.length > 0 && (
                    <div className="flex flex-col items-center gap-1 animate-in slide-in-from-left-4 fade-in">
                        <div className="flex -space-x-8">
                            {pendingToss.map(c => <Card key={c.id} card={c} disabled className="opacity-70 scale-90 ring-2 ring-blue-500/40 shadow-xl" />)}
                        </div>
                        <span className="text-[8px] font-black text-blue-500 uppercase">Tossing Pair</span>
                    </div>
                 )}
              </div>
            </div>

            {/* Victory Final Screen */}
            {isSuccess && (
               <div className="absolute inset-0 z-[110] flex items-center justify-center bg-black/85 backdrop-blur-xl animate-in fade-in duration-500">
                 <div className="bg-[#0f1f0f] border-2 border-yellow-500/30 p-10 rounded-[3rem] shadow-[0_0_100px_rgba(0,0,0,0.9)] max-w-sm w-full text-center scale-in-center">
                    <div className="w-20 h-20 bg-yellow-500 rounded-[2rem] flex items-center justify-center mx-auto mb-8 rotate-[15deg] shadow-lg shadow-yellow-500/40 ring-4 ring-black">
                       <ShieldCheck className="text-black" size={40} />
                    </div>
                    <h2 className="text-3xl font-serif font-black text-white mb-2 tracking-tight">Strategy Verified</h2>
                    <p className="text-slate-500 mb-10 text-[10px] uppercase tracking-[0.5em] font-black">Score Logged: {energy} Energy</p>
                    <button 
                      onClick={onExit} 
                      className="w-full bg-yellow-500 hover:bg-yellow-400 text-black font-black py-5 rounded-[2rem] flex items-center justify-center gap-3 text-sm transition-all active:scale-95 shadow-2xl shadow-yellow-900/40 uppercase tracking-[0.2em]"
                    >
                       Deploy to Real Match <ChevronRight size={20} />
                    </button>
                 </div>
               </div>
            )}
        </div>

        {/* Dynamic Action Console - Pixel Perfect Replication */}
        <div className="flex flex-col items-center gap-4 pb-14 shrink-0">

           <div className={`flex items-center gap-2 bg-black/70 backdrop-blur-3xl p-2 rounded-full border border-white/10 shadow-2xl transition-all duration-700 ${currentPlayerIndex === 0 && phase === GamePhase.PLAYER_TURN_START ? 'opacity-100 translate-y-0 scale-100' : 'opacity-10 translate-y-6 scale-95 pointer-events-none'}`}>
              <button 
                onClick={handleShowAction} 
                className={`relative px-6 py-3 rounded-full font-black flex items-center gap-2 text-[11px] transition-all ${guidance.target === 'SHOW_BTN' ? 'bg-red-600 text-white shadow-[0_0_20px_rgba(220,38,38,0.4)] ring-2 ring-white/30 animate-pulse' : 'bg-slate-800 text-slate-500'}`}
              >
                <Zap size={14} className="fill-current" /> SHOW
                {guidance.target === 'SHOW_BTN' && <TacticalPointer className="absolute -top-20 left-1/2 -translate-x-1/2" />}
              </button>

              <div className="w-[1px] h-6 bg-white/10 mx-1" />

              <button 
                onClick={handleTossAction} 
                className={`relative px-6 py-3 rounded-full font-black flex items-center gap-2 text-[11px] transition-all ${guidance.target === 'TOSS_BTN' ? 'bg-blue-600 text-white shadow-[0_0_20px_rgba(37,99,235,0.4)] ring-2 ring-white/30 animate-pulse' : 'bg-slate-800 text-slate-500'}`}
              >
                <RefreshCw size={14} /> TOSS (2)
                {guidance.target === 'TOSS_BTN' && <TacticalPointer className="absolute -top-20 left-1/2 -translate-x-1/2" />}
              </button>

              <button 
                onClick={handleDiscardAction} 
                className={`relative px-6 py-3 rounded-full font-black flex items-center gap-2 text-[11px] transition-all ${guidance.target === 'DISCARD_BTN' ? 'bg-green-600 text-white shadow-[0_0_20px_rgba(22,163,74,0.4)] ring-2 ring-white/30 animate-pulse' : 'bg-slate-800 text-slate-500'}`}
              >
                <Hand size={14} /> DISCARD (1)
                {guidance.target === 'DISCARD_BTN' && <TacticalPointer className="absolute -top-20 left-1/2 -translate-x-1/2" />}
              </button>
           </div>

           {/* Guided Hand Area */}
           <div className="flex items-end justify-center -space-x-8 md:-space-x-12 h-[130px] md:h-[160px]">
              {hand.map((card) => {
                const isSelected = selectedCardIds.includes(card.id);
                const isTarget = (guidance.target === 'PAIR' && guidance.ids?.includes(card.id)) || 
                               (guidance.target === 'HIGH_CARD' && guidance.id === card.id);

                return (
                  <div key={card.id} className="relative transition-all duration-500">
                    <Card 
                      card={card} 
                      isJoker={card.rank === roundJoker.rank}
                      selected={isSelected}
                      onClick={() => handleCardClick(card)}
                      className={`transition-all origin-bottom duration-500 ${currentPlayerIndex === 0 ? '' : 'grayscale opacity-40'} ${isTarget && !isSelected ? 'ring-2 ring-yellow-400 scale-110 z-30 shadow-[0_0_30px_rgba(234,179,8,0.5)]' : ''}`}
                    />
                    {isTarget && !isSelected && (
                       <TacticalPointer className="absolute -top-20 left-1/2 -translate-x-1/2" />
                    )}
                  </div>
                );
              })}
           </div>

           {/* Status Footer */}
           <div className="flex flex-col items-center gap-1.5 mt-3">
              <div className="flex items-center gap-2 px-5 py-2 rounded-full bg-white/[0.03] border border-white/10 shadow-inner backdrop-blur-md">
                <span className="text-gray-400 font-black uppercase tracking-[0.3em] text-[8px]">Guest Candidate Profile</span>
                <span className="w-1.5 h-1.5 rounded-full bg-green-500 shadow-[0_0_8px_rgba(34,197,94,0.5)]" />
              </div>
              <div className="text-white/40 font-black flex items-baseline gap-2 tabular-nums">
                <span className="text-[10px] uppercase tracking-[0.2em] text-white/20 font-black font-serif">Energy Level:</span>
                <span className="text-white text-3xl font-mono tracking-tighter drop-shadow-[0_0_15px_rgba(255,255,255,0.3)]">{energy}</span>
              </div>
           </div>
        </div>
      </div>

      <style>{`
        @keyframes scale-in-center {
          0% { transform: scale(0.85); opacity: 0; filter: blur(10px); }
          100% { transform: scale(1); opacity: 1; filter: blur(0); }
        }
        .scale-in-center { animation: scale-in-center 0.7s cubic-bezier(0.19, 1, 0.22, 1) both; }
      `}</style>
    </div>
  );
};

export default TutorialEngine;

import React, { useState, useEffect, useMemo } from 'react';
import { CardData, Suit, Rank, GamePhase } from '../types';
import Card from '../components/Card';
import TutorialSensei from '../components/TutorialSensei';
import { calculateHandValue, createDeck } from '../services/gameLogic';
import { RefreshCw, Hand, AlertCircle, Bot, ChevronRight, LogOut, ArrowDown, Zap, ShieldCheck } from 'lucide-react';

// Tactical Pointer Component (Blue Guidance Arrow)
const TacticalPointer = ({ className = "" }: { className?: string }) => (
  <div className={`flex flex-col items-center animate-bounce z-[100] pointer-events-none ${className}`}>
    <div className="relative">
      <ArrowDown className="text-blue-400 drop-shadow-[0_0_12px_rgba(96,165,250,0.9)]" size={32} strokeWidth={3} />
      <div className="absolute top-0 -left-3 w-6 h-0.5 bg-blue-400/60 rotate-[45deg]" />
      <div className="absolute top-0 -right-3 w-6 h-0.5 bg-blue-400/60 -rotate-[45deg]" />
      <div className="absolute -bottom-2 left-1/2 -translate-x-1/2 w-8 h-8 rounded-full border-2 border-blue-400/20 scale-[2] animate-ping" />
    </div>
  </div>
);

const TutorialEngine: React.FC<{ onExit: () => void }> = ({ onExit }) => {
  // --- Game State (Mirrors App.tsx exactly) ---
  const [phase, setPhase] = useState<GamePhase>(GamePhase.PLAYER_TURN_START);
  const [currentPlayerIndex, setCurrentPlayerIndex] = useState(0); 
  const [hand, setHand] = useState<CardData[]>([]);
  const [deckCount, setDeckCount] = useState(40);
  const [openPile, setOpenPile] = useState<CardData[]>([]);
  const [selectedCardIds, setSelectedCardIds] = useState<string[]>([]);
  const [pendingDiscard, setPendingDiscard] = useState<CardData | null>(null);
  const [pendingToss, setPendingToss] = useState<CardData[]>([]);
  const [isSuccess, setIsSuccess] = useState(false);
  const [tossedThisTurn, setTossedThisTurn] = useState(false);
  const [showCaller, setShowCaller] = useState<string | null>(null);
  const [senseiError, setSenseiError] = useState<string | null>(null);

  // Tutorial Round Joker is always Ace for simplicity
  const roundJoker = { id: 'tut-joker', rank: Rank.Ace, suit: Suit.Hearts, value: 1 };

  // --- Initial Setup (Rigged for Education) ---
  useEffect(() => {
    // Rig first hand to show a pair of 7s and a high King
    const riggedHand: CardData[] = [
      { id: 'tut-7a', suit: Suit.Clubs, rank: Rank.Seven, value: 7 },
      { id: 'tut-7b', suit: Suit.Spades, rank: Rank.Seven, value: 7 },
      { id: 'tut-k', suit: Suit.Hearts, rank: Rank.King, value: 10 }
    ];
    setHand(riggedHand);
    setPhase(GamePhase.PLAYER_TURN_START);
  }, []);

  // --- Dynamic Strategy Analysis ---
  const energy = useMemo(() => calculateHandValue(hand, roundJoker), [hand]);

  const guidance = useMemo(() => {
    if (showCaller) return { msg: `Simulation Over: ${showCaller} called SHOW. Tactical mission complete.`, target: null };
    if (senseiError) return { msg: senseiError, target: null };
    if (currentPlayerIndex !== 0) return { msg: `Bot ${['Kabil...', 'PK', 'Mithul'][currentPlayerIndex - 1]} is analyzing their strategy...`, target: null };

    if (phase === GamePhase.PLAYER_DRAW || phase === GamePhase.PLAYER_TOSSING_DRAW) {
      return { msg: "Strategy: Draw from the Stockpile to end your turn cycle.", target: 'DECK' };
    }

    // Check for pairs
    const ranks: Record<string, string[]> = {};
    hand.forEach(c => {
      if (!ranks[c.rank]) ranks[c.rank] = [];
      ranks[c.rank].push(c.id);
    });
    const pairRank = Object.keys(ranks).find(r => ranks[r].length >= 2);

    if (pairRank && !tossedThisTurn) {
      const isBothSelected = ranks[pairRank].every(id => selectedCardIds.includes(id));
      if (isBothSelected) return { msg: "Tactical Toss Ready: Matching ranks can be tossed to permanently shrink your hand size.", target: 'TOSS_BTN' };
      return { msg: "Rule Hint: You have a pair! Select both matching ranks to activate a TOSS maneuver.", target: 'PAIR', ids: ranks[pairRank] };
    }

    if (energy <= 5) {
      return { msg: `Protocol Met: Energy is ${energy}. You are now eligible to call SHOW. Use it if you think your score is the lowest.`, target: 'SHOW_BTN' };
    }

    const highest = [...hand].sort((a, b) => b.value - a.value)[0];
    if (highest && highest.value > 5) {
      if (selectedCardIds.includes(highest.id)) return { msg: "Maneuver: Discard this high-energy unit to drop your total score.", target: 'DISCARD_BTN' };
      return { msg: `Score Reduction: Select the high-value ${highest.rank} to prepare a Discard action.`, target: 'HIGH_CARD', id: highest.id };
    }

    return { msg: "Operational Flow: Optimize your hand energy. Lower is always better.", target: null };
  }, [hand, phase, currentPlayerIndex, selectedCardIds, energy, tossedThisTurn, showCaller, senseiError]);

  // --- Bot Turn Logic ---
  useEffect(() => {
    if (currentPlayerIndex !== 0 && !showCaller) {
      const runBot = async () => {
        await new Promise(r => setTimeout(r, 1500));
        const next = (currentPlayerIndex + 1) % 4;
        setCurrentPlayerIndex(next);
        if (next === 0) setTossedThisTurn(false);
      };
      runBot();
    }
  }, [currentPlayerIndex, showCaller]);

  // --- UI Handlers ---
  const handleCardClick = (card: CardData) => {
    if (currentPlayerIndex !== 0 || phase !== GamePhase.PLAYER_TURN_START) return;
    setSenseiError(null);
    setSelectedCardIds(prev => {
      if (prev.includes(card.id)) return prev.filter(id => id !== card.id);
      if (prev.length >= 2) return [prev[1], card.id];
      return [...prev, card.id];
    });
  };

  const handleDiscardAction = () => {
    if (selectedCardIds.length === 1) {
      const card = hand.find(c => c.id === selectedCardIds[0])!;
      setHand(prev => prev.filter(c => c.id !== card.id));
