// --- Reusable Numeric Round Stepper ---
const RoundStepper = ({ value, onChange, label = "Rounds" }: { value: number, onChange: (val: number) => void, label?: string }) => {
  const [inputValue, setInputValue] = useState(value.toString());

  useEffect(() => {
    setInputValue(value.toString());
  }, [value]);

  const handleManualChange = (val: string) => {
    const sanitized = val.replace(/[^0-9]/g, '');
    setInputValue(sanitized);
    const num = parseInt(sanitized);
    if (!isNaN(num)) {
      onChange(Math.max(1, Math.min(999, num)));
    }
  };

  const adjust = (delta: number) => {
    const next = Math.max(1, Math.min(999, value + delta));
    onChange(next);
  };

  return (
    <div className="flex flex-col items-center gap-2">
      <label className="text-[10px] text-gray-400 font-black uppercase tracking-[0.3em]">{label}</label>
      <div className="flex items-center gap-2 bg-black/40 p-1.5 rounded-2xl border border-white/10 shadow-inner group focus-within:border-yellow-500/50 transition-all">
        <button 
          onClick={() => adjust(-1)}
          className="w-10 h-10 flex items-center justify-center rounded-xl bg-slate-800 text-gray-400 hover:text-white hover:bg-slate-700 transition-colors"
        >
          <Minus size={18} />
        </button>

        <input 
          type="text"
          value={inputValue}
          onChange={(e) => handleManualChange(e.target.value)}
          onBlur={() => setInputValue(value.toString())}
          className="w-16 bg-transparent text-center text-xl font-mono font-bold text-white focus:outline-none"
        />

        <button 
          onClick={() => adjust(1)}
          className="w-10 h-10 flex items-center justify-center rounded-xl bg-slate-800 text-gray-400 hover:text-white hover:bg-slate-700 transition-colors"
        >
          <Plus size={18} />
        </button>
      </div>
      <div className="text-[9px] font-bold text-gray-500 italic mt-1 uppercase tracking-tighter">
        {value === 1 ? 'Sudden Death' : value > 50 ? 'Endurance Marathon' : 'Standard Match'}
      </div>
    </div>
  );
};

