  const startSinglePlayerMatch = () => {
    const playerName = getDisplayName();
    const shuffledPool = shuffleDeck([...BOT_NAMES].map((name, idx) => ({ id: `bot-name-${idx}`, name } as unknown as CardData)));
    const selectedBotNames = (shuffledPool as any[]).slice(0, 3).map(item => "Bot " + item.name);
    const names = [playerName, ...selectedBotNames];
    setGameState(prev => ({ ...prev, gameMode: 'SINGLE_PLAYER', playerNames: names, phase: GamePhase.SETUP }));
    setShowRoundSelectionSP(false);
  };

  const initMultiplayerSetup = (count: number) => {
    setSetupPlayerCount(count);
    setSelectedTotalRounds(5);
    setCustomPlayerNames(Array.from({ length: count }, (_, i) => `Player ${i + 1}`));
    setIsNameEntryStep(true);
  };

  const finalizeMultiplayerStart = () => {
    setGameState(prev => ({ ...prev, gameMode: 'MULTIPLAYER', playerNames: customPlayerNames, phase: GamePhase.SETUP }));
    setIsNameEntryStep(false);
  };

  const startRound = useCallback((roundNum: number, existingPlayers?: Player[], mode?: GameMode) => {
    const newDeck = createDeck();
    const jokerIndex = Math.floor(Math.random() * newDeck.length);
    const roundJoker = { ...newDeck[jokerIndex] };
    let players: Player[] = [];
    let startingPlayerIndex = 0; 
    let startLog = `Round ${roundNum} started! Joker is ${roundJoker.rank}`;

    if (existingPlayers) {
      const caller = existingPlayers.find(p => p.wasCaller);
      if (caller) {
        startingPlayerIndex = caller.id;
        startLog = `Round ${roundNum} started! ${caller.name} called SHOW and starts the turn.`;
      }
      players = existingPlayers.map(p => ({ 
        ...p, hand: [], score: 0, totalScore: p.totalScore || 0,
        lastAction: 'Waiting...', wasCaller: false 
      }));
    } else {
      if (mode === 'SINGLE_PLAYER') {
        const names = gameState.playerNames.length > 0 ? gameState.playerNames : [getDisplayName(), 'Bot Alpha', 'Bot Beta', 'Bot Gamma'];
        players = [
          { id: 0, name: names[0], isBot: false, hand: [], score: 0, totalScore: 0, lastAction: 'Waiting...' },
          { id: 1, name: names[1], isBot: true, hand: [], score: 0, totalScore: 0, lastAction: 'Waiting...' },
          { id: 2, name: names[2], isBot: true, hand: [], score: 0, totalScore: 0, lastAction: 'Waiting...' },
          { id: 3, name: names[3], isBot: true, hand: [], score: 0, totalScore: 0, lastAction: 'Waiting...' }
        ];
      } else if (mode === 'MULTIPLAYER') {
        const count = setupPlayerCount > 0 ? setupPlayerCount : 4;
        const names = gameState.playerNames.length > 0 ? gameState.playerNames : Array.from({ length: count }, (_, i) => `Player ${i + 1}`);
        players = Array.from({ length: count }, (_, i) => ({
          id: i, name: names[i], isBot: false, hand: [], score: 0, totalScore: 0, lastAction: 'Waiting...'
        }));
      }
    }

    players.forEach(p => { p.hand = newDeck.splice(0, 3); });
    const newState: GameState = {
      ...gameState, deck: newDeck, openDeck: [], players,
      currentPlayerIndex: startingPlayerIndex, roundJoker, roundNumber: roundNum,
      totalRounds: selectedTotalRounds, phase: GamePhase.PLAYER_TURN_START,
      turnLog: [startLog], winner: null, lastDiscardedId: null,
      tossedThisTurn: false, pendingDiscard: null, pendingToss: [],
      gameMode: (mode || gameState.gameMode) as GameMode 
    };
    setGameState(newState);
    if (mode === 'ONLINE_HOST' || gameState.gameMode === 'ONLINE_HOST') updateGameState(roomCode, newState);
    setSelectedCardIds([]);
    setIsTransitioning(mode === 'MULTIPLAYER' || (existingPlayers && gameState.gameMode === 'MULTIPLAYER'));
  }, [gameState.gameMode, setupPlayerCount, gameState.playerNames, selectedTotalRounds, roomCode, gameState, getDisplayName]);

  useEffect(() => {
    if (gameState.phase === GamePhase.SETUP && gameState.gameMode && gameState.gameMode !== 'ONLINE_HOST' && gameState.gameMode !== 'ONLINE_CLIENT' && gameState.gameMode !== 'TUTORIAL') {
      startRound(1, undefined, gameState.gameMode);
    }
  }, [gameState.phase, gameState.gameMode, startRound]);

  useEffect(() => {
    if (!isBotThinking) return;
    const timeout = setTimeout(() => {
      const p = currentPlayer;
      let newState = { ...gameState };
      if (gameState.phase === GamePhase.PLAYER_TURN_START) {
        const action = decideBotAction(p, gameState.roundJoker, gameState.tossedThisTurn);
        if (action.type === 'SHOW') {
           const results = getRoundScores(gameState.players, gameState.currentPlayerIndex, gameState.roundJoker);
           const updatedPlayers = gameState.players.map(pl => {
             const roundRes = results.find(r => r.playerId === pl.id);
             return { 
                ...pl, score: roundRes?.roundScore || 0, 
                totalScore: (pl.totalScore || 0) + (roundRes?.roundScore || 0),
                wasCaller: pl.id === p.id 
             };
           });
           newState = { ...newState, players: updatedPlayers, phase: GamePhase.ROUND_END };
        } else if (action.type === 'TOSS' && action.cardIds) {
          const tossedCards = p.hand.filter(c => action.cardIds?.includes(c.id));
          const newHand = p.hand.filter(c => !action.cardIds?.includes(c.id));
          newState = { ...newState, players: newState.players.map(pl => pl.id === p.id ? { ...pl, hand: newHand } : pl), pendingToss: tossedCards, phase: GamePhase.PLAYER_TOSSING_DRAW, tossedThisTurn: true };
        } else if (action.type === 'DISCARD' && action.cardIds) {
          const cardToDiscard = p.hand.find(c => c.id === action.cardIds![0])!;
          const newHand = p.hand.filter(c => c.id !== cardToDiscard.id);
          newState = { ...newState, players: newState.players.map(pl => pl.id === p.id ? { ...pl, hand: newHand } : pl), pendingDiscard: cardToDiscard, lastDiscardedId: cardToDiscard.id, phase: GamePhase.PLAYER_DRAW };
        }
      } else if (gameState.phase === GamePhase.PLAYER_DRAW || gameState.phase === GamePhase.PLAYER_TOSSING_DRAW) {
        let deckToDrawFrom = newState.deck;
        let openDeckForRecycle = newState.openDeck;
        if (deckToDrawFrom.length === 0) {
           if (openDeckForRecycle.length > 1) {
              const topCard = openDeckForRecycle.pop()!;
              const recycled = shuffleDeck([...openDeckForRecycle]);
              deckToDrawFrom = recycled; openDeckForRecycle = [topCard];
              newState.deck = deckToDrawFrom; newState.openDeck = openDeckForRecycle;
           } else { return; }
        }
        const drawn = newState.deck.shift()!;
        newState.players = newState.players.map(pl => pl.id === p.id ? { ...pl, hand: [...pl.hand, drawn] } : pl);
        if (newState.pendingToss.length) newState.openDeck = [...newState.openDeck, ...newState.pendingToss];
        if (newState.pendingDiscard) newState.openDeck = [...newState.openDeck, newState.pendingDiscard];
        newState.pendingToss = []; newState.pendingDiscard = null;
        newState.currentPlayerIndex = (newState.currentPlayerIndex + 1) % newState.players.length;
        newState.phase = GamePhase.PLAYER_TURN_START; newState.tossedThisTurn = false; newState.lastDiscardedId = null;
      }
      setGameState(newState);
    }, 1500); 
    return () => clearTimeout(timeout);
  }, [gameState.phase, gameState.currentPlayerIndex, isBotThinking, gameState.players, gameState.deck, gameState.openDeck, gameState.roundJoker, gameState.tossedThisTurn, currentPlayer]);

  const handleCardClick = (card: CardData) => {
    if (!isPlayerTurn) return;
    if (gameState.phase === GamePhase.PLAYER_TURN_START) {
      setSelectedCardIds(prev => {
        if (prev.includes(card.id)) return prev.filter(id => id !== card.id);
        if (prev.length >= 2) return [prev[1], card.id]; 
        return [...prev, card.id];
      });
    }
  };

  const handleToss = () => {
    if (selectedCardIds.length !== 2) return;
    if (gameState.tossedThisTurn) return;
    const p = currentPlayer;
    const cards = p.hand.filter(c => selectedCardIds.includes(c.id));
    if (cards[0].rank !== cards[1].rank) { alert("Must toss pair of same rank!"); return; }
    const newHand = p.hand.filter(c => !selectedCardIds.includes(c.id));
    const newState = {
      ...gameState, players: gameState.players.map(pl => pl.id === p.id ? { ...pl, hand: newHand, lastAction: `Tossed ${cards[0].rank}s` } : pl),
      pendingToss: cards, phase: GamePhase.PLAYER_TOSSING_DRAW, tossedThisTurn: true,
      turnLog: [...gameState.turnLog, `${p.name} tossed a pair of ${cards[0].rank}s`]
    };
    setGameState(newState); syncOnlineState(newState); setSelectedCardIds([]);
  };

  const handleDiscard = () => {
    if (selectedCardIds.length !== 1) return;
    const p = currentPlayer;
    const cardToDiscard = p.hand.find(c => c.id === selectedCardIds[0]);
    if (!cardToDiscard) return;
    const newHand = p.hand.filter(c => c.id !== selectedCardIds[0]);
    const newState = {
      ...gameState, players: gameState.players.map(pl => pl.id === p.id ? { ...pl, hand: newHand, lastAction: `Discarded ${cardToDiscard.rank}${cardToDiscard.suit}` } : pl),
      pendingDiscard: cardToDiscard, lastDiscardedId: cardToDiscard.id, phase: GamePhase.PLAYER_DRAW,
      turnLog: [...gameState.turnLog, `${p.name} discarded ${cardToDiscard.rank}${cardToDiscard.suit}`]
    };
    setGameState(newState); syncOnlineState(newState); setSelectedCardIds([]);
  };

  const handleDraw = (source: 'DECK' | 'OPEN') => {
    const p = currentPlayer;
    let drawnCard: CardData;
    let newOpenDeck = [...gameState.openDeck];
    let newDeck = [...gameState.deck];
    if (source === 'OPEN') {
      const topCard = newOpenDeck[newOpenDeck.length - 1];
      if (gameState.phase === GamePhase.PLAYER_DRAW && topCard && topCard.id === gameState.lastDiscardedId) {
        if (!p.isBot) alert("Cannot pick up your own discard!"); return;
      }
      drawnCard = newOpenDeck.pop()!;
    } else {
      if (newDeck.length === 0) {
         if (newOpenDeck.length > 1) {
            const topCard = newOpenDeck.pop()!; 
            const cardsToRecycle = [...newOpenDeck]; 
            newDeck = shuffleDeck(cardsToRecycle); 
            newOpenDeck = [topCard]; 
         } else { alert("No cards left! Ending round."); handleShow(); return; }
      }
      drawnCard = newDeck.shift()!;
    }
    const newHand = [...p.hand, drawnCard];
    if (gameState.pendingToss.length > 0) newOpenDeck.push(...gameState.pendingToss);
    if (gameState.pendingDiscard) newOpenDeck.push(gameState.pendingDiscard);
    finishTurn(p.id, newHand, newOpenDeck, newDeck, source === 'OPEN' ? `Drew from Open Pile` : `Drew from Deck`);
  };

  const handleShow = () => {
    const results = getRoundScores(gameState.players, gameState.currentPlayerIndex, gameState.roundJoker);
    const updatedPlayers = gameState.players.map(p => {
      const roundRes = results.find(r => r.playerId === p.id);
      return {
        ...p, score: roundRes ? roundRes.roundScore : 0,
        totalScore: (p.totalScore || 0) + (roundRes ? roundRes.roundScore : 0),
        lastAction: p.id === currentPlayer.id ? 'CALLED SHOW!' : 'Revealed',
        wasCaller: p.id === currentPlayer.id 
      };
    });
    const newState = { ...gameState, players: updatedPlayers, phase: GamePhase.ROUND_END, turnLog: [...gameState.turnLog, `${currentPlayer.name} called SHOW!`] };
    setGameState(newState); syncOnlineState(newState); setIsTransitioning(false);
  };

  const finishTurn = (playerId: number, newHand: CardData[], openDeck: CardData[], deck: CardData[], actionLog: string) => {
    const nextPlayerIndex = (gameState.currentPlayerIndex + 1) % gameState.players.length;
    const needsTransition = gameState.gameMode === 'MULTIPLAYER';
    const newState = {
      ...gameState, players: gameState.players.map(pl => pl.id === playerId ? { ...pl, hand: newHand, lastAction: 'Turn Over' } : pl),
      openDeck, deck, currentPlayerIndex: nextPlayerIndex, phase: GamePhase.PLAYER_TURN_START,
      turnLog: [...gameState.turnLog, actionLog], lastDiscardedId: null, tossedThisTurn: false, pendingDiscard: null, pendingToss: []
    };
    setGameState(newState); syncOnlineState(newState); 
    if (needsTransition) setIsTransitioning(true);
  };

  const nextRound = () => {
    if (gameState.roundNumber >= gameState.totalRounds) return;
    startRound(gameState.roundNumber + 1, gameState.players, gameState.gameMode);
  };

  if (gameState.gameMode === 'TUTORIAL') return <TutorialEngine onExit={() => clearSession()} />;
  if (authLoading || isReconnecting) return <div className="h-[100dvh] bg-[#1a2e1a] flex flex-col items-center justify-center text-white gap-4"><RefreshCw className="animate-spin text-yellow-500" size={48} /><h2 className="font-serif text-2xl">{isReconnecting ? 'Reconnecting...' : 'Loading...'}</h2></div>;
  if (!session && !isGuest) return <Auth onGuestPlay={() => setIsGuest(true)} />;

  if (isOnlineLobby) {
     const canStart = onlineLobbyPlayers.length >= 2;
     return (
        <div className="h-[100dvh] bg-[#1a2e1a] flex flex-col items-center justify-center p-4">
           <div className="bg-slate-900/90 p-8 rounded-2xl border border-yellow-500/30 w-full max-w-md text-center">
              <h1 className="text-3xl font-serif font-bold text-yellow-500 mb-2">Lobby</h1>
              <div className="bg-black/40 p-4 rounded-xl mb-6 flex items-center justify-between border border-white/10">
                 <div className="text-left">
                    <p className="text-xs text-gray-400 uppercase">Room Code</p>
                    <p className="text-3xl font-mono font-bold text-white tracking-widest">{roomCode}</p>
                 </div>
                 <button onClick={() => navigator.clipboard.writeText(roomCode)} className="bg-slate-700 p-2 rounded hover:bg-slate-600"><Copy size={20} className="text-gray-300" /></button>
              </div>
              <div className="mb-8">
                 <h3 className="text-sm font-bold text-gray-400 mb-2 flex items-center justify-center gap-2"><Users size={16}/> Players ({onlineLobbyPlayers.length}/10)</h3>
                 <div className="flex flex-col gap-2 max-h-[150px] overflow-y-auto">
                    {onlineLobbyPlayers.map(p => (
                       <div key={p.id} className="bg-slate-800 p-3 rounded-lg flex items-center justify-between">
                          <span className="font-bold text-white">{p.name}</span>
                          {p.id === 0 && <span className="text-xs bg-yellow-500 text-black px-2 py-1 rounded font-bold">HOST</span>}
                       </div>
                    ))}
                 </div>
              </div>
              <div className="flex flex-col gap-3">
                 {myOnlineId === 0 ? (
                    <>
                    <div className="mb-6 p-4 bg-slate-800/50 rounded-2xl border border-white/5">
                       <RoundStepper value={selectedTotalRounds} onChange={setSelectedTotalRounds} label="Match Rounds" />
                    </div>
                    <button onClick={startOnlineGame} disabled={!canStart} className={`w-full font-bold py-4 rounded-xl flex items-center justify-center gap-2 transition-all ${canStart ? 'bg-green-600 hover:bg-green-500 text-white' : 'bg-slate-700 text-slate-500 cursor-not-allowed opacity-50'}`}>Start Game <Play size={20} /></button>
                    {!canStart && <div className="text-xs text-yellow-500 flex items-center justify-center gap-1 animate-pulse"><AlertCircle size={12} /> Need at least 1 opponent...</div>}
                    </>
                 ) : (
                    <div className="w-full bg-slate-700 text-gray-400 font-bold py-4 rounded-xl flex items-center justify-center gap-2 animate-pulse">Waiting for Host...</div>
                 )}
                 <button onClick={clearSession} className="text-red-400 text-sm hover:underline mt-2">Leave Room</button>
              </div>
           </div>
        </div>
     );
  }

  if (!gameState.gameMode && !isNameEntryStep && !showRoundSelectionSP && !showOnlineSelection) {
    return (
      <div className="h-[100dvh] bg-[#1a2e1a] flex flex-col items-center justify-center p-4">
        <h1 className="font-serif text-5xl md:text-7xl font-bold text-yellow-500 mb-8 drop-shadow-2xl">TRI-STACK</h1>
        <div className="absolute top-4 right-4 flex items-center gap-2 text-sm bg-black/30 p-2 rounded-lg backdrop-blur z-50">
          <User size={16} className="text-green-400" />
          {isEditingName ? (
            <div className="flex items-center gap-1">
               <input autoFocus className="bg-slate-800 text-white border border-slate-600 rounded px-1 py-0.5 text-xs w-24 outline-none focus:border-yellow-500" value={customDisplayName} placeholder="Name" onChange={(e) => setCustomDisplayName(e.target.value)} onKeyDown={(e) => { if (e.key === 'Enter') saveCustomName(); }} />
               <button onClick={saveCustomName} className="text-green-400 hover:text-green-300"><Check size={14} /></button>
            </div>
          ) : (
            <div className="flex items-center gap-2">
               <span className="text-gray-300 font-bold">{getDisplayName()}</span>
               <button onClick={() => { setCustomDisplayName(getDisplayName()); setIsEditingName(true); }} className="text-gray-500 hover:text-white"><Edit2 size={12} /></button>
            </div>
          )}
          {!isGuest && <button onClick={handleSignOut} className="ml-2 text-red-400 hover:text-red-300 border-l border-white/10 pl-2"><LogOut size={16} /></button>}
        </div>
        <div className="bg-slate-900/50 p-8 rounded-2xl backdrop-blur-sm border border-white/10 shadow-2xl flex flex-col gap-4 w-full max-w-md">
           {!showMultiplayerSelection ? (
             <>
                <button onClick={openSinglePlayerSetup} className="bg-blue-600 hover:bg-blue-500 text-white p-5 rounded-xl font-bold text-lg flex items-center gap-4 transition-all">
                  <div className="w-10 h-10 bg-blue-800 rounded-full flex items-center justify-center"><User size={20} /></div>
                  <div className="text-left"><div>Single Player</div><div className="text-xs text-blue-200 font-normal">Challenge Bots</div></div>
                </button>
                <button onClick={() => setShowMultiplayerSelection(true)} className="bg-green-600 hover:bg-green-500 text-white p-5 rounded-xl font-bold text-lg flex items-center gap-4 transition-all">
                  <div className="w-10 h-10 bg-green-800 rounded-full flex items-center justify-center"><Users size={20} /></div>
                  <div className="text-left"><div>Local Multiplayer</div><div className="text-xs text-green-200 font-normal">1 Device (Hotseat)</div></div>
                </button>
                <button onClick={() => setShowOnlineSelection(true)} className="bg-purple-600 hover:bg-purple-500 text-white p-5 rounded-xl font-bold text-lg flex items-center gap-4 transition-all">
                  <div className="w-10 h-10 bg-purple-800 rounded-full flex items-center justify-center"><Globe size={20} /></div>
                  <div className="text-left"><div>Online</div><div className="text-xs text-purple-200 font-normal">Remote Match</div></div>
                </button>
                <div className="h-px bg-white/10 my-1" />
                <button onClick={() => setGameState(prev => ({ ...prev, gameMode: 'TUTORIAL' }))} className="bg-slate-800 hover:bg-slate-700 text-yellow-500 p-4 rounded-xl font-bold text-sm flex items-center justify-center gap-3 transition-all border border-yellow-500/20"><GraduationCap size={20} /><span>Begin Academy</span></button>
             </>
           ) : (
             <>
               <button onClick={() => setShowMultiplayerSelection(false)} className="self-start text-gray-400 hover:text-white flex items-center gap-1 mb-2"><ChevronLeft size={20} /> Back</button>
               <h2 className="text-white text-xl text-center mb-4">How many players?</h2>
               <div className="grid grid-cols-2 gap-3 max-h-[40vh] overflow-y-auto">
                 {[2, 3, 4, 5, 6, 7, 8, 9, 10].map(count => (
                   <button key={count} onClick={() => initMultiplayerSetup(count)} className="bg-slate-700 hover:bg-green-600 text-white p-4 rounded-xl font-bold flex items-center justify-center transition-all group">
                     <span className="flex items-center gap-2"><Users size={16} className="text-gray-400 group-hover:text-white" />{count}</span>
                   </button>
                 ))}
               </div>
             </>
           )}
        </div>
      </div>
    );
  }

  if (showOnlineSelection) {
    return (
      <div className="h-[100dvh] bg-[#1a2e1a] flex flex-col items-center justify-center p-4">
        <h1 className="font-serif text-3xl md:text-5xl font-bold text-yellow-500 mb-8">Online Play</h1>
        <div className="bg-slate-900/80 p-8 rounded-2xl border border-white/10 w-full max-w-md">
           <button onClick={() => setShowOnlineSelection(false)} className="text-gray-400 hover:text-white flex items-center gap-1 mb-6"><ChevronLeft size={20} /> Back</button>
           <div className="flex flex-col gap-4">
              <button onClick={handleCreateOnlineGame} className="bg-yellow-500 hover:bg-yellow-400 text-black p-6 rounded-xl font-bold text-xl flex flex-col items-center justify-center gap-2 shadow-lg"><Wifi size={32} />Create New Room</button>
              <div className="flex items-center gap-4 text-gray-500 text-sm my-2"><div className="h-px bg-white/10 flex-1" /> OR <div className="h-px bg-white/10 flex-1" /></div>
              <div className="bg-black/30 p-4 rounded-xl border border-white/10">
                 <label className="text-xs text-gray-400 font-bold uppercase mb-2 block">Join Room</label>
                 <div className="flex gap-2">
                    <input type="text" maxLength={4} placeholder="CODE" value={joinCodeInput} onChange={(e) => setJoinCodeInput(e.target.value.toUpperCase())} className="bg-slate-800 text-white font-mono text-center text-xl p-3 rounded-lg w-full border border-slate-600 focus:border-yellow-500 outline-none uppercase tracking-widest" />
                    <button onClick={handleJoinOnlineGame} disabled={isJoining} className="bg-blue-600 hover:bg-blue-500 text-white px-6 rounded-lg font-bold disabled:opacity-50 flex items-center justify-center min-w-[80px]">{isJoining ? <Loader2 className="animate-spin" size={20} /> : 'JOIN'}</button>
                 </div>
              </div>
           </div>
        </div>
      </div>
    );
  }

  if (showRoundSelectionSP) {
    return (
      <div className="h-[100dvh] bg-[#1a2e1a] flex flex-col items-center justify-center p-4">
        <h1 className="font-serif text-3xl md:text-5xl font-bold text-yellow-500 mb-6 text-center">Protocol Config</h1>
        <div className="bg-slate-900/80 p-10 rounded-[3rem] backdrop-blur-sm border border-white/10 shadow-2xl w-full max-w-md text-center">
           <div className="mb-10">
             <RoundStepper value={selectedTotalRounds} onChange={setSelectedTotalRounds} label="Match Length" />
           </div>
           <div className="flex flex-col gap-3">
             <button onClick={startSinglePlayerMatch} className="w-full bg-blue-600 hover:bg-blue-500 text-white py-4 rounded-2xl font-black uppercase tracking-widest shadow-xl flex items-center justify-center gap-2">Initiate Match <Play size={18} fill="currentColor" /></button>
             <button onClick={() => setShowRoundSelectionSP(false)} className="text-gray-400 hover:text-white flex items-center gap-2 mx-auto mt-2"><ChevronLeft size={20} /> Back</button>
           </div>
        </div>
      </div>
    );
  }

  if (isNameEntryStep) {
    return (
      <div className="h-[100dvh] bg-[#1a2e1a] flex flex-col items-center justify-center p-4">
        <h1 className="font-serif text-3xl md:text-5xl font-bold text-yellow-500 mb-6">Setup Game</h1>
        <div className="bg-slate-900/80 p-6 md:p-8 rounded-2xl backdrop-blur-sm border border-white/10 shadow-2xl w-full max-w-md flex flex-col gap-6">
           <div className="max-h-[30vh] overflow-y-auto pr-2 space-y-3">
             {customPlayerNames.map((name, idx) => (
               <div key={idx} className="flex flex-col gap-1">
                 <label className="text-xs text-gray-400 font-bold uppercase tracking-wider">Player {idx + 1}</label>
                 <input type="text" value={name} onChange={(e) => { const newNames = [...customPlayerNames]; newNames[idx] = e.target.value; setCustomPlayerNames(newNames); }} maxLength={12} className="bg-slate-800 text-white border border-slate-600 rounded-lg p-3 focus:border-yellow-500 outline-none transition-colors" />
               </div>
             ))}
           </div>

           <div className="p-4 bg-slate-800/40 rounded-2xl border border-white/5">
             <RoundStepper value={selectedTotalRounds} onChange={setSelectedTotalRounds} label="Rounds to Victory" />
           </div>

           <div className="flex gap-3 mt-2">
             <button onClick={() => { setIsNameEntryStep(false); setShowMultiplayerSelection(true); }} className="flex-1 bg-slate-700 hover:bg-slate-600 text-white py-3 rounded-xl font-bold">Back</button>
             <button onClick={finalizeMultiplayerStart} className="flex-[2] bg-green-600 hover:bg-green-500 text-white py-3 rounded-xl font-bold flex items-center justify-center gap-2 shadow-lg">Start Match <Play size={20} className="fill-current" /></button>
           </div>
        </div>
      </div>
    );
  }

  if (gameState.phase === GamePhase.SETUP || !currentPlayer || gameState.players.length === 0) {
    return <div className="h-[100dvh] bg-[#1a2e1a] flex flex-col items-center justify-center text-white gap-4"><RefreshCw className="animate-spin text-yellow-500" size={48} /><h2 className="font-serif text-2xl">Deploying Table...</h2></div>;
  }

  if (isTransitioning) {
    return (
      <div className="h-[100dvh] bg-slate-900 flex flex-col items-center justify-center p-4 z-50">
        <div className="max-w-md w-full bg-slate-800 p-8 rounded-2xl shadow-2xl border border-yellow-500/30 text-center animate-in fade-in">
           <div className="w-20 h-20 bg-blue-600 rounded-full flex items-center justify-center mx-auto mb-6"><EyeOff size={40} className="text-white" /></div>
           <h2 className="text-2xl text-gray-400 font-serif mb-2">Turn Over</h2>
           <p className="text-gray-500 mb-8">Pass device to</p>
           <h1 className="text-4xl font-bold text-white mb-8 tracking-tight">{currentPlayer.name}</h1>
           <button onClick={() => setIsTransitioning(false)} className="w-full bg-green-600 hover:bg-green-500 text-white font-bold py-4 rounded-xl flex items-center justify-center gap-3"><Eye size={24} /> I am {currentPlayer.name}</button>
        </div>
      </div>
    );
  }

  const showOpponentCards = gameState.phase === GamePhase.ROUND_END;
  const isLastRound = gameState.roundNumber >= gameState.totalRounds;
  const lowestScore = Math.min(...gameState.players.map(p => p.totalScore || 0));

  return (
    <div className="h-[100dvh] flex flex-col overflow-hidden bg-[#1a2e1a]">
      <div className="h-16 bg-[#0f1f0f] flex items-center justify-between px-4 shadow-lg z-20 shrink-0">
        <div className="flex items-center gap-4">
          <button onClick={() => setShowExitConfirm(true)} className="text-red-400 hover:text-red-300 transition-colors bg-white/5 p-2 rounded-lg"><LogOut size={20} /></button>
          <div className="bg-slate-800 px-3 py-1 rounded-lg text-xs md:text-sm flex items-center gap-2">
             <span className="text-gray-400">Round</span>
             <span className="font-bold text-white">{gameState.roundNumber}/{gameState.totalRounds}</span>
          </div>
          {(gameState.gameMode === 'ONLINE_HOST' || gameState.gameMode === 'ONLINE_CLIENT') && (
             <div className="bg-blue-900/50 px-3 py-1 rounded-lg text-xs md:text-sm flex items-center gap-2 border border-blue-500/30">
               <Globe size={12} className="text-blue-400" />
               <span className="font-mono font-bold text-blue-200">{roomCode}</span>
             </div>
          )}
        </div>
        <div className="flex items-center gap-2">
           <span className="text-xs uppercase tracking-widest text-purple-400 font-bold hidden sm:inline">JOKER: {gameState.roundJoker?.rank}</span>
           {gameState.roundJoker && <div className="flex bg-white text-black px-2 py-1 rounded border-2 border-purple-500 items-center gap-1 font-bold">{gameState.roundJoker.rank}</div>}
        </div>
        <div className="flex items-center gap-4">
           <div className="flex items-center gap-2">
             <div className={`w-3 h-3 rounded-full ${isBotThinking ? 'bg-yellow-500' : 'bg-green-500'} animate-pulse`} />
             <span className="text-sm font-bold truncate max-w-[100px] text-white">{currentPlayer.name}</span>
           </div>
        </div>
      </div>

      <div className="flex-1 relative flex flex-col justify-between p-2 md:p-4 max-w-7xl mx-auto w-full overflow-hidden">
        <div className="flex justify-center flex-wrap gap-2 md:gap-8 mb-2 max-h-[30vh] overflow-y-auto">
           {opponentsToRender.map(opp => (
             <div key={opp.id} className={`flex flex-col items-center p-2 rounded-lg transition-all ${opp.id === gameState.currentPlayerIndex ? 'bg-yellow-500/10 scale-105 border border-yellow-500/30 shadow-2xl' : 'bg-black/20'}`}>
                <div className="relative">
                   <div className="w-10 h-10 bg-slate-700 rounded-full flex items-center justify-center border-2 border-slate-500">
                     {opp.isBot ? <Bot size={18} className="text-slate-300" /> : <Users size={18} className="text-slate-300" />}
                   </div>
                   <div className="absolute -bottom-1 -right-1 w-5 h-5 bg-blue-900 rounded-full flex items-center justify-center text-[10px] font-bold border border-white">{opp.hand?.length || 0}</div>
                </div>
                <span className="text-xs font-bold mt-1 max-w-[60px] truncate">{opp.name}</span>
                <span className="text-[10px] text-yellow-400 font-black">{opp.totalScore || 0} pts</span>
                {gameState.phase === GamePhase.ROUND_END && (
                  <div className="absolute top-10 z-30 flex gap-1 bg-black/90 p-1 rounded shadow-2xl animate-in zoom-in">
                     {(opp.hand || []).map((c, i) => (<Card key={c.id || i} card={c} small isJoker={gameState.roundJoker ? (c.rank === gameState.roundJoker.rank) : false} />))}
                  </div>
                )}
                {gameState.phase !== GamePhase.ROUND_END && (
                  <div className="flex -space-x-4 mt-2">{(opp.hand || []).map((c, i) => (<Card key={i} small className="scale-75" />))}</div>
                )}
             </div>
           ))}
        </div>

        <div className="flex-1 flex items-center justify-center gap-4 md:gap-16 my-2 relative">
            <div className="flex flex-col items-center gap-2">
               <Card disabled={!isPlayerTurn || (gameState.phase !== GamePhase.PLAYER_DRAW && gameState.phase !== GamePhase.PLAYER_TOSSING_DRAW)} onClick={() => handleDraw('DECK')} />
               <span className="text-xs uppercase tracking-widest font-black text-slate-400">Stockpile ({gameState.deck.length})</span>
            </div>
            <div className="flex gap-4 items-center">
              <div className="flex flex-col items-center gap-2 relative">
                 {gameState.openDeck.length > 0 ? (
                   <Card card={gameState.openDeck[gameState.openDeck.length - 1]} onClick={() => handleDraw('OPEN')} disabled={!isPlayerTurn || (gameState.phase !== GamePhase.PLAYER_DRAW && gameState.phase !== GamePhase.PLAYER_TOSSING_DRAW)} />
                 ) : (
                   <div className="w-20 h-28 md:w-24 md:h-36 border-2 border-dashed border-white/20 rounded-xl flex items-center justify-center bg-black/10"><span className="text-white/20 text-xs">Empty</span></div>
                 )}
                 <span className="text-xs uppercase tracking-widest font-black text-slate-400">Open Pile</span>
              </div>
            </div>
            {gameState.phase === GamePhase.ROUND_END && (
               <div className="absolute inset-0 z-50 flex items-center justify-center bg-black/80 backdrop-blur-sm animate-in fade-in">
                 <div className="bg-slate-900 p-6 rounded-[2.5rem] shadow-2xl border border-yellow-500/30 max-w-sm w-full text-center m-4">
                    <h2 className="text-2xl font-serif font-black text-white mb-1">{isLastRound ? "Mission Complete" : "Round Terminated"}</h2>
                    <p className="text-gray-500 mb-6 text-[10px] uppercase tracking-[0.3em]">Operational Standings</p>
                    <div className="space-y-2 mb-8 text-left max-h-[40vh] overflow-y-auto pr-1">
                       {gameState.players.sort((a, b) => isLastRound ? (a.totalScore - b.totalScore) : 0).map(p => {
                           const isWinner = isLastRound && (p.totalScore || 0) === lowestScore;
                           return (
                             <div key={p.id} className={`flex justify-between items-center p-3 rounded-2xl border ${isWinner ? 'bg-yellow-500/10 border-yellow-500/50' : 'bg-slate-800 border-white/5'}`}>
                                <span className={`flex items-center gap-2 text-sm font-bold ${isWinner ? 'text-yellow-400' : 'text-gray-300'}`}>
                                  {isWinner && <Trophy size={14} className="text-yellow-500" />} {p.name}
                                </span>
                                <div className="flex items-center gap-4">
                                   <div className="flex flex-col items-end">
                                      <span className="text-[8px] uppercase text-gray-500 font-black">Round</span>
                                      <span className={`text-xs font-black ${p.score === 0 ? 'text-green-400' : 'text-red-400'}`}>{p.score > 0 ? `+${p.score}` : p.score}</span>
                                   </div>
                                   <div className="flex flex-col items-end min-w-[30px]">
                                       <span className="text-[8px] uppercase text-gray-500 font-black">Total</span>
                                       <span className={`text-lg font-mono font-black ${isWinner ? 'text-yellow-400' : 'text-white'}`}>{p.totalScore || 0}</span>
                                   </div>
                                </div>
                             </div>
                           );
                       })}
                    </div>
                    {((gameState.gameMode !== 'ONLINE_CLIENT' && gameState.gameMode !== 'ONLINE_HOST') || (gameState.gameMode === 'ONLINE_HOST' && myOnlineId === 0)) && (
                       <button onClick={isLastRound ? (gameState.gameMode === 'ONLINE_HOST' ? handleReturnToLobby : clearSession) : nextRound} className={`w-full font-black py-4 rounded-2xl flex items-center justify-center gap-2 uppercase tracking-widest text-xs ${isLastRound ? 'bg-green-600 text-white' : 'bg-yellow-500 text-black'}`}>
                         {isLastRound ? 'Archive & Exit' : 'Next Round'} <ChevronRight size={18} />
                       </button>
                    )}
                 </div>
               </div>
            )}
        </div>

        <div className="flex flex-col items-center gap-4 pb-8 shrink-0">
           {isPlayerTurn && currentPlayer.id === bottomPlayer.id ? (
             <div className="flex items-center gap-2 bg-black/60 backdrop-blur-xl p-2 rounded-full border border-white/10 shadow-2xl transition-all scale-90 md:scale-100 z-10">
                {gameState.phase === GamePhase.PLAYER_TURN_START && (
                  <>
                    <button onClick={handleShow} className="bg-red-600 hover:bg-red-500 text-white px-5 py-2.5 rounded-full font-black flex items-center gap-2 text-[10px] md:text-xs shadow-lg shadow-red-900/40 tracking-widest"><AlertCircle size={14} /> SHOW</button>
                    <div className="w-px h-6 bg-white/10 mx-1" />
                    <button onClick={handleToss} disabled={selectedCardIds.length !== 2 || gameState.tossedThisTurn} className={`px-5 py-2.5 rounded-full font-black flex items-center gap-2 text-[10px] md:text-xs tracking-widest ${selectedCardIds.length === 2 && !gameState.tossedThisTurn ? 'bg-blue-600 text-white' : 'bg-slate-800 text-slate-500 cursor-not-allowed'}`}><RefreshCw size={14} /> TOSS</button>
                    <button onClick={handleDiscard} disabled={selectedCardIds.length !== 1} className={`px-5 py-2.5 rounded-full font-black flex items-center gap-2 text-[10px] md:text-xs tracking-widest ${selectedCardIds.length === 1 ? 'bg-green-600 text-white' : 'bg-slate-800 text-slate-500 cursor-not-allowed'}`}><Hand size={14} /> DISCARD</button>
                  </>
                )}
                {(gameState.phase === GamePhase.PLAYER_DRAW || gameState.phase === GamePhase.PLAYER_TOSSING_DRAW) && (
                   <div className="px-6 py-2.5 text-white font-black text-xs animate-pulse uppercase tracking-[0.2em]">{gameState.phase === GamePhase.PLAYER_TOSSING_DRAW ? 'Toss Confirmed • Draw One' : 'Action Required • Draw Card'}</div>
                )}
             </div>
           ) : (
             <div className="h-10 flex items-center justify-center text-gray-500 text-[10px] uppercase font-black tracking-widest animate-pulse">
                {currentPlayer.isBot ? 'Bot Intelligence Computing...' : `Waiting for ${currentPlayer.name}...`}
             </div>
           )}
           <div className="flex items-end justify-center -space-x-4 md:-space-x-8 h-[140px] md:h-[160px]">
              {(bottomPlayer.hand || []).map((card) => (
                <Card key={card.id} card={(!isPlayerTurn && gameState.gameMode === 'MULTIPLAYER') ? undefined : card} isJoker={gameState.roundJoker ? (card.rank === gameState.roundJoker.rank) : false} selected={selectedCardIds.includes(card.id)} onClick={() => handleCardClick(card)} className={`transition-all duration-300 ${isPlayerTurn && currentPlayer.id === bottomPlayer.id ? '' : 'opacity-40 grayscale'}`} />
              ))}
           </div>
           <div className="text-[10px] text-gray-500 font-black uppercase tracking-[0.2em] mt-2"><span className="text-green-400">{bottomPlayer.name}</span> • Energy: <span className="text-white text-base font-mono">{calculateHandValue(bottomPlayer.hand, gameState.roundJoker)}</span></div>
        </div>
      </div>

      {showExitConfirm && (
        <div className="fixed inset-0 z-[60] flex items-center justify-center bg-black/90 backdrop-blur-md p-4 animate-in fade-in">
          <div className="bg-slate-900 border border-red-500/20 p-8 rounded-[3rem] max-w-sm w-full text-center shadow-[0_0_100px_rgba(220,38,38,0.1)]">
             <div className="w-16 h-16 bg-red-950/40 rounded-3xl flex items-center justify-center mx-auto mb-6 border border-red-500/20"><LogOut size={28} className="text-red-500" /></div>
             <h2 className="text-2xl font-black text-white mb-2 uppercase tracking-tight">Abort Match?</h2>
             <p className="text-gray-500 text-[11px] mb-8 uppercase tracking-widest leading-relaxed">Tactical progress will be purged from the neural network.</p>
             <div className="flex flex-col gap-3">
                <button onClick={() => { clearSession(); setShowExitConfirm(false); }} className="w-full py-4 bg-red-600 hover:bg-red-500 text-white rounded-2xl font-black uppercase tracking-widest text-xs">Confirm Exit</button>
                <button onClick={() => setShowExitConfirm(false)} className="w-full py-4 bg-slate-800 text-gray-400 rounded-2xl font-black uppercase tracking-widest text-xs hover:text-white transition-colors">Resume Mission</button>
             </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default App;
